/// Per-address replication connection slot. Each replica address gets its
/// own independent mutex, so concurrent sends to different replicas never
/// contend on a single lock. At millions of ops/sec with RF=3, this
/// eliminates the serialization point that a single global pool creates.
///
/// R-D1/D-3: the slot also owns the master→replica **dense stream
/// cursor** (`next_sequence`). Sequence assignment, send, and ACK all
/// happen under this slot's mutex, so each replica address observes a
/// strictly ordered, densely numbered batch stream regardless of how
/// many dispatch threads fan out concurrently.
struct PerAddrSlot {
    connection: Option<TcpReplicaTransport>,
    /// Highest per-stream sequence this replica has ACKed (diagnostic).
    last_acked: u64,
    /// Next per-replica stream sequence to assign. `None` until the
    /// cursor has been synced to the replica's authoritative applied
    /// watermark via an empty-batch probe (process start / first
    /// contact). Positions consumed by failed sends are burned —
    /// never reused — so a position at or below the replica's
    /// watermark always refers to content the replica has applied.
    next_sequence: Option<u64>,
}

/// Per-address connection pool. The outer HashMap is locked briefly for
/// lookup/insert only. Each address has its own `Arc<Mutex<PerAddrSlot>>`,
/// so concurrent sends to different replicas proceed without contention.
static REPL_POOL: LazyLock<Mutex<HashMap<SocketAddr, std::sync::Arc<Mutex<PerAddrSlot>>>>> =
    LazyLock::new(|| Mutex::new(HashMap::new()));

fn le_u16_at(bytes: &[u8], offset: usize) -> Option<u16> {
    let b = bytes.get(offset..offset.checked_add(2)?)?;
    Some(u16::from_le_bytes([b[0], b[1]]))
}

fn le_u32_at(bytes: &[u8], offset: usize) -> Option<u32> {
    let b = bytes.get(offset..offset.checked_add(4)?)?;
    Some(u32::from_le_bytes([b[0], b[1], b[2], b[3]]))
}

fn le_u64_at(bytes: &[u8], offset: usize) -> Option<u64> {
    let b = bytes.get(offset..offset.checked_add(8)?)?;
    Some(u64::from_le_bytes([
        b[0], b[1], b[2], b[3], b[4], b[5], b[6], b[7],
    ]))
}

/// Decode the optional `OP_MIGRATION_COMPLETE` tombstone section (deletion-
/// tombstone Phase 8, design §7), beginning at byte `off` in `payload`.
///
/// Wire: `[version:1][count(M):4 LE][M × (txid:[u8;32] || generation:u32 LE)]`.
///
/// Returns `Some(entries)` only on a fully-valid section whose declared `M`
/// matches the available bytes. Any of: section absent (offset past end),
/// unrecognized `version`, truncated header, overflowing count, or a length
/// that does not match `M` → `None`. A `None` is SAFE: the §7 reconciliation
/// then treats every extra local key as never-received and TRANSFERS it
/// (no-loss), never a spurious drop. An empty-but-well-formed section (M == 0)
/// decodes to `Some(vec![])` — an authoritative "this source has no tombstones
/// for the shard," distinct from `None` (no section at all).
fn decode_tombstone_section(payload: &[u8], off: usize) -> Option<Vec<(TxKey, u32)>> {
    let version = *payload.get(off)?;
    if version != TOMBSTONE_SECTION_VERSION {
        return None;
    }
    let count = le_u32_at(payload, off.checked_add(1)?)? as usize;
    let entries_start = off.checked_add(5)?;
    let needed = 36usize
        .checked_mul(count)
        .and_then(|n| n.checked_add(entries_start))?;
    if payload.len() < needed {
        return None;
    }
    let mut out = Vec::with_capacity(count);
    let mut pos = entries_start;
    for _ in 0..count {
        let mut txid = [0u8; 32];
        txid.copy_from_slice(payload.get(pos..pos + 32)?);
        let generation = le_u32_at(payload, pos + 32)?;
        out.push((TxKey { txid }, generation));
        pos += 36;
    }
    Some(out)
}

/// Apply the tombstone-driven migration reconciliation at the commit gate
/// (deletion-tombstone Phase 8, design §7 + §9.1 #1 — the multi-source union).
///
/// Drains the per-shard reconcile accumulator (every pending current-epoch
/// source's `(live, tombstones)` manifest), forms the UNION, and for each LOCAL
/// key the rejoinee holds for `shard` decides via
/// [`crate::tombstone::classify_reconcile_union`]:
///
/// * **Drop** — no source has the key live AND some source tombstones it at a
///   generation at-or-ahead of the local copy. The rejoinee RECORDS the learned
///   tombstone (`apply_replicated_tombstone`, pre-arming its own future
///   self-purge per §6) THEN removes the record (`delete_for_purge`, which
///   writes NO second tombstone). Idempotent: re-running re-derives the same
///   state.
/// * **Transfer** — never-received (no source live, no source tombstone): the
///   record is LEFT in place for the existing transfer-up path (no-loss).
/// * **Keep** — live on some source, or a newer local re-creation than the
///   source's tombstone (§8.4): left untouched (existing exact-entry behavior).
///
/// No-loss invariant (Claim B): a key is dropped ONLY when a tombstone is in the
/// union; a key omitted by every source (no live, no tombstone) is NEVER
/// dropped — it is transferred. No-resurrection invariant (Claim A): a key
/// tombstoned by some source and not live anywhere is dropped, so it is never
/// pushed up to the master.
///
/// Always drains the accumulator (even when empty), so a no-op on the off-path.
///
/// # Errors
/// Returns the underlying [`crate::ops::error::SpendError`]'s display string if
/// recording the learned tombstone or removing a record fails — the caller must
/// then NOT commit the shard (the over-count is unreconciled).
fn apply_tombstone_reconciliation(
    engine: &Engine,
    cluster: &RunningCluster,
    shard: u16,
) -> std::result::Result<(), String> {
    use crate::tombstone::{ReconcileAction, classify_reconcile_union};

    let manifests = cluster.take_reconcile_accumulator(shard);
    if manifests.is_empty() {
        // Nothing accumulated (off-path, or no current-epoch source presented a
        // tombstone section) → nothing to reconcile.
        return Ok(());
    }

    // The committed/migration epoch this commit is happening at. Accumulated
    // entries are stamped with the `migration_epoch` of the completion that
    // produced them (BUG4 fix (a)); only entries stamped with THIS epoch may
    // drive DROPS via their tombstones.
    let current_epoch = cluster.shard_table().read().version;

    // Build the UNION across all pending sources (§9.1 #1):
    //   * union_live: a key live on ANY accumulated source. Contributed
    //     UNCONDITIONALLY by every accumulated entry, regardless of its stamped
    //     epoch — the no-loss invariant (Claim B) requires the union to see
    //     EVERY pending source's live set so a key live anywhere is Kept
    //     (BUG2). A within-slack (epoch == current-1) source's live keys must
    //     never be Dropped just because that source is not epoch-current.
    //   * union_tomb: per key, the MAX (newest) tombstone generation across
    //     sources that tombstone it (the most permissive for a drop — if even
    //     the newest is older than local, none authorize the drop). A
    //     tombstone is admitted into the union ONLY from an entry whose stamped
    //     epoch equals `current_epoch` (BUG4 fix (a)): a STALE entry — one that
    //     was epoch-current when accumulated but whose epoch the cluster has
    //     since advanced past (a leaked entry, the case BUG4 (b) also guards) —
    //     must NOT drive a Drop of a now-live key in this later epoch. Its live
    //     set is still counted above (no-loss), only its drop-driving power is
    //     dropped.
    let mut union_live: std::collections::HashSet<TxKey> = std::collections::HashSet::new();
    let mut union_tomb: std::collections::HashMap<TxKey, u32> = std::collections::HashMap::new();
    for m in &manifests {
        for k in &m.live {
            union_live.insert(*k);
        }
        if m.epoch != current_epoch {
            // Stale (or within-slack) entry: its tombstones are untrusted for
            // driving a drop at this epoch. Live set already folded in above.
            continue;
        }
        for (k, tgen) in &m.tombstones {
            union_tomb
                .entry(*k)
                .and_modify(|g| {
                    // Keep the newer (wrapping-aware) tombstone generation.
                    if crate::record::generation_target_ahead(*g, *tgen) {
                        *g = *tgen;
                    }
                })
                .or_insert(*tgen);
        }
    }

    // Classify every LOCAL key the rejoinee holds for this shard against the
    // union. Only keys the source UNION does NOT hold live are drop/transfer
    // candidates; a live key is Keep (and reconciled by the exact-entry path).
    for key in engine.keys_for_shard(shard) {
        let local_gen = match engine.read_metadata(&key) {
            Ok(meta) => meta.generation,
            // The key vanished between the scan and the read (a concurrent
            // delete). Nothing to reconcile for it.
            Err(_) => continue,
        };
        let live = union_live.contains(&key);
        let tomb_gen = union_tomb.get(&key).copied();
        match classify_reconcile_union(local_gen, live, tomb_gen) {
            ReconcileAction::Keep | ReconcileAction::Transfer => {
                // Keep: live on some source / newer local re-creation — leave it.
                // Transfer: never-received — leave it for the transfer-up path
                // (no-loss). Neither mutates local state here.
            }
            ReconcileAction::Drop => {
                // Authoritative deletion. RECORD the learned tombstone first
                // (pre-arm self-purge, §6), then remove the record WITHOUT
                // writing a second tombstone (`delete_for_purge`). Use the
                // union's tombstone generation (the gen that authorized the
                // drop) and SpentDah cause (the dominant deletion path; the
                // exact cause is not load-bearing for reconciliation).
                let drop_gen = tomb_gen.unwrap_or(local_gen);
                if let Err(e) = engine.apply_replicated_tombstone(
                    &key,
                    0, // deletion_height unknown at the rejoinee; 0 keeps the
                    // tombstone for the full GC horizon (conservative-safe).
                    drop_gen,
                    crate::tombstone::TombstoneCause::SpentDah.as_u8(),
                ) {
                    return Err(format!("record learned tombstone for {key:?}: {e:?}"));
                }
                match engine.delete_for_purge(&crate::ops::remaining::DeleteRequest {
                    tx_key: key,
                    due_guard: None,
                }) {
                    Ok(()) | Err(crate::ops::error::SpendError::TxNotFound) => {}
                    Err(e) => {
                        return Err(format!("drop tombstoned key {key:?}: {e:?}"));
                    }
                }
            }
        }
    }
    Ok(())
}

/// Configurable worker thread count for the replication runtime.
/// Set via [`init_repl_worker_threads`] before the runtime is first used.
/// Defaults to 2 if not explicitly configured.
static REPL_WORKER_THREADS: std::sync::OnceLock<usize> = std::sync::OnceLock::new();

/// Configure the number of replication I/O worker threads.
///
/// Must be called during server startup before any replication occurs.
/// If not called, defaults to 2 threads. At high throughput (10M+ ops/sec),
/// consider setting this to `num_cpus / 4` or the replication factor,
/// whichever is larger.
pub fn init_repl_worker_threads(count: usize) {
    let _ = REPL_WORKER_THREADS.set(count.max(1));
}

/// Shared tokio runtime for async replication I/O. Uses a configurable thread
/// pool dedicated to replication, keeping blocking I/O off the main server
/// threads while reusing threads across replication calls instead of spawning
/// new OS threads per `replicate_all_ops` invocation.
static REPL_RUNTIME: LazyLock<tokio::runtime::Runtime> = LazyLock::new(|| {
    let workers = REPL_WORKER_THREADS.get().copied().unwrap_or(2);
    tokio::runtime::Builder::new_multi_thread()
        .worker_threads(workers)
        .thread_name("repl-io")
        .enable_all()
        .build()
        .expect("failed to create replication tokio runtime")
});

/// Global sum bound on concurrent `replicate_all_ops` fan-outs. Each
/// in-flight fan-out clones per-address op buffers and parks one caller
/// thread (plus `spawn_blocking` tasks on [`REPL_RUNTIME`]) for up to the
/// ack timeout, so the cap bounds memory and thread pressure. P7/R5: this
/// is deliberately a SUM bound over the per-address slots below — it is no
/// longer the only admission gate, so one wedged replica cannot exhaust it
/// for healthy ones.
const MAX_REPLICATION_FANOUTS_IN_FLIGHT: usize = 128;

/// Minimum per-address fan-out budget regardless of cluster size, so a
/// replica in a large cluster still gets useful pipelining depth.
const MIN_PER_ADDR_FANOUTS_IN_FLIGHT: usize = 8;

/// Extra slack added on top of the fan-out ack timeout to form the permit
/// admission deadline. A permit holder blocks for at most its own ack
/// timeout per send attempt, so `ack_timeout + margin` covers the worst
/// case of waiting behind a holder that just started, plus scheduling
/// jitter — after that, waiting longer cannot succeed against a wedged
/// replica and the client should fast-fail instead.
const FANOUT_ADMISSION_MARGIN: Duration = Duration::from_millis(250);

/// Per-address fan-out cap: divide the global pool across the known
/// replica addresses (floored at [`MIN_PER_ADDR_FANOUTS_IN_FLIGHT`]).
/// With 0–1 known replicas this equals the full global pool, so small
/// clusters keep the exact pre-partition throughput.
fn per_addr_fanout_cap(known_replica_addrs: usize) -> usize {
    MIN_PER_ADDR_FANOUTS_IN_FLIGHT
        .max(MAX_REPLICATION_FANOUTS_IN_FLIGHT / known_replica_addrs.max(1))
}

/// Two-level fan-out admission state: total in-flight fan-outs (global
/// sum bound) and in-flight fan-outs per target replica address.
struct FanoutPermitState {
    total: usize,
    per_addr: HashMap<SocketAddr, usize>,
}

static REPLICATION_FANOUT_PERMITS: LazyLock<(
    std::sync::Mutex<FanoutPermitState>,
    std::sync::Condvar,
)> = LazyLock::new(|| {
    (
        std::sync::Mutex::new(FanoutPermitState {
            total: 0,
            per_addr: HashMap::new(),
        }),
        std::sync::Condvar::new(),
    )
});

/// Error from replication fan-out admission control (P7/R5).
///
/// Surfaced to clients through the existing `ERR_REPLICATION_FAILED` path:
/// `replicate_all_ops` returns `Err(String)` and every mutation handler
/// maps that to `ERR_REPLICATION_FAILED`. A dedicated wire error code
/// would require extending the protocol surface and every client decoder
/// for a condition clients handle exactly like any other replication
/// failure (fail the write, retry with backoff), so the distinguishable
/// `Display` message is the contract instead of a new code.
#[derive(Debug, thiserror::Error, PartialEq, Eq)]
enum FanoutAdmissionError {
    /// No permit became available before the deadline. `saturated` names
    /// the first target address whose per-address slots were exhausted,
    /// or `None` when the global sum bound was what blocked admission.
    #[error(
        "replication fan-out admission timed out after {waited_ms} ms: \
         {in_flight}/{global_cap} fan-outs in flight, saturated address: \
         {saturated:?} (a replica is likely wedged in ack timeouts)"
    )]
    Timeout {
        waited_ms: u64,
        in_flight: usize,
        global_cap: usize,
        saturated: Option<SocketAddr>,
    },
}

/// RAII permit for one in-flight fan-out covering `addrs`.
#[derive(Debug)]
struct ReplicationFanoutPermit {
    addrs: Vec<SocketAddr>,
}

/// Acquire admission for one fan-out targeting `addrs`, waiting at most
/// `max_wait`.
///
/// Admission requires, atomically under one lock (all-or-nothing, so
/// partial holds can never deadlock): the global total below
/// [`MAX_REPLICATION_FANOUTS_IN_FLIGHT`] AND every target address below
/// `per_addr_cap`. On deadline expiry returns
/// [`FanoutAdmissionError::Timeout`] so the caller fails fast instead of
/// blocking unboundedly behind a wedged replica (P7/R5).
fn acquire_replication_fanout_permits(
    addrs: &[SocketAddr],
    per_addr_cap: usize,
    max_wait: Duration,
) -> std::result::Result<ReplicationFanoutPermit, FanoutAdmissionError> {
    let (lock, cvar) = &*REPLICATION_FANOUT_PERMITS;
    let start = std::time::Instant::now();
    let mut state = lock.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
    loop {
        let global_ok = state.total < MAX_REPLICATION_FANOUTS_IN_FLIGHT;
        let blocked_addr = addrs
            .iter()
            .find(|a| state.per_addr.get(a).copied().unwrap_or(0) >= per_addr_cap);
        if global_ok && blocked_addr.is_none() {
            state.total += 1;
            for a in addrs {
                *state.per_addr.entry(*a).or_insert(0) += 1;
            }
            return Ok(ReplicationFanoutPermit {
                addrs: addrs.to_vec(),
            });
        }
        let elapsed = start.elapsed();
        if elapsed >= max_wait {
            return Err(FanoutAdmissionError::Timeout {
                waited_ms: elapsed.as_millis() as u64,
                in_flight: state.total,
                global_cap: MAX_REPLICATION_FANOUTS_IN_FLIGHT,
                saturated: if global_ok {
                    blocked_addr.copied()
                } else {
                    None
                },
            });
        }
        let (next, _timed_out) = cvar
            .wait_timeout(state, max_wait - elapsed)
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        state = next;
    }
}

impl Drop for ReplicationFanoutPermit {
    fn drop(&mut self) {
        let (lock, cvar) = &*REPLICATION_FANOUT_PERMITS;
        let mut state = lock.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
        state.total = state.total.saturating_sub(1);
        for a in &self.addrs {
            if let Some(count) = state.per_addr.get_mut(a) {
                *count = count.saturating_sub(1);
                if *count == 0 {
                    state.per_addr.remove(a);
                }
            }
        }
        drop(state);
        // Waiters have heterogeneous predicates (different address sets),
        // so notify_one could wake a waiter this release does not unblock
        // while the one it does unblock keeps sleeping. notify_all is
        // required for correctness; the pool is small (≤128 holders) so
        // the thundering herd is bounded.
        cvar.notify_all();
    }
}

/// Persistent replication ACK tracker. Initialized during server startup
/// via `init_ack_tracker()`. Records per-replica durable ACK sequences
/// to disk so that after a master restart, catch-up streaming can resume
/// from the correct position.
static ACK_TRACKER: std::sync::OnceLock<crate::replication::durable::AckTracker> =
    std::sync::OnceLock::new();

/// Persistent receiver-side applied tracker for production `OP_REPLICA_BATCH`
/// dispatch through the main server port. Initialized at startup beside the
/// cluster state file. This closes the gap where production dispatch used a
/// thread-local in-memory high-water mark and lost dedup state on restart.
static REPLICA_APPLIED_TRACKER: std::sync::OnceLock<
    crate::replication::durable::ReplicaAppliedTracker,
> = std::sync::OnceLock::new();

/// Persistent master-side pending replication intent tracker.
static REPLICATION_INTENT_TRACKER: std::sync::OnceLock<
    crate::replication::durable::ReplicationIntentTracker,
> = std::sync::OnceLock::new();

/// Monotonic diagnostic high-water mark across all source streams.
static DISPATCH_REPLICA_LAST_APPLIED: AtomicU64 = AtomicU64::new(0);

/// Gap #5 — secondary-index readiness status.
///
/// Tracks whether each secondary index (DAH and unmined) was successfully
/// (re)built at startup. When a secondary rebuild fails, the binary still
/// starts (the primary index is intact and the node can serve regular
/// spend/get/create traffic) but endpoints that depend on the missing
/// secondary reject requests with [`crate::protocol::opcodes::ERR_INDEX_DEGRADED`]
/// until the operator investigates and restarts. We deliberately do NOT
/// silently start with an empty secondary index because that would silently
/// break the pruner, unmined iterator, DAH-driven deletion, conflict, and
/// mining workflows.
///
/// Both flags default to `true` (healthy) at process start so that test
/// harnesses and code paths that never call [`set_secondary_status`] keep
/// the historical "everything is ready" behavior.
static SECONDARY_DAH_OK: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(true);
static SECONDARY_UNMINED_OK: std::sync::atomic::AtomicBool =
    std::sync::atomic::AtomicBool::new(true);

/// Snapshot of secondary-index readiness flags at startup.
///
/// Returned by [`secondary_status`]. Both flags default to `true` (healthy);
/// the server binary calls [`set_secondary_status`] after rebuild attempts
/// to flip them to `false` if the corresponding rebuild failed.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct SecondaryStatus {
    /// Whether the DAH index was successfully (re)built at startup.
    pub dah_ok: bool,
    /// Whether the unmined index was successfully (re)built at startup.
    pub unmined_ok: bool,
}

impl SecondaryStatus {
    /// True when both secondary indexes are healthy.
    pub fn fully_ok(&self) -> bool {
        self.dah_ok && self.unmined_ok
    }
}

/// Set the global secondary-index readiness flags.
///
/// Called once during server startup after the index/secondary rebuild
/// attempts complete. Subsequent reads via [`secondary_status`] observe the
/// stored values with `Ordering::Relaxed` semantics — fine for a flag that
/// is set once before the server begins accepting client requests.
pub fn set_secondary_status(status: SecondaryStatus) {
    SECONDARY_DAH_OK.store(status.dah_ok, std::sync::atomic::Ordering::Relaxed);
    SECONDARY_UNMINED_OK.store(status.unmined_ok, std::sync::atomic::Ordering::Relaxed);
}

/// Read the current secondary-index readiness flags.
pub fn secondary_status() -> SecondaryStatus {
    SecondaryStatus {
        dah_ok: SECONDARY_DAH_OK.load(std::sync::atomic::Ordering::Relaxed),
        unmined_ok: SECONDARY_UNMINED_OK.load(std::sync::atomic::Ordering::Relaxed),
    }
}

/// Global metrics reference. Initialized during server startup via
/// `init_dispatch_metrics()`. Used to increment operation counters
/// without threading metrics through every handler function.
static DISPATCH_METRICS: std::sync::OnceLock<&'static crate::metrics::ThreadMetrics> =
    std::sync::OnceLock::new();

/// Global histograms reference. Initialized during server startup via
/// `init_dispatch_histograms()`. Records per-handler end-to-end latency
/// for Prometheus histogram export. Like `DISPATCH_METRICS`, all call
/// sites are guarded with `if let Some(h) = DISPATCH_HISTOGRAMS.get()`
/// so tests that skip init still work.
static DISPATCH_HISTOGRAMS: std::sync::OnceLock<&'static crate::metrics::ThreadHistograms> =
    std::sync::OnceLock::new();

/// Initialize the persistent ACK tracker.
///
/// Must be called once during server startup before any replication occurs.
/// The `path` should be alongside the cluster state file (e.g., `<device>.repl-ack`).
pub fn init_ack_tracker(path: std::path::PathBuf) {
    let tracker = crate::replication::durable::AckTracker::new(path);
    let _ = ACK_TRACKER.set(tracker);
}

/// R-038 (D-01): borrow the static [`crate::replication::durable::AckTracker`] for background subsystems
/// (e.g. the replica-lag monitor) that need a `&'static AckTracker` handle.
///
/// Returns `None` until [`init_ack_tracker`] has been called. Single-node
/// servers never call it, so single-node callers naturally see `None` and
/// skip lag monitoring.
pub fn ack_tracker_handle() -> Option<&'static crate::replication::durable::AckTracker> {
    ACK_TRACKER.get()
}

/// Initialize the persistent receiver-side applied tracker.
///
/// Must be called once during clustered server startup before accepting
/// replication frames. A corrupt tracker is returned as an error so startup
/// can fail closed instead of serving with unknown receiver durability state.
pub fn init_replica_applied_tracker(path: std::path::PathBuf) -> std::result::Result<(), String> {
    let tracker = crate::replication::durable::ReplicaAppliedTracker::load(path)
        .map_err(|e| format!("load replica applied tracker: {e}"))?;
    let initial = tracker.snapshot().values().copied().max().unwrap_or(0);
    DISPATCH_REPLICA_LAST_APPLIED.store(initial, std::sync::atomic::Ordering::Relaxed);
    REPLICA_APPLIED_TRACKER
        .set(tracker)
        .map_err(|_| "replica applied tracker already initialized".to_string())
}

/// Initialize the persistent master-side replication intent tracker.
pub fn init_replication_intent_tracker(
    path: std::path::PathBuf,
) -> std::result::Result<(), String> {
    let tracker = crate::replication::durable::ReplicationIntentTracker::load(path)
        .map_err(|e| format!("load replication intent tracker: {e}"))?;
    REPLICATION_INTENT_TRACKER
        .set(tracker)
        .map_err(|_| "replication intent tracker already initialized".to_string())
}

/// Flush any coalesced replication-intent commits before a clean shutdown.
pub fn flush_replication_intent_tracker() -> std::result::Result<(), String> {
    if let Some(tracker) = REPLICATION_INTENT_TRACKER.get() {
        tracker
            .flush()
            .map_err(|e| format!("replication intent flush: {e}"))?;
    }
    Ok(())
}

/// Initialize the dispatch metrics reference.
///
/// Must be called once during server startup before any requests are processed.
pub fn init_dispatch_metrics(metrics: &'static crate::metrics::ThreadMetrics) {
    let _ = DISPATCH_METRICS.set(metrics);
}

/// P2.2: crate-internal accessor for the same `ThreadMetrics` handle that
/// in-dispatch code reaches via `DISPATCH_METRICS.get()`. Surfaced so
/// non-dispatch hot paths (e.g. `InflightBytesLimiter::try_acquire` in
/// `server::mod`) can bump per-thread counters without duplicating the
/// `OnceLock`. Returns `None` before `init_dispatch_metrics` has been
/// called, matching every other call site's tolerance for unset state.
pub(crate) fn dispatch_metrics_handle() -> Option<&'static crate::metrics::ThreadMetrics> {
    DISPATCH_METRICS.get().copied()
}

/// Initialize the dispatch histograms reference.
///
/// Must be called once during server startup before any requests are
/// processed. Tests that don't install a histogram reference still work —
/// handlers skip the `record_since` call in that case.
pub fn init_dispatch_histograms(histograms: &'static crate::metrics::ThreadHistograms) {
    let _ = DISPATCH_HISTOGRAMS.set(histograms);
}

/// Dispatch a request frame to the appropriate Engine method.
///
/// If `cluster` is Some, shard ownership is checked for key-based operations.
/// Requests for keys not owned by this node get a Redirect response.
///
/// # Mutation path (durability contract — WAL-first)
///
/// Gap #2 (TERANODE_PRODUCTION_READINESS_GAPS.md) corrected the
/// previously stated "engine-first" ordering — the actual implemented
/// order is:
///
/// 1. **Validate under lock** — parse, check shard ownership, acquire
///    the per-record lock. For multi-spend, snapshot the metadata.
/// 2. **Append + fsync redo entry** — every authoritative WAL-first
///    payload (full record bytes for `Create`, real `new_spent_count`
///    for spend/unspend) is captured BEFORE any device write so
///    recovery can reconstruct the post-mutation state byte-for-byte.
///    Redo open/create failure is fatal at startup; redo flush failure
///    fails the client request.
/// 3. **Apply to engine** — write UTXO slots / metadata to the block
///    device via `pwrite_all_at` (durable on return for `DirectDevice`
///    via `O_DIRECT`).
/// 4. **Replicate** — fan out to replicas with the durable sequence
///    numbers assigned in step 2. Best-effort under the current ack
///    policy; degraded RF>1 modes are validated at config load time.
/// 5. **Respond** — send the success/error response to the client.
///
/// Crash recovery walks the redo log after the last checkpoint and
/// idempotently re-applies entries; Create fully reconstructs
/// records, spend / unspend overwrite `meta.spent_utxos` with the
/// correct value the dispatch path computed before the WAL flush.
#[tracing::instrument(
    skip_all,
    level = "debug",
    fields(op = %request.op_code, request_id = request.request_id),
)]
pub(crate) fn handle_request(
    request: &RequestFrame,
    engine: &Engine,
    max_batch_size: u32,
    cluster: Option<&RunningCluster>,
    redo_log: Option<&Mutex<RedoLog>>,
    conn_state: &mut super::ConnectionState,
    blob_store: Option<&dyn BlobStore>,
) -> ResponseFrame {
    // Phase I — readiness gate (runs BEFORE the quorum check). A
    // multi-node node that has joined SWIM membership but has not yet
    // observed its first quorum-committed topology must reject
    // client-facing reads/writes with `ERR_CLUSTER_NOT_READY` (retryable
    // by the client) so a seeding client cannot drive data into a
    // half-formed cluster. This is more diagnostic than the broader
    // `ERR_NO_QUORUM` and lets clients discriminate "still booting"
    // from "lost quorum after formation".
    //
    // The gate is intentionally narrow: cluster-bootstrap traffic
    // (topology proposals/votes/commits, replica batches, admin
    // health/diagnostics, ping) bypasses the check so a node can
    // become Alive in the first place.
    if needs_cluster_readiness(request.op_code)
        && let Some(c) = cluster
        && c.shard_table().read().replication_factor() > 1
        && !c.cluster_health().is_ready()
    {
        return error_response(
            request.request_id,
            ERR_CLUSTER_NOT_READY,
            "node has not yet observed first committed topology",
        );
    }

    // Gap #5 — secondary-index readiness gate. When a secondary index
    // (DAH or unmined) failed to rebuild at startup, the binary is still
    // running so the primary index continues to serve regular spend/get/
    // create traffic, but endpoints that depend on the missing secondary
    // must reject requests with `ERR_INDEX_DEGRADED` instead of silently
    // returning empty results (which would break pruner / unmined iterator /
    // DAH-driven deletion / conflict / mining workflows). Recovery requires
    // the operator to investigate the underlying I/O / device error and
    // restart the node so the secondary rebuild can be re-attempted.
    if let Some(err_resp) = check_secondary_readiness(request.op_code, request.request_id) {
        return err_resp;
    }

    // Reject mutations when the cluster lacks quorum to prevent split-brain.
    if is_mutation_opcode(request.op_code)
        && let Some(err_resp) = check_quorum(cluster, request.request_id)
    {
        return err_resp;
    }

    let mut _visibility_guard =
        acquire_dispatch_visibility_guard(engine, request.op_code, request.flags);
    // C-1: for mutation ops, borrow the exclusive barrier out as a
    // releasable handle so the handler can drop it after local apply +
    // redo durability, before the replication network round-trip. Read
    // and barrier-less ops get `None` and keep the guard for their full
    // scope. The handle borrows the same `Option` `_visibility_guard`
    // owns; it is moved by value into the handler and dropped (or
    // released) there, before `_visibility_guard` itself goes out of
    // scope at the end of this function.
    let mutation_barrier = mutation_barrier_from(&mut _visibility_guard);

    // Refresh the cached wall-clock time once per request so that all
    // individual operations within the batch share the same timestamp.
    engine.refresh_clock();

    // Batch-level entry counters (one per request frame). Item-level
    // `_items_attempted` counters are incremented inside each handler once
    // the payload is decoded — they can't be incremented here because the
    // item count is payload-dependent.
    if let Some(m) = DISPATCH_METRICS.get() {
        match request.op_code {
            OP_SET_MINED_BATCH => m.set_mined_attempted.inc(),
            OP_GET_BATCH | OP_GET_SPEND_BATCH => m.gets_attempted.inc(),
            OP_FREEZE_BATCH => m.freezes_attempted.inc(),
            OP_UNFREEZE_BATCH => m.unfreezes_attempted.inc(),
            OP_DELETE_BATCH => m.deletes_attempted.inc(),
            OP_REASSIGN_BATCH => m.reassign_attempted.inc(),
            OP_SET_CONFLICTING_BATCH => m.set_conflicting_attempted.inc(),
            OP_REMOVE_CONFLICTING_CHILD_BATCH => m.remove_conflicting_child_attempted.inc(),
            OP_QUERY_CONFLICTING => m.query_conflicting_attempted.inc(),
            OP_SET_LOCKED_BATCH => m.set_locked_attempted.inc(),
            OP_PRESERVE_UNTIL_BATCH => m.preserve_until_attempted.inc(),
            OP_MARK_LONGEST_CHAIN_BATCH => m.mark_longest_chain_attempted.inc(),
            _ => {}
        }
    }

    // Wrap each handler with latency timing. The timer closure fetches the
    // global histograms ref once per request (a `Relaxed` atomic load) and
    // does nothing if the handler didn't opt into timing or if histograms
    // weren't initialized.
    let start = std::time::Instant::now();

    let response = match request.op_code {
        OP_SPEND_BATCH => handle_spend_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_UNSPEND_BATCH => handle_unspend_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_SET_MINED_BATCH => handle_set_mined_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_CREATE_BATCH => handle_create_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            blob_store,
            mutation_barrier,
        ),
        OP_FREEZE_BATCH => handle_freeze_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_UNFREEZE_BATCH => handle_unfreeze_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_REASSIGN_BATCH => handle_reassign_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_SET_CONFLICTING_BATCH => handle_set_conflicting_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_REMOVE_CONFLICTING_CHILD_BATCH => handle_remove_conflicting_child_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_SET_LOCKED_BATCH => handle_set_locked_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_PRESERVE_UNTIL_BATCH => handle_preserve_until_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_DELETE_BATCH => handle_delete_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
            // Direct client delete: unconditional (spec §3.18). No sweep guard.
            None,
        ),
        OP_MARK_LONGEST_CHAIN_BATCH => handle_mark_longest_chain_batch(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_GET_BATCH => handle_get_batch(request, engine, max_batch_size, cluster),
        OP_GET_SPEND_BATCH => handle_get_spend_batch(request, engine, max_batch_size, cluster),
        OP_QUERY_OLD_UNMINED => handle_query_old_unmined(request, engine, cluster),
        OP_QUERY_CONFLICTING => handle_query_conflicting(request, engine, cluster),
        OP_PRESERVE_TRANSACTIONS => handle_preserve_transactions(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_PROCESS_EXPIRED_PRESERVATIONS => handle_process_expired(
            request,
            engine,
            max_batch_size,
            cluster,
            redo_log,
            mutation_barrier,
        ),
        OP_GET_PARTITION_MAP => handle_get_partition_map(request, cluster),
        OP_GET_COMMITTED_TOPOLOGY => handle_get_committed_topology(request, cluster),
        // Height subsystem (deletion-tombstone design §4): return this node's
        // last-durable height as a 4-byte LE payload. Always-on and additive:
        // it reads a number and never mutates state, so it is safe regardless
        // of the tombstone / GC flags.
        OP_GET_NODE_HEIGHT => ResponseFrame {
            request_id: request.request_id,
            status: STATUS_OK,
            payload: engine.last_durable_height().to_le_bytes().to_vec(),
        },
        OP_ADMIN_DIAGNOSE_KEY => handle_admin_diagnose_key(request, engine, cluster),
        OP_PARTITION_VERSION_REPORT => handle_partition_version_report(request, engine, cluster),
        OP_ADMIN_CLUSTER_HEALTH => handle_admin_cluster_health(request, cluster),
        OP_PING => ResponseFrame {
            request_id: request.request_id,
            status: STATUS_OK,
            payload: vec![],
        },
        OP_HEALTH => ResponseFrame {
            request_id: request.request_id,
            status: STATUS_OK,
            payload: b"ok".to_vec(),
        },
        OP_HELLO => ResponseFrame {
            request_id: request.request_id,
            status: STATUS_OK,
            payload: PROTOCOL_VERSION.to_le_bytes().to_vec(),
        },
        // F-G5-006: SWIM heartbeats use the dedicated UDP gossip port, not
        // this TCP data port. The OP_HEARTBEAT constant exists for clients
        // that have not been updated to use the gossip transport — respond
        // with STATUS_OK and an empty payload instead of falling into the
        // catch-all "unknown opcode" error so an operator who misconfigures
        // a probe doesn't see misleading ERR_INTERNAL responses.
        OP_HEARTBEAT => ResponseFrame {
            request_id: request.request_id,
            status: STATUS_OK,
            payload: vec![],
        },
        // F-G5-015: OP_INCREMENT_SPENT_EXTRA_RECS is a no-op compatibility
        // shim retained for clients carried over from the pre-TeraSlab Lua
        // UDF. The old store maintained extra-records counters that
        // TeraSlab tracks implicitly via UTXO generation. Returning
        // STATUS_OK with an empty payload is the contract: callers expect
        // success and do not parse a body. Returning an error here would
        // break legacy clients; logging on every call would flood the
        // logs. The constant is retained until all clients have migrated;
        // a counter would be a better signal, but a counter requires
        // shared mutable state and the call-site is hot.
        OP_INCREMENT_SPENT_EXTRA_RECS => ResponseFrame {
            request_id: request.request_id,
            status: STATUS_OK,
            payload: vec![], // No-op compatibility shim
        },
        OP_STREAM_CHUNK => handle_stream_chunk(request, conn_state, blob_store, cluster),
        OP_STREAM_END => handle_stream_end(request, conn_state, cluster),
        OP_REPLICA_BATCH => {
            // Dispatch replication batch to the receiver's apply logic.
            // During migration, flags bit FLAG_MIGRATION_BATCH is set
            // and request_id carries the shard number. Register this
            // shard as actively receiving inbound migration data so
            // the read/write path knows to wait for completion.
            // Normal replication batches do NOT set this flag.
            if request.flags & FLAG_MIGRATION_BATCH != 0
                && let Some(cluster) = cluster
            {
                // F-G5-010: request_id is overloaded to carry the shard
                // number for migration batches. Reject any caller whose
                // upper 48 bits are non-zero — that would silently land
                // on a different shard than the caller intended (typo,
                // bug, or attacker repurposing the field).
                if request.request_id >> 16 != 0 {
                    return error_response(
                        request.request_id,
                        ERR_INVARIANT_VIOLATION,
                        "FLAG_MIGRATION_BATCH: request_id must encode shard in low 16 bits",
                    );
                }
                let shard = request.request_id as u16;
                let already_expected = cluster.inbound_bitmap().test(shard);
                let should_track_handoff = {
                    let table = cluster.shard_table();
                    let table = table.read();
                    table.shard_handoff_state(shard) != ShardHandoff::ServingNew
                };
                if already_expected || should_track_handoff {
                    cluster.mark_inbound_active(shard);
                }
            }
            // Phase B3: route the receiver's local cluster_key view through
            // the coordinator-owned `RunningCluster` accessor instead of a
            // global atomic. When dispatch is invoked without a cluster
            // (single-node tests, non-clustered mode) the gate falls back to
            // `0` which preserves the V1-compat "accept all" behavior.
            let local_cluster_key = cluster.map(|c| c.local_cluster_key()).unwrap_or(0);
            if let Some(applied) = REPLICA_APPLIED_TRACKER.get() {
                handle_replica_batch_with_tracker(
                    request,
                    engine,
                    &DISPATCH_REPLICA_LAST_APPLIED,
                    Some(applied),
                    DEFAULT_STREAM_KEY,
                    local_cluster_key,
                )
            } else {
                // Test harness / single-stream path: route through the
                // cluster-key-aware variant so the gate honors the
                // coordinator's view even without a persistent tracker.
                // The receiver still uses a thread-local in-memory
                // tracker internally, so parallel tests stay isolated.
                crate::replication::receiver::handle_replica_batch_with_cluster_key(
                    request,
                    engine,
                    &DISPATCH_REPLICA_LAST_APPLIED,
                    local_cluster_key,
                )
            }
            // NOTE: We do NOT mark inbound shards as complete here.
            // Only the OP_MIGRATION_COMPLETE handshake clears the
            // pending-inbound flag, after verifying the data arrived.
        }
        OP_MIGRATION_COMPLETE => {
            // Migration-complete handshake: the source has finished
            // streaming all batches for a shard and wants confirmation
            // that we received the data. The request_id carries the shard.
            //
            // Payload format:
            //   [record_count:8]                 — expected records (0 = empty shard)
            //   [fence_sequence:8] (optional)    — redo fence sequence for audit
            //   [topology_epoch:8] (optional)    — reject stale migrations
            //   [manifest_hash:32] (optional)    — XOR-hash of (txid, generation) pairs
            // F-G5-004: reject any caller that sets the upper 48 bits of
            // request_id. Like FLAG_MIGRATION_BATCH (F-G5-010), the field
            // is overloaded for shard identity here; a typo or repurposed
            // id must not silently target an unintended shard.
            if request.request_id >> 16 != 0 {
                return error_response(
                    request.request_id,
                    ERR_INVARIANT_VIOLATION,
                    "OP_MIGRATION_COMPLETE: request_id must encode shard in low 16 bits",
                );
            }
            let shard = request.request_id as u16;

            // ABORT (FLAG_MIGRATION_ABORT). The source could not finish the
            // outbound transfer (baseline/late-key/delta/manifest/commit
            // failure) and is telling us to abandon the in-flight inbound for
            // this shard. An abort is precisely the case where the partial copy
            // will NOT match any record count, so it MUST bypass the
            // manifest-evidence + count + prune machinery below — otherwise it
            // is rejected as a "record count mismatch" and the shard stays
            // inbound-pending / fenced forever (the stuck-inbound outcome).
            //
            // We clear the inbound-pending fence so the shard converges, retain
            // any partial records (harmless residue — the source stays the
            // authoritative master+holder of an aborted, NON-committed handoff,
            // and the task-#28 orphan cleanup only reclaims after a recorded
            // committed handoff, never on an abort), and never commit the shard
            // to ourselves (the handoff did not complete). Idempotent: a shard
            // with no matching pending inbound entry is a no-op.
            if request.flags & FLAG_MIGRATION_ABORT != 0 {
                if let Some(cluster) = cluster {
                    let cleared = cluster.abort_inbound_migration(shard);
                    tracing::info!(
                        shard,
                        cleared,
                        "OP_MIGRATION_COMPLETE: abort — cleared inbound-pending, source stays authoritative",
                    );
                }
                return ResponseFrame {
                    request_id: request.request_id,
                    status: STATUS_OK,
                    payload: Vec::new(),
                };
            }

            let expected_records = le_u64_at(&request.payload, 0).unwrap_or(0);
            let _fence_sequence = le_u64_at(&request.payload, 8).unwrap_or(0);
            let migration_epoch = le_u64_at(&request.payload, 16).unwrap_or(0);
            let source_manifest: Option<[u8; 32]> = if request.payload.len() >= 56 {
                let mut h = [0u8; 32];
                h.copy_from_slice(&request.payload[24..56]);
                // All-zeros = no manifest (legacy source or empty shard).
                if h == [0u8; 32] { None } else { Some(h) }
            } else {
                None
            };
            let (source_entries, completion_from_node): (
                Option<Vec<(TxKey, u32)>>,
                Option<NodeId>,
            ) = if request.payload.len() >= 60 {
                let entry_count = match le_u32_at(&request.payload, 56) {
                    Some(n) => n as usize,
                    None => {
                        // H-LOW: a wire-decode failure is a hard "your bytes
                        // are wrong" error, not a transient/retryable one.
                        // Match the batched sibling (OP_MIGRATION_BATCH_COMPLETE),
                        // which uses ERR_PAYLOAD_MALFORMED for the identical
                        // decode failures, so a peer doesn't retry malformed
                        // bytes forever.
                        return error_response(
                            request.request_id,
                            ERR_PAYLOAD_MALFORMED,
                            "malformed exact-manifest entry count",
                        );
                    }
                };
                // R-043 (GH-04): use `checked_mul` + `checked_add` so
                // an attacker-controlled `entry_count` cannot overflow
                // `usize` (matters on 32-bit; defensive on 64-bit) and
                // produce a tiny `needed` that bypasses the size check
                // before allocating a `Vec::with_capacity(entry_count)`.
                // Pre-fix `60 + entry_count * 36` was an unchecked
                // multiply on a `u32::MAX` payload value.
                let needed = match 36usize
                    .checked_mul(entry_count)
                    .and_then(|n| n.checked_add(60))
                {
                    Some(n) => n,
                    None => {
                        // H-LOW: overflowing entry_count is malformed bytes,
                        // not transient — ERR_PAYLOAD_MALFORMED for parity
                        // with the batched sibling.
                        return error_response(
                            request.request_id,
                            ERR_PAYLOAD_MALFORMED,
                            &format!(
                                "shard {shard} entry_count overflow ({entry_count}); rejecting frame",
                            ),
                        );
                    }
                };
                if request.payload.len() < needed {
                    // H-LOW: a declared entry_count that doesn't match the
                    // frame length is malformed bytes — ERR_PAYLOAD_MALFORMED
                    // for parity with the batched sibling.
                    return error_response(
                        request.request_id,
                        ERR_PAYLOAD_MALFORMED,
                        &format!(
                            "shard {shard} malformed exact-manifest payload: need {needed} bytes, got {}",
                            request.payload.len(),
                        ),
                    );
                }
                let mut entries = Vec::with_capacity(entry_count);
                let mut pos = 60;
                for _ in 0..entry_count {
                    let mut txid = [0u8; 32];
                    txid.copy_from_slice(&request.payload[pos..pos + 32]);
                    pos += 32;
                    let Some(generation) = le_u32_at(&request.payload, pos) else {
                        // H-LOW: ERR_PAYLOAD_MALFORMED for parity with the
                        // batched sibling — malformed bytes, not transient.
                        return error_response(
                            request.request_id,
                            ERR_PAYLOAD_MALFORMED,
                            "malformed exact-manifest generation",
                        );
                    };
                    pos += 4;
                    entries.push((TxKey { txid }, generation));
                }
                let completion_from_node = if request.payload.len() >= needed + 8 {
                    match le_u64_at(&request.payload, needed) {
                        Some(node) => Some(NodeId(node)),
                        None => {
                            // H-LOW: ERR_PAYLOAD_MALFORMED for parity with the
                            // batched sibling — malformed bytes, not transient.
                            return error_response(
                                request.request_id,
                                ERR_PAYLOAD_MALFORMED,
                                "malformed migration completion source node",
                            );
                        }
                    }
                } else {
                    None
                };
                (Some(entries), completion_from_node)
            } else {
                (None, None)
            };

            // Phase 8 (deletion-tombstone §7): decode the optional TOMBSTONE
            // section. ONLY when reconciliation is enabled on THIS node AND the
            // source set FLAG_MIGRATION_TOMBSTONES. The section is appended after
            // the `from_node:u64` at `needed + 8`; a flagless / disabled receiver
            // never reads past `from_node`, so the off-path decode is
            // byte-identical to today (the trailing bytes are simply ignored).
            //
            // Wire: [version:1][count(M):4][M × (txid:32 || generation:4)].
            // An unrecognized version, a short/truncated section, or a malformed
            // count degrades to `None` (no tombstone section) — which makes the
            // §7 classify treat every extra local key as never-received and
            // TRANSFER it (no-loss), never a spurious drop.
            let source_tombstones: Option<Vec<(TxKey, u32)>> =
                if request.flags & FLAG_MIGRATION_TOMBSTONES != 0
                    && engine.tombstone_reconciliation_enabled()
                    && source_entries.is_some()
                {
                    // `needed` is in scope only inside the entries branch above, so
                    // recompute the tombstone-section offset from the parsed shape:
                    // 60 + entry_count*36 (entries) + 8 (from_node).
                    let entries_len = source_entries.as_ref().map(|e| e.len()).unwrap_or(0);
                    let section_off = 60usize
                        .checked_add(entries_len.saturating_mul(36))
                        .and_then(|n| n.checked_add(8));
                    match section_off {
                        Some(off) => decode_tombstone_section(&request.payload, off),
                        None => None,
                    }
                } else {
                    None
                };

            // The §7 reconciliation path engages ONLY when this node has the
            // flag on AND the source actually presented a tombstone section.
            // When false, EVERY decision below — the #29 prune, the superset
            // accept, the commit gate — is byte-identical to the pre-Phase-8
            // path. A flag-on receiver that gets a flagless/old source frame
            // (no section → `source_tombstones == None`) is NOT reconcile-active
            // and keeps the #29 behavior verbatim.
            let reconcile_active = engine.tombstone_reconciliation_enabled()
                && source_tombstones.is_some()
                && cluster.is_some();

            // Reject migrations from very stale topology epochs.
            // Allow 2 epochs of slack to accommodate re-activation cycles
            // where the epoch advances while migrations are in flight.
            if migration_epoch > 0
                && let Some(cluster) = cluster
            {
                let current_epoch = cluster.topology_epoch();
                if current_epoch > migration_epoch + 2 {
                    return error_response(
                        request.request_id,
                        ERR_MIGRATION_IN_PROGRESS,
                        &format!(
                            "stale migration epoch {migration_epoch} < current {current_epoch}"
                        ),
                    );
                }
                // W1.1 FIX A — the inverse direction: this node has NOT
                // yet activated the epoch the migration belongs to (its
                // shard table predates the handoff), so it cannot
                // meaningfully acknowledge the completion: the inbound
                // shard registration and the post-handoff assignment do
                // not exist locally yet. Acknowledging anyway let a
                // source commit a master move that a slow target never
                // recorded, leaving the shard permanently masterless.
                // Retryable — the source holds the handoff as pending.
                let local_version = cluster.shard_table().read().version;
                if local_version < migration_epoch {
                    return error_response(
                        request.request_id,
                        ERR_MIGRATION_TARGET_NOT_READY,
                        &format!(
                            "shard {shard} target shard-table version {local_version} has not activated migration epoch {migration_epoch}"
                        ),
                    );
                }
            }

            let verify_only = request.flags & FLAG_MIGRATION_VERIFY_ONLY != 0;

            // SUPERSET probe (sc09/sc05 drain convergence — transfer-then-
            // relinquish). A gracefully-draining node that re-asserted stale
            // mastership of a NON-empty shard a live peer already took over
            // streams its (older) copy to the rightful master, then asks: "do
            // you now hold EVERY (txid, generation) in my exact manifest?".
            // Because the rightful master already holds the shard AND has
            // accepted writes the draining node never saw, its actual count is
            // a strict SUPERSET of the source's — the normal exact-count
            // completion is rejected as a count mismatch and the source rolls
            // the non-empty shard back to itself forever (the ~5-shard drain
            // stall). This probe answers superset containment instead of count
            // equality: it confirms every source entry is present locally with
            // the matching generation and returns STATUS_OK regardless of
            // EXTRA local records. A STATUS_OK proves the source's data is safe
            // here, so the source may relinquish the phantom mastership.
            //
            // Strictly verify-only and non-mutating: it requires the
            // VERIFY_ONLY flag and an exact-entry manifest, performs NO prune,
            // NO commit, and NO inbound-state change. A mismatch is reported as
            // a retryable error and changes nothing, so the source keeps the
            // data and rolls back (no-loss). It deliberately runs BEFORE the
            // count/prune machinery so the rightful master's legitimate extra
            // records never trip the exact-count reject.
            if request.flags & FLAG_MIGRATION_SUPERSET_OK != 0 {
                if !verify_only {
                    return error_response(
                        request.request_id,
                        ERR_INVARIANT_VIOLATION,
                        &format!(
                            "shard {shard} superset probe requires FLAG_MIGRATION_VERIFY_ONLY",
                        ),
                    );
                }
                let entries = match source_entries.as_ref() {
                    Some(e) if !e.is_empty() => e,
                    _ => {
                        return error_response(
                            request.request_id,
                            ERR_MIGRATION_MANIFEST_REQUIRED,
                            &format!(
                                "shard {shard} superset probe requires a non-empty exact-entry manifest",
                            ),
                        );
                    }
                };
                for (key, expected_generation) in entries {
                    let meta = match engine.read_metadata(key) {
                        Ok(meta) => meta,
                        Err(_) => {
                            // The target does NOT hold this source record:
                            // superset containment fails. Retryable — the
                            // source keeps the data and rolls back.
                            return error_response(
                                request.request_id,
                                ERR_MIGRATION_IN_PROGRESS,
                                &format!(
                                    "shard {shard} superset probe: target missing key {:?}",
                                    key,
                                ),
                            );
                        }
                    };
                    // Copy out of the packed-struct field before referencing
                    // it (an unaligned reference to a packed field is UB).
                    let actual_generation = meta.generation;
                    // Generation is a monotonic per-record mutation counter: a
                    // HIGHER local generation means the target applied STRICTLY
                    // MORE mutations to this record than the source ever saw
                    // (e.g. spends the draining/stale source missed). The
                    // source's state is then a prefix of the target's — still a
                    // superset for the source, so dropping it is no-loss. A
                    // LOWER local generation means the target is BEHIND the
                    // source on this record (the source holds a mutation the
                    // target lacks); that is NOT a superset, so reject and let
                    // the source keep the data.
                    if actual_generation < *expected_generation {
                        return error_response(
                            request.request_id,
                            ERR_MIGRATION_IN_PROGRESS,
                            &format!(
                                "shard {shard} superset probe: target behind for {:?}: source generation {}, target {}",
                                key, expected_generation, actual_generation,
                            ),
                        );
                    }
                }
                // Every source entry is present locally at a generation >= the
                // source's: the target holds a superset (equal or newer). No
                // mutation.
                return ResponseFrame {
                    request_id: request.request_id,
                    status: STATUS_OK,
                    payload: Vec::new(),
                };
            }

            // Safety requirement (R-219): every completion, including an
            // empty shard (`record_count == 0`), MUST send cryptographic
            // manifest evidence. The prior zero-count/no-manifest fast path
            // let a stale source clear inbound state for a non-empty shard
            // without proving the target's contents.
            //
            // Phase 8: when reconciliation is active the TOMBSTONE section is
            // itself authoritative manifest evidence (the source proved which
            // keys it deleted), so a tombstone-only completion (empty live set)
            // is admissible. This OR is gated on `reconcile_active`, so the
            // off-path R-219 requirement is unchanged.
            let has_manifest_evidence = source_manifest.is_some()
                || source_entries.as_ref().is_some_and(|e| !e.is_empty())
                || (reconcile_active && source_tombstones.is_some());
            if !has_manifest_evidence {
                return error_response(
                    request.request_id,
                    ERR_MIGRATION_MANIFEST_REQUIRED,
                    &format!(
                        "shard {shard} migration-complete with record_count={expected_records} requires manifest hash or exact-entry manifest",
                    ),
                );
            }

            // DATA-LOSS GATE (task #29). The exact-entry manifest reconciliation
            // below deletes every local key for this shard that the source's
            // manifest omits. That is only correct when the manifest is the
            // COMPLETE, AUTHORITATIVE set for the shard. The residual data-loss bug
            // (the `holders=[N,N,N]` stranding in scenario_05 / scenario_07) came
            // from a SHORT manifest whose source was NOT the authoritative holder
            // of the shard's complete contents: a still-catching-up rejoining node,
            // or a completion from a stale/superseded migration plan. Such a
            // manifest under-reports the shard, so pruning the target down to it
            // deletes GOOD records the live topology still expects — and when every
            // holder receives the same short manifest, the last copy is lost.
            //
            // We therefore prune ONLY when BOTH hold:
            //
            //   1. EPOCH-CURRENT. The completion is stamped with an epoch (>0) that
            //      equals this node's currently-activated shard-table version. This
            //      mirrors `migration_epoch_current` in coordinator.rs, which makes
            //      a mismatched-epoch completion get "ignored as stale" — such a
            //      completion (e.g. an epoch-N scale-up completion arriving after
            //      the cluster activated epoch N+1) must never drive a destructive
            //      prune. A legacy no-epoch frame (epoch == 0) cannot be proven
            //      current and is treated as untrusted.
            //
            //   2. SOURCE IS THE AUTHORITATIVE HOLDER. The completion source
            //      (`from_node`) is the node that legitimately holds the complete
            //      authoritative copy of the shard at this epoch: the committed
            //      (target) master, OR the effective/old master that is still
            //      authoritative mid-handoff (`effective_assignment`, which returns
            //      the pre-handoff owner until the shard commits — this is the
            //      node streaming the data out in a normal handoff, including a
            //      draining node in scale-down). A source that is neither — a peer
            //      that merely holds a partial copy, or a rejoining node still
            //      assembling its set — is NOT authoritative; its omission of a key
            //      is not evidence the key is stale, so the key is retained.
            //
            // Within a single current-epoch migration the authoritative source
            // builds its manifest from the same consistent snapshot it streams (see
            // the manifest fold in `stream_shard_to_target`), so a current-epoch
            // manifest from the authoritative holder is a faithful, complete
            // account — pruning the target down to it correctly removes
            // genuinely-stale residue (e.g. a record the authoritative path
            // deleted/spent), preserving the prune's legitimate anti-resurrection
            // purpose.
            //
            // When the source is NOT authoritative-complete, the extra local keys
            // are RETAINED. The subsequent exact count check (`actual ==
            // expected_records`) then fails with the retryable
            // `ERR_MIGRATION_IN_PROGRESS`, which leaves the shard's inbound state
            // pending — i.e. the shard is NOT committed/unfenced on this node, so a
            // retained record cannot be served to a client as a possibly-stale
            // (spent) UTXO. The authoritative current-epoch migration, or the
            // committed-handoff-gated orphan cleanup (task #28), reconciles any
            // genuinely-stale residue. Bias: never delete the last copy on a
            // stale/untrusted manifest.
            let source_is_authoritative_complete = if let Some(cluster) = cluster {
                let shard_table = cluster.shard_table();
                let table = shard_table.read();
                let epoch_current = migration_epoch > 0 && migration_epoch == table.version;
                epoch_current
                    && completion_from_node.is_some_and(|src| {
                        // Authoritative holder = committed (target) master, or the
                        // effective/old master still authoritative mid-handoff.
                        table.target_assignment(shard).master == src
                            || table.effective_assignment(shard).master == src
                    })
            } else {
                // No cluster context (single-node / unit harness without a shard
                // table): there is no committed epoch or owner to verify against,
                // so the completion cannot be proven authoritative. Retain.
                false
            };

            // Phase 8: when reconciliation is ENABLED, the destructive #29
            // "prune the whole shard down to the manifest" is REPLACED by the
            // §7 "drop exactly the tombstoned keys" union applied at the commit
            // gate. Skip the #29 prune for the WHOLE shard whenever
            // reconciliation is enabled — NOT merely per-frame `reconcile_active`
            // (BUG3 fix).
            //
            // Why whole-shard, not per-frame: the union is PER-SHARD, but
            // `reconcile_active` is PER-FRAME (it requires THIS frame's
            // `source_tombstones.is_some()`). With heterogeneous sources, source
            // X may carry tombstones (reconcile_active=true → #29 skipped, X
            // accumulates) while source Y is authoritative-complete but ships NO
            // tombstone section (reconcile_active=false → #29 prune would RUN for
            // Y's frame, deleting a legit-extra LIVE key `j` via
            // `engine.delete()`, which WRITES a tombstone → replicates →
            // cluster-wide loss). Under reconciliation, ALL destructive removal
            // must go EXCLUSIVELY through the commit-gate union
            // (`apply_tombstone_reconciliation`), which is no-loss by
            // construction (Claim B). So gate the #29 prune on
            // `!tombstone_reconciliation_enabled()`.
            //
            // OFF path (reconciliation disabled): the condition is exactly
            // `!false == true`, identical to the pre-Phase-8 `#29` guard, so the
            // prune runs verbatim.
            if !engine.tombstone_reconciliation_enabled()
                && source_is_authoritative_complete
                && let Some(entries) = source_entries.as_ref()
                && !entries.is_empty()
                && entries.len() as u64 == expected_records
            {
                let expected_keys: std::collections::HashSet<TxKey> =
                    entries.iter().map(|(key, _)| *key).collect();
                for key in engine.keys_for_shard(shard) {
                    if expected_keys.contains(&key) {
                        continue;
                    }
                    match engine.delete(&crate::ops::remaining::DeleteRequest {
                        tx_key: key,
                        due_guard: None,
                    }) {
                        Ok(()) | Err(crate::ops::error::SpendError::TxNotFound) => {}
                        Err(e) => {
                            return error_response(
                                request.request_id,
                                ERR_MIGRATION_IN_PROGRESS,
                                &format!(
                                    "shard {shard} failed to prune stale key {:?}: {e:?}",
                                    key,
                                ),
                            );
                        }
                    }
                }
            }

            // Exact-entry verification runs BEFORE the count decision so it can
            // serve as the SUPERSET proof (Fix B). When the source ships an exact
            // (txid, generation) manifest, proving every source key is present
            // locally at the matching generation is strictly stronger evidence
            // than a count equality: it confirms the target holds EVERY record
            // the source streamed, regardless of how many EXTRA records the
            // target also holds.
            //
            // NOTE: concurrent multi-source inbound migration of the SAME shard
            // (overlapping plans during a rolling restart / epoch churn) is
            // intentionally TOLERATED here, not serialized. Several sources may
            // stream the same shard to this target; the target's per-shard count
            // is then the UNION (superset) of all sources. We accept each
            // source's completion on a verified superset (below) and gate the
            // actual COMMIT on `!has_pending_inbound_shard` so the handoff only
            // commits once EVERY pending source has completed.
            //
            // Only treat the exact-entry manifest as usable when it is non-empty
            // AND its length matches the expected record count. An empty
            // exact-entry list with `record_count > 0` is not evidence of
            // anything — the receiver must still verify via the SHA-256 manifest
            // (H3 safety requirement).
            let exact_entries_verified = if let Some(entries) = source_entries.as_ref()
                && !entries.is_empty()
                && entries.len() as u64 == expected_records
            {
                for (key, expected_generation) in entries {
                    let meta = match engine.read_metadata(key) {
                        Ok(meta) => meta,
                        Err(e) => {
                            // Missing source key: the target does NOT hold a
                            // record the source streamed. No-loss reject — never
                            // commit when a source key is absent.
                            return error_response(
                                request.request_id,
                                ERR_MIGRATION_IN_PROGRESS,
                                &format!("shard {shard} missing exact key {:?}: {e:?}", key,),
                            );
                        }
                    };
                    let actual_generation = meta.generation;
                    if actual_generation != *expected_generation {
                        return error_response(
                            request.request_id,
                            ERR_MIGRATION_IN_PROGRESS,
                            &format!(
                                "shard {shard} generation mismatch for {:?}: expected {}, got {}",
                                key, expected_generation, actual_generation,
                            ),
                        );
                    }
                }
                true
            } else {
                false
            };

            // EPOCH-CURRENCY of the completion. A superset accept (below) may
            // only COMMIT the shard when the completion is stamped with the
            // node's currently-activated epoch. This is the discriminator that
            // separates the two superset cases:
            //
            //   * CONCURRENT MULTI-SOURCE (the bug Fix B fixes): overlapping
            //     CURRENT-epoch migration plans stream the same shard to this
            //     target during a rolling restart. The target's extra records
            //     come from OTHER current-epoch sources and are live — safe to
            //     accept + commit even though THIS source is not the master.
            //
            //   * STALE-EPOCH SHORT MANIFEST (task #29): a completion from a
            //     SUPERSEDED migration plan whose manifest lags the live
            //     topology. Its extra local records may be genuinely-stale
            //     residue (e.g. a UTXO the authoritative master already spent).
            //     Committing on its verified subset would unfence the shard and
            //     let those possibly-stale extras be served. Such a completion is
            //     NOT epoch-current, so it falls through to the STRICT count
            //     check and is rejected (shard stays fenced) — exactly the #29
            //     anti-stale-serving guarantee. The #29 prune gate above already
            //     retains the extras; this keeps them unservable until the
            //     authoritative current-epoch migration reconciles them.
            //
            // A legacy no-epoch completion (epoch == 0) cannot be proven current
            // and is treated as not-current → strict.
            let completion_epoch_current = if let Some(cluster) = cluster {
                let shard_table = cluster.shard_table();
                let table = shard_table.read();
                migration_epoch > 0 && migration_epoch == table.version
            } else {
                false
            };

            // Count decision (Fix B — accept a VERIFIED, EPOCH-CURRENT superset).
            //
            //   * expected_records == 0: a CURRENT-epoch source that streamed
            //     ZERO records (empty snapshot / stale re-attempt) is allowed to
            //     complete regardless of the target's total. The target's records
            //     belong to OTHER concurrent sources whose own completions verify
            //     them; the empty source has nothing to transfer, and the
            //     relinquish disposition (#25) only drops EMPTY shards from a
            //     source, so an empty completion never causes the source to drop
            //     real data. Gated on epoch currency so a stale empty completion
            //     cannot unfence a shard holding possibly-stale extras.
            //
            //   * exact_entries_verified && epoch-current: the per-key loop above
            //     already proved the target holds EVERY source key at the matching
            //     generation — a verified superset. Accept `actual >=
            //     expected_records`; the EXTRA local keys are legitimate
            //     current-epoch shard records (other concurrent sources /
            //     pre-existing replica copies) and are KEPT.
            //
            //   * hash-only manifest (no usable exact entries): the manifest hash
            //     folds over ALL keys_for_shard(target), so any superset changes
            //     the hash. A superset cannot be verified via hash, so this path
            //     KEEPS the strict `actual == expected_records` requirement.
            //
            //   * reconcile_active && exact_entries_verified (BUG2): a
            //     reconciliation source that proved its full live set is present
            //     locally is accepted as a verified superset EVEN WHEN it is not
            //     epoch-current (a within-slack source, migration_epoch ==
            //     version-1). This is required so the within-slack source can
            //     REACH the accumulate + mark-inbound-complete path below and
            //     contribute its LIVE set to the union (Claim B no-loss): a key
            //     live on the within-slack source must be Kept, not Dropped by a
            //     concurrent source's tombstone. Its TOMBSTONES are NOT
            //     accumulated (only epoch-current tombstones drive drops, §9.1
            //     #2), and the commit-gate union + epoch-stamp (BUG4) keep this
            //     no-loss / resurrection-proof. Gated on `reconcile_active`, so
            //     the OFF path is unaffected.
            //
            //   * anything not epoch-current (and not reconcile_active): STRICT
            //     `actual == expected_records` (preserves #29).
            let actual = engine.shard_record_count(shard);
            let count_ok = if expected_records == 0 && completion_epoch_current {
                true
            } else if exact_entries_verified && (completion_epoch_current || reconcile_active) {
                actual >= expected_records
            } else {
                actual == expected_records
            };

            if !count_ok {
                return error_response(
                    request.request_id,
                    ERR_MIGRATION_IN_PROGRESS,
                    &format!(
                        "shard {shard} record count mismatch: expected {expected_records}, got {actual}"
                    ),
                );
            }

            // Skip the expensive O(N) manifest hash scan when exact-entry
            // verification already confirmed every key's generation — the
            // manifest hash would recompute the same result.
            //
            // Phase 8: also skip when reconciliation is active. The rejoinee
            // LEGITIMATELY holds extra keys (the over-count being reconciled),
            // so the whole-shard hash fold would never match the source's
            // (smaller) live-set hash. The §7 classify is the authoritative
            // reconciliation instead. Gated on `reconcile_active`, so the
            // off-path hash check is unchanged.
            if !reconcile_active
                && !exact_entries_verified
                && let Some(expected_hash) = source_manifest
            {
                let mut local_manifest = crate::cluster::coordinator::ManifestHasher::new();
                for key in engine.keys_for_shard(shard) {
                    let meta = match engine.read_metadata(&key) {
                        Ok(meta) => meta,
                        Err(e) => {
                            return error_response(
                                request.request_id,
                                ERR_MIGRATION_IN_PROGRESS,
                                &format!(
                                    "shard {shard} manifest read_metadata failed for {:?}: {e:?}",
                                    key,
                                ),
                            );
                        }
                    };
                    local_manifest.fold(&key.txid, meta.generation);
                }
                let local_hash = local_manifest.finalize();
                if local_hash != expected_hash {
                    return error_response(
                        request.request_id,
                        ERR_MIGRATION_MANIFEST_MISMATCH,
                        &format!(
                            "shard {shard} manifest hash mismatch (count matched at {actual} records but content differs)",
                        ),
                    );
                }
            }

            if verify_only {
                return ResponseFrame {
                    request_id: request.request_id,
                    status: STATUS_OK,
                    payload: Vec::new(),
                };
            }

            if let Some(cluster) = cluster {
                // Phase 8 (§9.1 #1 + §9.1 #2): accumulate THIS source's live +
                // tombstone manifest for the multi-source union.
                //
                // INVARIANT (design §7, Claim B no-loss): a key live on ANY
                // pending source ⇒ Keep; the union must see every pending
                // source's LIVE set regardless of epoch-currency. So the LIVE
                // set is accumulated UNCONDITIONALLY for every reconcile-active
                // pending source (BUG2 fix, option (a)). Otherwise a within-slack
                // (migration_epoch == version-1) completion — which is admitted
                // past the stale-epoch reject (2-epoch slack) but is NOT
                // `completion_epoch_current` — would clear its inbound-pending
                // bit (below) WITHOUT contributing its live keys, and a
                // concurrent source that tombstones one of those keys would then
                // wrongly Drop a key that is still LIVE on the within-slack
                // source. Accumulating its live set keeps the union complete
                // while still letting the source complete (liveness preserved).
                //
                // The TOMBSTONE set, by contrast, stays epoch-gated: a
                // non-epoch-current source's tombstones are untrusted and must
                // NEVER drive a drop (design §9.1 #2). So tombstones are included
                // ONLY when `completion_epoch_current`; a within-slack source
                // contributes live keys but zero drop-driving tombstones.
                //
                // The manifest is stamped with `migration_epoch` (BUG4 fix (a))
                // so the commit gate can DISCARD any accumulator entry whose
                // epoch is stale relative to the committed/migration epoch before
                // computing the union — a superseded plan's stale {tomb k} must
                // not drive a Drop of a now-live k in a later epoch.
                //
                // Accumulate ONLY when this node is the prospective TARGET MASTER
                // for the shard (BUG4 fix (c)): a non-master/replica target never
                // applies the union (the commit gate below requires master), so
                // accumulating there would only leak entries.
                let prospective_target_master = {
                    let shard_table = cluster.shard_table();
                    let table = shard_table.read();
                    table.target_assignment(shard).master == cluster.self_id()
                };
                if reconcile_active && prospective_target_master {
                    let live = source_entries
                        .as_ref()
                        .map(|e| e.iter().map(|(k, _)| *k).collect::<Vec<_>>())
                        .unwrap_or_default();
                    // Only an epoch-current source's tombstones may drive drops.
                    let tombstones = if completion_epoch_current {
                        source_tombstones.clone().unwrap_or_default()
                    } else {
                        Vec::new()
                    };
                    cluster.accumulate_reconcile_manifest(
                        shard,
                        crate::cluster::coordinator::SourceReconcileManifest {
                            live,
                            tombstones,
                            epoch: migration_epoch,
                        },
                    );
                }

                if let Some(from_node) = completion_from_node {
                    cluster.mark_inbound_complete_from_source(shard, from_node);
                } else {
                    cluster.mark_inbound_complete(shard);
                }
                let should_commit = {
                    let shard_table = cluster.shard_table();
                    let table = shard_table.read();
                    table.target_assignment(shard).master == cluster.self_id()
                } && !cluster.has_pending_inbound_shard(shard);
                if should_commit {
                    // Phase 8 (§7 + §9.1 #1): apply the tombstone-driven drops
                    // against the UNION of all pending sources BEFORE committing
                    // the shard. Gated on the flag so the OFF path never touches
                    // the accumulator — byte-identical commit to today.
                    if engine.tombstone_reconciliation_enabled()
                        && let Err(e) = apply_tombstone_reconciliation(engine, cluster, shard)
                    {
                        // A drop failure must NOT silently commit a shard whose
                        // over-count we failed to reconcile. Report retryable so
                        // the source re-drives; NOT committing here preserves the
                        // inbound-pending semantics.
                        return error_response(
                            request.request_id,
                            ERR_MIGRATION_IN_PROGRESS,
                            &format!("shard {shard} tombstone reconciliation failed: {e}"),
                        );
                    }
                    cluster.shard_table().write().commit_shard(shard);
                }
            }
            ResponseFrame {
                request_id: request.request_id,
                status: STATUS_OK,
                payload: Vec::new(),
            }
        }
        OP_MIGRATION_BATCH_COMPLETE => {
            // Batched migration-complete: marks multiple shards as done
            // in a single TCP frame. Wire format:
            //   [shard_count:4][shard_id:2 × count][from_node:8][topology_epoch:8]
            // The trailing topology_epoch (W1.1 FIX A) is optional for
            // backward compatibility with pre-FIX-A senders.
            if request.payload.len() < 4 {
                return error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    "batch-complete: too short",
                );
            }
            let shard_count = match le_u32_at(&request.payload, 0) {
                Some(n) => n as usize,
                None => {
                    return error_response(
                        request.request_id,
                        ERR_PAYLOAD_MALFORMED,
                        "batch-complete: malformed shard count",
                    );
                }
            };
            let expected_len = match 2usize
                .checked_mul(shard_count)
                .and_then(|n| n.checked_add(4))
                .and_then(|n| n.checked_add(8))
            {
                Some(len) => len,
                None => {
                    return error_response(
                        request.request_id,
                        ERR_PAYLOAD_MALFORMED,
                        &format!(
                            "batch-complete: shard_count overflow ({shard_count}); rejecting frame"
                        ),
                    );
                }
            };
            if request.payload.len() < expected_len {
                return error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    &format!(
                        "batch-complete: need {expected_len} bytes, got {}",
                        request.payload.len()
                    ),
                );
            }
            let mut shards = Vec::with_capacity(shard_count);
            for i in 0..shard_count {
                let off = 4 + i * 2;
                let Some(shard) = le_u16_at(&request.payload, off) else {
                    return error_response(
                        request.request_id,
                        ERR_PAYLOAD_MALFORMED,
                        "batch-complete: malformed shard id",
                    );
                };
                shards.push(shard);
            }
            let from_node_off = 4 + shard_count * 2;
            let Some(from_node_id) = le_u64_at(&request.payload, from_node_off) else {
                return error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    "batch-complete: malformed source node",
                );
            };
            let from_node = NodeId(from_node_id);
            // W1.1 FIX A — optional trailing topology epoch stamped by
            // the source's activation. Absent on legacy frames.
            let migration_epoch = le_u64_at(&request.payload, from_node_off + 8).unwrap_or(0);

            if migration_epoch > 0
                && let Some(cluster) = cluster
            {
                // Mirror the OP_MIGRATION_COMPLETE stale-source check
                // (2 epochs of slack for in-flight re-activation cycles).
                let current_epoch = cluster.topology_epoch();
                if current_epoch > migration_epoch + 2 {
                    return error_response(
                        request.request_id,
                        ERR_MIGRATION_IN_PROGRESS,
                        &format!(
                            "stale migration epoch {migration_epoch} < current {current_epoch}"
                        ),
                    );
                }
                // W1.1 FIX A — this node has not activated the epoch the
                // handoff belongs to: its shard table has neither the
                // post-handoff assignments nor the pending-inbound
                // registrations, so "completing" here would let the
                // source commit a master move this node never recorded
                // (the CI-confirmed masterless-shard deadlock).
                // Retryable: the source treats it as pending.
                let local_version = cluster.shard_table().read().version;
                if local_version < migration_epoch {
                    return error_response(
                        request.request_id,
                        ERR_MIGRATION_TARGET_NOT_READY,
                        &format!(
                            "target shard-table version {local_version} has not activated migration epoch {migration_epoch}"
                        ),
                    );
                }
            }

            if let Some(cluster) = cluster {
                cluster.mark_inbound_complete_many_from_source(&shards, from_node);
                // Batch-commit all shards where this node is the new master
                // and no inbound is pending.
                let self_id = cluster.self_id();
                let shard_table = cluster.shard_table();
                let mut table = shard_table.write();
                for &shard in &shards {
                    let is_new_master = table.target_assignment(shard).master == self_id;
                    if is_new_master && !cluster.has_pending_inbound_shard(shard) {
                        table.commit_shard(shard);
                    }
                }
                drop(table);
                let _ = from_node; // Used for audit logging if needed
            }

            ResponseFrame {
                request_id: request.request_id,
                status: STATUS_OK,
                payload: Vec::new(),
            }
        }
        OP_MIGRATION_TRANSFER_REQUEST => {
            // W1.1 FIX B — a migration target whose committed topology
            // says it should hold the listed shards, but which has
            // pending inbound migrations and no incoming pushes, asks
            // this node to (re-)run the outbound migration for them.
            // Wire format:
            //   [topology_epoch:8][requester_node:8][shard_count:4][shard_id:2 × count]
            let cluster = match cluster {
                Some(c) => c,
                None => {
                    return error_response(request.request_id, ERR_NOT_CLUSTERED, "not clustered");
                }
            };
            let (Some(epoch), Some(requester_id), Some(shard_count)) = (
                le_u64_at(&request.payload, 0),
                le_u64_at(&request.payload, 8),
                le_u32_at(&request.payload, 16),
            ) else {
                return error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    "transfer-request: truncated header",
                );
            };
            let shard_count = shard_count as usize;
            if shard_count == 0 || shard_count > crate::cluster::shards::NUM_SHARDS {
                return error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    &format!("transfer-request: shard count {shard_count} out of range"),
                );
            }
            if request.payload.len() < 20 + shard_count * 2 {
                return error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    &format!(
                        "transfer-request: need {} bytes, got {}",
                        20 + shard_count * 2,
                        request.payload.len()
                    ),
                );
            }
            let mut shards = Vec::with_capacity(shard_count);
            for i in 0..shard_count {
                let Some(shard) = le_u16_at(&request.payload, 20 + i * 2) else {
                    return error_response(
                        request.request_id,
                        ERR_PAYLOAD_MALFORMED,
                        "transfer-request: malformed shard id",
                    );
                };
                shards.push(shard);
            }
            // Both sides must have activated the same topology term:
            // - behind → this node cannot serve a handoff it has not
            //   activated yet (the requester retries on its next cycle);
            // - ahead → the requester's view is stale; it must re-fetch
            //   the committed topology before asking again.
            let local_version = cluster.shard_table().read().version;
            if local_version < epoch {
                return error_response(
                    request.request_id,
                    ERR_MIGRATION_TARGET_NOT_READY,
                    &format!(
                        "source shard-table version {local_version} has not activated epoch {epoch}"
                    ),
                );
            }
            if local_version > epoch {
                return error_response(
                    request.request_id,
                    ERR_STALE_EPOCH,
                    &format!("transfer-request epoch {epoch} behind local version {local_version}"),
                );
            }
            let queued = cluster.signal_shard_transfer_request(
                crate::cluster::coordinator::ShardTransferRequest {
                    epoch,
                    requester: NodeId(requester_id),
                    shards,
                },
            );
            if !queued {
                return error_response(
                    request.request_id,
                    ERR_INTERNAL,
                    "transfer-request: coordinator shutting down",
                );
            }
            ResponseFrame {
                request_id: request.request_id,
                status: STATUS_OK,
                payload: Vec::new(),
            }
        }
        OP_TOPOLOGY_PROPOSE => {
            // Topology authority: another node is proposing a new term.
            //
            // Safety requirement (H10): `voted_term` MUST be fsync'd to disk
            // BEFORE the vote reply frame hits the wire. If the voter crashes
            // between reply and persist, the proposer may have already
            // counted our "yes" toward quorum while we come back thinking we
            // never voted — giving us license to vote "yes" for a *conflicting*
            // term and causing split-brain. The sequence is:
            //
            //   1. `handle_propose` records the vote in memory.
            //   2. `persist_topology` fsyncs it durably.
            //   3. Only then do we construct and return the reply frame.
            //
            // If step 2 fails we return `ERR_TOPOLOGY_PERSIST_FAILED` and the
            // proposer treats it as "no vote / retry".
            let cluster = match cluster {
                Some(c) => c,
                None => {
                    return error_response(request.request_id, ERR_NOT_CLUSTERED, "not clustered");
                }
            };
            match crate::cluster::topology::TopologyTerm::deserialize(&request.payload) {
                Some(propose) => {
                    let vote = cluster.topology_authority().handle_propose(&propose);
                    if vote.accepted
                        && let Err(e) = cluster.persist_topology()
                    {
                        return error_response(
                            request.request_id,
                            ERR_TOPOLOGY_PERSIST_FAILED,
                            &format!(
                                "topology vote accepted for term {} but persist failed: {e}",
                                propose.term,
                            ),
                        );
                    }
                    ResponseFrame {
                        request_id: request.request_id,
                        status: STATUS_OK,
                        payload: vote.serialize(),
                    }
                }
                None => error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    "malformed topology propose",
                ),
            }
        }
        OP_TOPOLOGY_VOTE => {
            // Topology authority: a peer voted on our proposal.
            // Check if quorum is reached — if so, broadcast commit.
            // The commit broadcast is handled by the coordinator event loop,
            // not here. We just return OK with any resulting commit.
            let cluster = match cluster {
                Some(c) => c,
                None => {
                    return error_response(request.request_id, ERR_NOT_CLUSTERED, "not clustered");
                }
            };
            match crate::cluster::topology::TopologyVote::deserialize(&request.payload) {
                Some(vote) => {
                    let commit = cluster.topology_authority().handle_vote(&vote);
                    let payload = match commit {
                        Some(c) => c.serialize(),
                        None => Vec::new(),
                    };
                    ResponseFrame {
                        request_id: request.request_id,
                        status: STATUS_OK,
                        payload,
                    }
                }
                None => error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    "malformed topology vote",
                ),
            }
        }
        OP_TOPOLOGY_COMMIT => {
            // Topology authority: a proposer achieved quorum and is committing.
            // Activate the shard table with the committed members.
            let cluster = match cluster {
                Some(c) => c,
                None => {
                    return error_response(request.request_id, ERR_NOT_CLUSTERED, "not clustered");
                }
            };
            match crate::cluster::topology::TopologyCommit::deserialize(&request.payload) {
                Some(commit) => {
                    let members = commit.members.clone();
                    if let Some(term) = cluster.topology_authority().handle_commit(&commit) {
                        // Safety requirement (H10): persist the committed
                        // `committed_term` / `committed_members` BEFORE
                        // replying so the commit survives a crash. If
                        // persist fails, refuse to ack; the proposer will
                        // retry and we'll re-apply on the retry.
                        if let Err(e) = cluster.persist_topology() {
                            return error_response(
                                request.request_id,
                                ERR_TOPOLOGY_PERSIST_FAILED,
                                &format!(
                                    "topology commit term {term} applied in memory but persist failed: {e}",
                                ),
                            );
                        }
                        tracing::info!(
                            term = term,
                            members = members.len(),
                            "cluster: topology committed"
                        );
                        // Signal the coordinator event loop to activate the
                        // shard table with the committed member list — only
                        // after the commit is durable.
                        cluster.signal_topology_committed(members, term);
                    }
                    ResponseFrame {
                        request_id: request.request_id,
                        status: STATUS_OK,
                        payload: Vec::new(),
                    }
                }
                None => error_response(
                    request.request_id,
                    ERR_PAYLOAD_MALFORMED,
                    "malformed topology commit",
                ),
            }
        }
        _ => error_response(request.request_id, ERR_OPCODE_UNSUPPORTED, "unknown opcode"),
    };

    // Record end-to-end handler latency into the appropriate histogram.
    // The per-item outcome counters are incremented inside each handler;
    // this records wall-clock time from dispatch entry to response built.
    if let Some(h) = DISPATCH_HISTOGRAMS.get() {
        match request.op_code {
            OP_SPEND_BATCH => {
                h.spend_latency.record_since(start);
                // spend_multi_latency shadows spend_latency for legacy
                // /admin/top compatibility — same samples.
                h.spend_multi_latency.record_since(start);
            }
            OP_UNSPEND_BATCH => h.unspend_latency.record_since(start),
            OP_CREATE_BATCH => h.create_latency.record_since(start),
            OP_SET_MINED_BATCH => h.set_mined_latency.record_since(start),
            OP_FREEZE_BATCH => h.freeze_latency.record_since(start),
            OP_UNFREEZE_BATCH => h.unfreeze_latency.record_since(start),
            OP_DELETE_BATCH => h.delete_latency.record_since(start),
            OP_GET_BATCH | OP_GET_SPEND_BATCH => h.get_latency.record_since(start),
            OP_MARK_LONGEST_CHAIN_BATCH => h.mark_longest_chain_latency.record_since(start),
            OP_REASSIGN_BATCH => h.reassign_latency.record_since(start),
            OP_SET_CONFLICTING_BATCH => h.set_conflicting_latency.record_since(start),
            OP_REMOVE_CONFLICTING_CHILD_BATCH => {
                h.remove_conflicting_child_latency.record_since(start)
            }
            OP_QUERY_CONFLICTING => h.query_conflicting_latency.record_since(start),
            OP_SET_LOCKED_BATCH => h.set_locked_latency.record_since(start),
            OP_PRESERVE_UNTIL_BATCH => h.preserve_until_latency.record_since(start),
            _ => {}
        }
    }

    response
}

// ---------------------------------------------------------------------------
// Redo log helper
// ---------------------------------------------------------------------------

// Production redo group-commit window. ZERO: the previous 200µs `thread::sleep`
// before every flush imposed a hard ~5k ops/s/connection latency floor (measured
// 6-163x throughput loss on a cheap-fsync device) while coalescing almost nothing
// (≈1.5 entries/flush). It is NOT reintroduced for any path: batched writes
// amortize the fsync, and concurrent flushes coalesce at fsync time via per-store
// parallel flush + the per-physical-device `PhysicalBarrier` (src/subdevice.rs) —
// with no artificial latency. `group_commit_window` keeps #21's per-call shape as
// a test seam, but with this constant at ZERO it returns ZERO for every input.
const REDO_GROUP_COMMIT_WINDOW: Duration = Duration::ZERO;

/// Group-commit wait applied before flushing a redo write.
///
/// The window exists so that, under concurrent load, a thread about to flush
/// pauses briefly to let other connections' appends land in the shared redo
/// buffer, coalescing them into a single fsync. That only helps when the write
/// is small: once a write already carries multiple ops, its fsync is amortized
/// over them and the fixed `thread::sleep` is pure added latency — the per-call
/// 200 µs floor (~5000 calls/s/connection) flagged in profiling. Teranode
/// traffic is always batched (≈742-item CreateBatch RPCs; whole SpendBatch
/// RPCs after target #2), so those paths skip the wait entirely; only genuine
/// single-op writes keep it, where coalescing with a concurrent writer is the
/// one case it can pay off.
///
/// NOTE: a fixed sleep is a crude group-commit. The proper fix (no fixed floor
/// at all, coalescing driven by an in-flight-flush condvar / leader-follower)
/// is tracked separately; this de-floors the batched paths with zero risk to
/// the existing single-op coalescing behaviour.
#[inline]
fn group_commit_window(ops_len: usize) -> Duration {
    // Only a genuine single-op write keeps the coalescing wait. Empty writes
    // (ops_len == 0) never reach the flush, and multi-op writes already
    // amortize the fsync, so both skip the floor.
    if ops_len == 1 {
        REDO_GROUP_COMMIT_WINDOW
    } else {
        Duration::ZERO
    }
}

/// Append redo ops to the log and flush.
///
/// Returns the sequence number of the last appended entry on success.
/// Returns an error string if the redo log write or flush fails — the
/// caller must fail the client request to maintain the durability
/// contract (every acknowledged mutation has a redo log entry).
///
/// When no redo log is configured (single-node test setups), returns
/// `Ok(0)` — the engine writes are still durable via O_DIRECT but
/// there is no crash recovery journal.
/// Write redo operations to the WAL and flush.
///
/// Returns `(first_seq, last_seq)` — the redo sequence range assigned to the
/// appended entries. These are the authoritative sequence numbers used by
/// replica catch-up and ACK tracking.
fn write_redo_ops(
    engine: &Engine,
    redo_log: Option<&Mutex<RedoLog>>,
    ops: &[RedoOp],
) -> std::result::Result<(u64, u64), String> {
    write_redo_ops_with_group_window(engine, redo_log, ops, group_commit_window(ops.len()))
}

fn write_redo_ops_with_group_window(
    engine: &Engine,
    redo_log: Option<&Mutex<RedoLog>>,
    ops: &[RedoOp],
    group_window: Duration,
) -> std::result::Result<(u64, u64), String> {
    if ops.is_empty() {
        return Ok((0, 0));
    }

    // Per-store redo: when per-store logs are attached, fan each op out to the
    // log owning its store and flush each touched store's log. The N fsyncs
    // run as parallel streams instead of serializing on one mutex; the shared
    // global sequence counter keeps the returned (first,last) range a valid
    // replication contract. The group-commit window is meaningless here (real
    // group commit happens at the per-physical-device barrier), so the routed
    // path ignores it.
    if engine.has_per_store_redo() {
        return engine.append_redo_ops_routed(ops);
    }

    // Single-handle path (tests / single-store-unconfigured): journal through
    // the directly-passed handle exactly as before. `None` means no journal.
    let redo = match redo_log {
        Some(r) => r,
        None => return Ok((0, 0)),
    };

    let (first_seq, last_seq) = {
        let mut log = redo.lock();
        // First sequence is the value the first append assigns; capture it
        // from the append itself so it is correct under both the local and
        // shared-global counters.
        let first_seq = log.append(ops[0].clone()).map_err(|e| {
            // F-G5-008: log the underlying I/O error (which may
            // contain file paths or kernel diagnostic strings) at
            // `error!` level for operator triage, but return a
            // sanitized message to the client so internal
            // deployment topology is not leaked through ERR_INTERNAL
            // payloads. Same treatment for `redo log flush` below.
            tracing::error!(err = %e, "redo log append failed");
            "redo log append failed".to_string()
        })?;
        let mut last_seq = first_seq;
        for op in &ops[1..] {
            last_seq = log.append(op.clone()).map_err(|e| {
                tracing::error!(err = %e, "redo log append failed");
                "redo log append failed".to_string()
            })?;
        }
        (first_seq, last_seq)
    };

    if !group_window.is_zero() {
        std::thread::sleep(group_window);
    }

    let mut log = redo.lock();
    log.flush().map_err(|e| {
        tracing::error!(err = %e, "redo log flush failed");
        "redo log flush failed".to_string()
    })?;
    Ok((first_seq, last_seq))
}

// ---------------------------------------------------------------------------
// Replication helper
// ---------------------------------------------------------------------------

/// Outcome of a replication attempt, conveyed back to request handlers so
/// they can pick the right response status for the client.
///
/// - [`ReplicationOutcome::NotApplicable`]: no replication was attempted —
///   either the server is not part of a cluster, there were no ops to
///   replicate, or no replica targets were resolved. The client response
///   is the natural `STATUS_OK` / `STATUS_PARTIAL_ERROR` for the handler.
/// - [`ReplicationOutcome::Full`]: every replica target ACKed successfully
///   (or the configured ACK policy was met for the normal case). Full
///   cluster durability was achieved; respond with `STATUS_OK`.
/// - [`ReplicationOutcome::Degraded`]: best-effort mode is active AND
///   **zero** replica targets ACKed. The mutation is durable only on the
///   local master; if the master crashes before catch-up streaming, the
///   write is lost. Respond with `STATUS_DEGRADED_DURABILITY` so the
///   client knows durability silently degraded to single-node.
///
/// The threshold for `Degraded` is deliberately "zero ACKs" (as opposed to
/// "less than quorum") because the *middle* case — some but not all
/// replicas ACKed — still satisfies the weakest commonly-desired invariant
/// (the write exists on at least one peer, so a single master crash will
/// not lose it). That case continues to emit `STATUS_OK` in best-effort
/// mode and only ticks the `replication_degraded_acks` telemetry counter.
/// The zero-ACK case is fundamentally different: the write exists on no
/// peer at all, and a master crash loses it unconditionally — that is the
/// signal the client actually needs.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum ReplicationOutcome {
    /// No replication was applicable (standalone, no ops, or no targets).
    NotApplicable,
    /// Every replica target ACKed successfully (or the ACK policy was met).
    Full,
    /// Best-effort mode: zero replica targets ACKed. Durability is
    /// single-node only and clients should be informed via
    /// `STATUS_DEGRADED_DURABILITY`.
    Degraded,
}

impl ReplicationOutcome {
    /// Whether this outcome indicates the client should receive
    /// `STATUS_DEGRADED_DURABILITY` instead of `STATUS_OK`.
    #[inline]
    pub(crate) fn is_degraded(self) -> bool {
        matches!(self, ReplicationOutcome::Degraded)
    }
}

#[inline]
fn valid_redo_range(range: (u64, u64)) -> bool {
    range.0 != 0 && range.1 >= range.0
}

fn begin_replication_intent_with_tracker(
    range: (u64, u64),
    keys: &[TxKey],
    tracker: Option<&crate::replication::durable::ReplicationIntentTracker>,
) -> std::result::Result<(), String> {
    if !valid_redo_range(range) {
        return Ok(());
    }
    if let Some(tracker) = tracker {
        tracker
            .begin(range.0, range.1, keys)
            .map_err(|e| format!("replication intent begin: {e}"))?;
    }
    Ok(())
}

/// Collect the EXACT key set of a batch of redo ops for the replication intent.
///
/// The intent's key set is the dedup'd union of every keyed redo op's tx_key
/// (control entries like `Checkpoint` have no key and are skipped). This is the
/// same key set that the corresponding `ReplicaOp`s carry, so recovery can
/// filter the merged redo window to exactly this RPC's keys and never re-ship a
/// foreign op whose sequence interleaved into the range.
fn intent_keys_from_redo_ops(ops: &[RedoOp]) -> Vec<TxKey> {
    let mut keys: Vec<TxKey> = Vec::with_capacity(ops.len());
    let mut seen: std::collections::HashSet<[u8; 32]> = std::collections::HashSet::new();
    for op in ops {
        if let Some(tx_key) = op.tx_key()
            && seen.insert(tx_key.txid)
        {
            keys.push(*tx_key);
        }
    }
    keys
}

fn write_replicated_redo_ops(
    engine: &Engine,
    cluster: Option<&RunningCluster>,
    redo_log: Option<&Mutex<RedoLog>>,
    ops: &[RedoOp],
) -> std::result::Result<(u64, u64), String> {
    write_replicated_redo_ops_with_tracker(
        engine,
        cluster.is_some(),
        redo_log,
        ops,
        REPLICATION_INTENT_TRACKER.get(),
    )
}

fn write_replicated_redo_ops_with_tracker(
    engine: &Engine,
    replication_applicable: bool,
    redo_log: Option<&Mutex<RedoLog>>,
    ops: &[RedoOp],
    tracker: Option<&crate::replication::durable::ReplicationIntentTracker>,
) -> std::result::Result<(u64, u64), String> {
    let range = write_redo_ops(engine, redo_log, ops)?;
    if replication_applicable && !ops.is_empty() {
        // R-036: the master-side intent is the durable bridge between
        // "redo fsynced" and "replica ACK policy satisfied". It must be
        // persisted before the local engine apply; otherwise a crash in that
        // window leaves a local-only mutation with no startup barrier.
        //
        // The intent carries THIS RPC's exact key set (derived from the redo
        // ops being written) so startup recovery replays only these keys from
        // the merged redo window — never a foreign op whose global sequence
        // happened to interleave into [first..last].
        let keys = intent_keys_from_redo_ops(ops);
        begin_replication_intent_with_tracker(range, &keys, tracker)?;
    }
    Ok(range)
}

fn commit_replication_intent_with_tracker(
    range: (u64, u64),
    tracker: Option<&crate::replication::durable::ReplicationIntentTracker>,
) -> std::result::Result<(), String> {
    if !valid_redo_range(range) {
        return Ok(());
    }
    if let Some(tracker) = tracker {
        tracker
            .commit(range.0, range.1)
            .map_err(|e| format!("replication intent commit: {e}"))?;
    }
    Ok(())
}

fn commit_replication_intent(range: (u64, u64)) -> std::result::Result<(), String> {
    commit_replication_intent_with_tracker(range, REPLICATION_INTENT_TRACKER.get())
}

fn clear_replication_intents_after_compensation(ranges: &[(u64, u64)]) {
    for &range in ranges {
        if let Err(e) = commit_replication_intent(range) {
            tracing::warn!(err = %e, "replication intent: failed to clear after compensation");
        }
    }
}

fn clear_replication_intents_after_success(ranges: &[(u64, u64)]) {
    for &range in ranges {
        if let Err(e) = commit_replication_intent(range) {
            tracing::warn!(
                err = %e,
                "replication intent: failed to clear after successful replica ACKs; startup recovery will replay"
            );
        }
    }
}

/// Send replication operations to replica nodes for the given keys.
///
/// R-D1/D-3: each replica address receives batches on its own dense
/// per-replica sequence stream (see [`send_replica_ops_to`]); the
/// master-global redo range from `write_redo_ops()` is NOT used as the
/// wire label (each address only carries a per-address op subset), but
/// its high end is recorded per ACK in the durable `AckTracker` so
/// catch-up and lag monitoring operate in real redo space.
///
/// When ACK policy enforcement is enabled (RF >= 2 with a non-best_effort
/// policy), replication failures are returned as errors so the caller can
/// fail the client request. In best-effort mode, failures are logged only
/// and the return value distinguishes `Full` (all replicas ACKed) from
/// `Degraded` (zero replicas ACKed — durability collapsed to single-node).
///
/// Returns `Ok(ReplicationOutcome)` when the ACK policy is satisfied or
/// best-effort mode suppresses the error. Returns `Err(message)` when the
/// required number of replica ACKs was not received AND best-effort is
/// disabled.
/// Build the per-address fan-out map for an outbound replication batch.
///
/// Pure function (no I/O): consults the shard table for replica targets,
/// the migration tracker for active dual-write windows, and the cluster's
/// node-address map to produce the `addr → ops` plan that
/// `replicate_all_ops` will actually send over the wire.
///
/// During an outbound migration of `shard` from this node, the dual-write
/// window contains the destination NodeIds (new master + new replicas).
/// Their addresses are added to the fan-out so writes that happen mid-
/// migration land on both the old replica set (durability) and the new
/// master / replica set (post-handoff consistency).
/// Phase E — replica fan-out plan returned by [`build_replication_targets`].
///
/// `by_addr` is the `addr → ops` map every targeted node receives.
///
/// `dual_write_only` is the subset of `by_addr` keys that exist
/// *solely* because at least one shard in the batch is migrating
/// outbound and the dual-write window names the target. Replicate
/// callers use this to enforce the per-set ACK invariant: a write
/// that touched a migrating shard cannot succeed unless at least one
/// `dual_write_only` address ACKed, regardless of the configured
/// `WriteAll` / `WriteMajority` policy. Without this, a `WriteMajority`
/// fan-out over the unioned set could ACK on the OLD replicas alone
/// and silently leave the new master with stale data, defeating the
/// dual-write durability invariant.
#[derive(Debug, Clone)]
pub(crate) struct ReplicationPlan {
    pub by_addr: HashMap<SocketAddr, Vec<ReplicaOp>>,
    pub dual_write_only: std::collections::HashSet<SocketAddr>,
    /// D-6: per-key set of *regular* replica addresses this key was sent
    /// to (the shard's replica set, excluding dual-write-only migration
    /// extras and excluding `self`). Used to evaluate the ACK policy
    /// **per key** instead of over the union of all fan-out addresses:
    /// a key is durable only when a quorum of ITS own replicas ACK.
    /// Keys appear in input order; a key whose shard has no resolvable
    /// regular replica addresses carries an empty set.
    pub key_targets: Vec<(TxKey, Vec<SocketAddr>)>,
    /// P4/R4: reverse map of every fan-out address to the NodeId it was
    /// resolved from, so the sender can select a per-TARGET ACK timeout
    /// (`migration_pressure_active_for`) instead of a sender-local one.
    pub addr_nodes: HashMap<SocketAddr, NodeId>,
}

pub(crate) fn build_replication_targets(
    cluster: &RunningCluster,
    ops_by_key: &[(TxKey, Vec<ReplicaOp>)],
) -> std::result::Result<ReplicationPlan, String> {
    let table = cluster.shard_table();
    let table_guard = table.read();
    let rf = table_guard.replication_factor();
    let expected_replicas_per_key = rf.saturating_sub(1) as usize;
    let mut by_addr: HashMap<SocketAddr, Vec<ReplicaOp>> = HashMap::new();
    let mut regular_addrs: std::collections::HashSet<SocketAddr> = std::collections::HashSet::new();
    let mut dual_write_addrs: std::collections::HashSet<SocketAddr> =
        std::collections::HashSet::new();
    let mut target_errors: Vec<String> = Vec::new();
    let self_id = cluster.self_id();
    // D-6: per-key regular replica address set, in input order.
    let mut key_targets: Vec<(TxKey, Vec<SocketAddr>)> = Vec::with_capacity(ops_by_key.len());
    // P4/R4: addr → NodeId for per-target ACK timeout selection.
    let mut addr_nodes: HashMap<SocketAddr, NodeId> = HashMap::new();

    for (key, ops) in ops_by_key {
        let shard = ShardTable::shard_for_key(key);
        let mut this_key_regular: Vec<SocketAddr> = Vec::new();
        // Use target_assignment (new topology) rather than effective_assignment
        // (old topology during handoff). Replication must go to nodes in the
        // NEW member list — the old assignment may reference dead nodes whose
        // departure triggered the topology change.
        let assignment = table_guard.target_assignment(shard);
        if rf > 1 && assignment.replicas.len() < expected_replicas_per_key {
            target_errors.push(format!(
                "shard {shard} has {} replica targets, expected {expected_replicas_per_key} for RF={rf}",
                assignment.replicas.len(),
            ));
            continue;
        }
        // Phase E: expand the replica set to include any active dual-write
        // destinations (new master + new replicas of an in-flight outbound
        // migration). This guarantees the new master observes writes that
        // happen during the migration window, so the post-handoff record
        // set is consistent with the pre-handoff durable state.
        //
        // Dual-write fan-out is best-effort with respect to address
        // resolution: a brand-new destination that hasn't yet been gossiped
        // is silently skipped rather than failing the write, because the
        // migration stream itself will deliver baseline+deltas to the
        // destination once the address is known.
        let dual_write_extras = cluster.dual_write_targets_for_shard(shard);
        for replica_id in &assignment.replicas {
            // A node never makes a NETWORK replication connection to its own
            // address. When the shard's replica set names THIS node (which
            // happens on rejoin / intent recovery, where the node holds the
            // shard as a replica and re-drives its own pending intents, and
            // on any topology where self is a replica rather than the
            // master), self's copy is satisfied LOCALLY: the redo-log fsync
            // and engine apply that produced this op already landed on this
            // node's own device before fan-out. A TCP connect to self:port
            // would fail during startup (the listener isn't up yet) and is
            // always a no-op round-trip otherwise — so self is excluded from
            // the network target set entirely. The local copy still counts
            // toward quorum: `required_replica_acks` models the local copy as
            // the implicit +1 (replication_factor = replica_targets + 1), so
            // omitting self from `this_key_regular` shrinks the OTHER-holder
            // count by one and credits this node's durable local copy without
            // requiring a self-ACK. See `classify_per_key_replication`.
            if *replica_id == self_id {
                continue;
            }
            match cluster.node_addr(replica_id) {
                Some(addr) => {
                    by_addr.entry(addr).or_default().extend(ops.clone());
                    regular_addrs.insert(addr);
                    addr_nodes.insert(addr, *replica_id);
                    if !this_key_regular.contains(&addr) {
                        this_key_regular.push(addr);
                    }
                }
                None if rf > 1 => {
                    target_errors.push(format!(
                        "shard {shard} replica node {} has no resolved address",
                        replica_id.0,
                    ));
                }
                None => {}
            }
        }
        // P5 / R7b: include the shard's CURRENT master in the holder set
        // whenever it is not this node.
        //
        // On the live client-write path the master IS this node (self), so
        // this adds nothing — the `current_master != self_id` guard below
        // skips self, exactly as the replica loop above does — and the
        // regular replica/quorum set is unchanged.
        //
        // On the compensation re-drive path the topology may have changed
        // since the failed write: the divergent replica R may have been
        // PROMOTED to master of this shard. After promotion R is no longer in
        // `assignment.replicas` (it is the master, and the demoted old master
        // now sits in `replicas`), so the replica loop above would never reach
        // R — leaving R serving a record the rest of the cluster compensated
        // away (durable silent divergence). The current holder set for a shard
        // is `{master} ∪ replicas`; resolving the compensation against that
        // full set (minus self) closes the hole. The master is added to the
        // per-key regular set so it participates in fan-out, ACK accounting
        // and quorum exactly like a replica holder.
        let current_master = assignment.master;
        if current_master != self_id {
            match cluster.node_addr(&current_master) {
                Some(addr) => {
                    if !this_key_regular.contains(&addr) {
                        by_addr.entry(addr).or_default().extend(ops.clone());
                        regular_addrs.insert(addr);
                        addr_nodes.insert(addr, current_master);
                        this_key_regular.push(addr);
                    }
                }
                None if rf > 1 => {
                    target_errors.push(format!(
                        "shard {shard} master node {} has no resolved address",
                        current_master.0,
                    ));
                }
                None => {}
            }
        }
        for extra in &dual_write_extras {
            if *extra == self_id || *extra == current_master || assignment.replicas.contains(extra)
            {
                continue;
            }
            if let Some(addr) = cluster.node_addr(extra) {
                by_addr.entry(addr).or_default().extend(ops.clone());
                dual_write_addrs.insert(addr);
                addr_nodes.insert(addr, *extra);
            }
        }
        key_targets.push((*key, this_key_regular));
    }
    drop(table_guard);

    if !target_errors.is_empty() {
        target_errors.sort();
        target_errors.dedup();
        return Err(format!(
            "replication target resolution failed: {}",
            target_errors.join("; "),
        ));
    }

    // Subtract any addr that is *also* a regular replica for some
    // other shard — a replica promoted to new master during migration
    // satisfies the regular-set policy on its own and counts on both
    // sides; we only want addrs that are exclusively dual-write.
    dual_write_addrs.retain(|a| !regular_addrs.contains(a));

    Ok(ReplicationPlan {
        by_addr,
        dual_write_only: dual_write_addrs,
        key_targets,
        addr_nodes,
    })
}

fn replicate_all_ops(
    cluster: Option<&RunningCluster>,
    ops_by_key: &[(TxKey, Vec<ReplicaOp>)],
    redo_seq_range: (u64, u64),
    intent_ranges: &[(u64, u64)],
) -> std::result::Result<ReplicationOutcome, String> {
    replicate_all_ops_with_barrier(cluster, ops_by_key, redo_seq_range, intent_ranges, None)
}

/// Replication fan-out with C-1 barrier handoff.
///
/// `barrier` is the exclusive visibility barrier held by the mutation
/// handler. The local engine apply and redo-log fsync are already
/// complete by the time this is called (see the WAL-first contract in the
/// mutation handlers); this function therefore **releases the barrier
/// before the synchronous replication round-trip** so the network RTT
/// does not stall concurrent client reads or the peer's
/// `OP_REPLICA_BATCH` apply (which needs its own exclusive barrier).
/// See [`MutationBarrier`] for the visibility/crash-safety argument.
///
/// `barrier` is `None` for recovery / intent re-replication (no client is
/// blocked) and for unit tests that drive the fan-out directly.
///
/// R-D1/D-3 (preserved): each replica address still receives batches on
/// its own dense per-replica sequence stream via [`send_replica_ops_to`].
/// D-6 (added): the ACK policy is evaluated **per key** against the
/// replica set each key was actually sent to, not over the union of all
/// fan-out addresses.
fn replicate_all_ops_with_barrier(
    cluster: Option<&RunningCluster>,
    ops_by_key: &[(TxKey, Vec<ReplicaOp>)],
    redo_seq_range: (u64, u64),
    intent_ranges: &[(u64, u64)],
    mut barrier: Option<MutationBarrier<'_>>,
) -> std::result::Result<ReplicationOutcome, String> {
    let cluster = match cluster {
        Some(c) => c,
        None => return Ok(ReplicationOutcome::NotApplicable),
    };
    if ops_by_key.is_empty() {
        clear_replication_intents_after_success(intent_ranges);
        return Ok(ReplicationOutcome::NotApplicable);
    }
    // Group all ops by target replica address — including any dual-write
    // expansion for shards currently migrating outbound (Phase E).
    // (P7/R5: the fan-out admission permit is acquired AFTER the plan is
    // built — admission is per target address — and after the barrier is
    // released, so a bounded permit wait never stalls concurrent reads.)
    let plan = build_replication_targets(cluster, ops_by_key)?;
    let ReplicationPlan {
        by_addr,
        dual_write_only,
        key_targets,
        addr_nodes,
    } = plan;
    let rf = cluster.shard_table().read().replication_factor();

    if by_addr.is_empty() {
        // No replicas configured or no replica addresses known.
        if rf > 1 {
            return Err(format!(
                "replication target resolution failed: no replica targets for RF={rf}",
            ));
        }
        clear_replication_intents_after_success(intent_ranges);
        return Ok(ReplicationOutcome::NotApplicable);
    }

    // C-1: the local apply + redo durability are complete and every
    // replica target has been resolved; release the engine-wide
    // exclusive visibility barrier now so the synchronous replication
    // round-trip below does not hold it. Reads resume immediately (they
    // observe the fully-applied, locally-committed batch — never a torn
    // one) and a peer master↔master apply can acquire its own barrier
    // instead of deadlocking until the ack timeout. If replication later
    // fails, compensation is a separate durable mutation.
    if let Some(b) = barrier.as_mut() {
        b.release();
    }

    // Send to all replica targets in parallel using the shared replication
    // runtime. Each send runs on a blocking task (reusing pooled threads)
    // instead of spawning a new OS thread per replication call.
    let source_node_id = cluster.self_id().0;
    // P4/R4: the ACK timeout is selected PER TARGET, not sender-locally.
    // `migration_pressure_active_for` escalates when local migration
    // pressure is active OR the target replica itself is a mover in the
    // current topology transition (it may be drowning in inbound
    // migration batches even though this sender migrates nothing).
    let base_timeout = cluster.replication_timeout();
    let migration_timeout_floor = cluster.replication_timeout_during_migration();
    let ack_timeouts: HashMap<SocketAddr, Duration> = by_addr
        .keys()
        .map(|addr| {
            let pressure = match addr_nodes.get(addr) {
                Some(node) => cluster.migration_pressure_active_for(*node),
                // Address with no resolved NodeId (defensive — every
                // fan-out addr is inserted with its node): fall back to
                // the sender-local check.
                None => cluster.migration_pressure_active(),
            };
            (
                *addr,
                replication_ack_timeout_for(base_timeout, pressure, migration_timeout_floor),
            )
        })
        .collect();

    // P7/R5: bounded, per-address fan-out admission. A wedged replica can
    // hold at most its own per-address slot budget; fan-outs to healthy
    // addresses keep flowing on the remaining global capacity. The wait is
    // bounded by the LONGEST per-target ack timeout this fan-out would use
    // plus a small margin — a permit holder frees its slots within its own
    // ack timeout, so waiting longer than the most-generous target's timeout
    // cannot succeed and the client must see a fast ERR_REPLICATION_FAILED
    // instead of an unbounded stall. Using the max (not min) avoids failing
    // admission before a legitimately-escalated (migration-pressured) target
    // could still ack.
    let target_addrs: Vec<SocketAddr> = by_addr.keys().copied().collect();
    let max_ack_timeout = ack_timeouts.values().copied().max().unwrap_or(base_timeout);
    let known_replica_addrs = cluster.alive_node_count().saturating_sub(1);
    let _fanout_permit = acquire_replication_fanout_permits(
        &target_addrs,
        per_addr_fanout_cap(known_replica_addrs),
        max_ack_timeout + FANOUT_ADMISSION_MARGIN,
    )
    .map_err(|e| e.to_string())?;
    // Phase B3: stamp every outbound batch with the live coordinator
    // epoch so the receiver's gate can reject stale-cluster writes.
    let cluster_key = cluster.local_cluster_key();
    let auth_secret = cluster.cluster_secret().map(|s| s.to_vec());
    // Preserve the (addr, result) association so we can apply per-set
    // ACK accounting (Phase E) after the parallel fan-out completes.
    let results: Vec<(SocketAddr, std::result::Result<(), String>)> =
        REPL_RUNTIME.block_on(async {
            let mut handles = Vec::with_capacity(by_addr.len());
            for (addr, ops) in by_addr {
                let auth_secret = auth_secret.clone();
                let ack_timeout = ack_timeouts.get(&addr).copied().unwrap_or(base_timeout);
                handles.push(tokio::task::spawn_blocking(move || {
                    if ops.is_empty() {
                        return (addr, Ok(()));
                    }
                    // R-D1/D-3: per-replica dense stream labels are
                    // assigned inside `send_replica_ops_to` under the
                    // per-address slot mutex — NOT the master-global
                    // redo range, which covers ops this address never
                    // receives. The redo range's high end is recorded
                    // against the ACK for catch-up/lag bookkeeping.
                    let res = send_replica_ops_to(
                        addr,
                        &ops,
                        ack_timeout,
                        auth_secret.as_deref(),
                        cluster_key,
                        source_node_id,
                        redo_seq_range.1,
                    );
                    (addr, res)
                }));
            }
            let mut results = Vec::with_capacity(handles.len());
            for handle in handles {
                results.push(handle.await.unwrap_or_else(|_| {
                    (
                        SocketAddr::from(([0u8, 0, 0, 0], 0)),
                        Err("task panicked".to_string()),
                    )
                }));
            }
            results
        });

    let mut last_error: Option<String> = None;
    let mut dual_write_acks: usize = 0;
    // D-6: the set of addresses that ACKed, used for per-key quorum.
    let mut acked: std::collections::HashSet<SocketAddr> = std::collections::HashSet::new();
    for (addr, result) in &results {
        match result {
            Ok(()) => {
                acked.insert(*addr);
                if dual_write_only.contains(addr) {
                    dual_write_acks += 1;
                }
            }
            Err(e) => {
                tracing::warn!(err = %e, "replication to replica failed");
                last_error = Some(e.clone());
            }
        }
    }
    let total_targets = results.len();
    let dual_write_total = dual_write_only.len();
    let ack_policy = cluster.ack_policy();
    let best_effort = cluster.is_replication_best_effort();

    // Phase E per-set ACK invariant: when at least one shard in this
    // batch is migrating outbound, require ≥1 ACK from the dual-write
    // set so the new master observes writes during the migration
    // window. Otherwise a `WriteMajority` policy could ACK on the OLD
    // replicas alone, leaving the post-handoff record set divergent.
    if dual_write_total > 0 && dual_write_acks == 0 {
        if best_effort {
            tracing::warn!(
                dual_write_total,
                "replication: dual-write set produced 0 ACKs (best_effort — write proceeds, new master may need full resync)",
            );
        } else {
            return Err(format!(
                "replication: dual-write set produced 0 ACKs of {dual_write_total} new-master target(s); \
                 migration durability requires at least one new-master ACK: {}",
                last_error.unwrap_or_default()
            ));
        }
    }

    // D-6: evaluate the ACK policy PER KEY against the replica set each
    // key was actually sent to — not over the union of all fan-out
    // addresses. A multi-shard client batch fans out disjoint per-key op
    // subsets to different replica sets; the union count would let a key
    // be reported durable while a quorum of ITS OWN replicas never ACKed
    // (e.g. RF=2 WriteMajority with key A's replica up and key B's
    // replica down: union ack_count=1 satisfies the union "majority", but
    // key B has zero replica copies). Per-key accounting fails the batch
    // when ANY key misses its own quorum.
    let mut any_degraded = false;
    let mut first_failure: Option<(TxKey, KeyReplicationVerdict)> = None;
    for (key, targets) in &key_targets {
        let verdict = classify_per_key_replication(targets, &acked, ack_policy, best_effort);
        if verdict.is_failure() && first_failure.is_none() {
            first_failure = Some((*key, verdict));
        }
        if verdict.is_degraded() {
            any_degraded = true;
        }
    }

    if let Some((
        key,
        KeyReplicationVerdict::Failed {
            required,
            acked: key_acks,
            targets,
        },
    )) = first_failure
    {
        // At least one key did not reach a quorum of its own replicas and
        // best-effort is disabled: the whole batch fails so the caller
        // compensates and returns ERR_REPLICATION_FAILED. The key is named
        // in the error for triage but not surfaced to the client.
        return Err(format!(
            "replication: key {:02x}{:02x}{:02x}{:02x}.. reached {key_acks}/{targets} of its own replicas, need {required}: {}",
            key.txid[0],
            key.txid[1],
            key.txid[2],
            key.txid[3],
            last_error.unwrap_or_default()
        ));
    }

    if any_degraded {
        // best_effort: some key(s) missed their own quorum but the write
        // proceeds with degraded durability rather than failing. Escalate
        // to `Degraded` so the caller responds STATUS_DEGRADED_DURABILITY.
        if let Some(metrics) = DISPATCH_METRICS.get() {
            metrics.repl_degraded_durability.inc();
        }
        tracing::warn!(
            best_effort,
            err = %last_error.clone().unwrap_or_default(),
            "replication: DEGRADED DURABILITY — a key missed its replica quorum (best_effort), client will receive STATUS_DEGRADED_DURABILITY",
        );
        clear_replication_intents_after_success(intent_ranges);
        return Ok(ReplicationOutcome::Degraded);
    }

    // Every key met its own quorum. If some replica nonetheless failed (a
    // key's set was larger than its quorum and a non-quorum-critical
    // replica did not ACK), tick the degraded-acks counter but still
    // report Full so the client sees STATUS_OK.
    if acked.len() < total_targets {
        if let Some(metrics) = DISPATCH_METRICS.get() {
            metrics.replication_degraded_acks.inc();
        }
        tracing::warn!(
            acked = acked.len(),
            total_targets,
            best_effort,
            ack_policy = ?ack_policy,
            "replication: per-key quorum met with some replica ACKs missing",
        );
    }
    clear_replication_intents_after_success(intent_ranges);
    Ok(ReplicationOutcome::Full)
}

fn replication_ack_timeout_for(
    base: Duration,
    migration_pressure: bool,
    migration_timeout_floor: Duration,
) -> Duration {
    if migration_pressure {
        base.max(migration_timeout_floor)
    } else {
        base
    }
}

/// Resolve durable pending replication intents before the server starts
/// serving client traffic.
///
/// Any range left in the intent tracker means the previous process applied a
/// mutation locally but crashed before it could prove the replica ACK policy
/// and clear the marker. We reconstruct replica ops from the redo log and
/// replicate them to the current target holders. If any range cannot be
/// resolved, startup must fail closed.
pub fn recover_pending_replication_intents(
    cluster: &RunningCluster,
    redo_log: Option<&Mutex<RedoLog>>,
    engine: &Engine,
) -> std::result::Result<(), String> {
    let tracker = match REPLICATION_INTENT_TRACKER.get() {
        Some(t) => t,
        None => return Ok(()),
    };
    recover_pending_replication_intents_from_tracker(tracker, redo_log, engine, |ops, range| {
        // The intent range is already present in the durable tracker; this
        // recovery path commits it explicitly after successful fan-out.
        replicate_all_ops(Some(cluster), ops, range, &[]).map(|_| ())
    })
}

fn recover_pending_replication_intents_from_tracker<F>(
    tracker: &crate::replication::durable::ReplicationIntentTracker,
    redo_log: Option<&Mutex<RedoLog>>,
    engine: &Engine,
    mut replicate: F,
) -> std::result::Result<(), String>
where
    F: FnMut(&[(TxKey, Vec<ReplicaOp>)], (u64, u64)) -> std::result::Result<(), String>,
{
    let pending = tracker.pending_with_keys();
    if pending.is_empty() {
        return Ok(());
    }
    let redo_log = redo_log.ok_or_else(|| {
        format!(
            "replication intent recovery requires redo log; {} pending range(s)",
            pending.len(),
        )
    })?;

    for (range, intent_keys) in pending {
        // Membership set for this RPC's OWN keys. Recovery replays exactly
        // these — never a foreign op whose global sequence interleaved into
        // [first..last] under per-store redo (the latent wrong-apply vector).
        let owned_keys: std::collections::HashSet<[u8; 32]> =
            intent_keys.iter().map(|k| k.txid).collect();
        // The global sequence counter is shared across every store log, so any
        // log's `current_sequence` reports the global high-water.
        let current_sequence = redo_log.lock().current_sequence();
        // Mirror `write_redo_ops`' routing: when per-store logs are attached, a
        // pending intent's [first..last] range may span several store logs, so
        // read the merged, sequence-ordered view (and the global earliest) via
        // the engine. Otherwise (single-store / tests with a standalone handle)
        // read directly from the passed redo handle, exactly as before.
        // F-G5-008: redo I/O errors carry kernel diagnostic strings and
        // (depending on the storage backend) file paths. Log detail for
        // operator triage; return a sanitized message that does not leak
        // deployment topology to clients.
        let (entries, earliest_sequence) = if engine.has_per_store_redo() {
            let entries = engine
                .read_redo_from_sequence_merged(range.first_sequence)
                .map_err(|e| {
                    tracing::error!(err = %e, "read redo for pending replication intent failed");
                    "read redo for pending replication intent failed".to_string()
                })?;
            let earliest = engine.earliest_redo_sequence_merged().map_err(|e| {
                tracing::error!(err = %e, "read redo floor for pending replication intent failed");
                "read redo floor for pending replication intent failed".to_string()
            })?;
            (entries, earliest)
        } else {
            let log = redo_log.lock();
            let entries = log.read_from_sequence(range.first_sequence).map_err(|e| {
                tracing::error!(err = %e, "read redo for pending replication intent failed");
                "read redo for pending replication intent failed".to_string()
            })?;
            let earliest = log.earliest_sequence().map_err(|e| {
                tracing::error!(err = %e, "read redo floor for pending replication intent failed");
                "read redo floor for pending replication intent failed".to_string()
            })?;
            (entries, earliest)
        };
        let entries: Vec<_> = entries
            .into_iter()
            .filter(|entry| {
                entry.sequence >= range.first_sequence && entry.sequence <= range.last_sequence
            })
            .collect();

        // Reclamation is the ONLY satisfiability gate. Under per-store redo the
        // global sequence counter is shared across logs, so this RPC's
        // [first..last] window legitimately contains FOREIGN ops (other
        // already-committed RPCs whose sequences interleaved) AND may be missing
        // sequences this RPC never produced. The old boundary check (first
        // entry == range.first && last == range.last) is therefore WRONG once we
        // filter by key: a foreign op can occupy the boundary sequence, and this
        // RPC's own first/last keyed op need not sit exactly on the range edge.
        //
        // Genuine reclamation = the redo floor (earliest available sequence) has
        // advanced ABOVE range.first_sequence, i.e. this range was compacted
        // away. That — and only that — means the owned ops are gone and we must
        // fall back to a full replica resync/catch-up. "Some sequences in the
        // range are absent because they were foreign / never produced by this
        // RPC" is NOT reclamation.
        let range_reclaimed = match earliest_sequence {
            Some(earliest) => earliest > range.first_sequence,
            // No entries remain at/after range.first at all: only treat as
            // reclaimed if the log has genuinely advanced past the whole range
            // (compacted/wrapped). Otherwise the range is simply empty of our
            // keys and is satisfied by committing the no-op intent below.
            None => entries.is_empty() && current_sequence > range.last_sequence,
        };
        if range_reclaimed {
            tracing::warn!(
                first_sequence = range.first_sequence,
                last_sequence = range.last_sequence,
                ?earliest_sequence,
                current_sequence,
                "pending replication intent refers to reclaimed redo range; clearing marker and requiring replica full resync/catch-up",
            );
            tracker
                .commit(range.first_sequence, range.last_sequence)
                .map_err(|e| format!("replication intent commit: {e}"))?;
            continue;
        }

        // The range is satisfiable (not reclaimed). Replay EXACTLY this RPC's
        // keys: reconstruct only entries whose key is in the intent's own key
        // set. Foreign ops sharing the window are skipped — never re-shipped —
        // so a non-idempotent `ReplicaOp` can never be wrong-applied to a
        // replica from a foreign RPC's interleaved sequence.
        let mut ops_by_key = Vec::new();
        for entry in &entries {
            let Some(tx_key) = entry.op.tx_key().copied() else {
                continue;
            };
            if !owned_keys.contains(&tx_key.txid) {
                // Foreign op that interleaved into this range under the shared
                // sequence counter — belongs to a different (already-committed)
                // RPC. Never re-ship it from this intent.
                continue;
            }
            let shard = ShardTable::shard_for_key(&tx_key);
            if let Some(op) =
                crate::cluster::coordinator::redo_entry_to_replica_op(entry, shard, engine)
            {
                debug_assert_eq!(
                    op.tx_key(),
                    tx_key,
                    "reconstructed replica op key must match its redo entry key",
                );
                debug_assert!(
                    entry.sequence >= range.first_sequence && entry.sequence <= range.last_sequence,
                    "recovery must only ship ops whose redo entry falls in the intent window",
                );
                ops_by_key.push((tx_key, vec![op]));
            }
        }

        if ops_by_key.is_empty() {
            tracker
                .commit(range.first_sequence, range.last_sequence)
                .map_err(|e| format!("replication intent commit: {e}"))?;
            continue;
        }

        replicate(&ops_by_key, (range.first_sequence, range.last_sequence))?;
        tracker
            .commit(range.first_sequence, range.last_sequence)
            .map_err(|e| format!("replication intent commit: {e}"))?;
    }

    Ok(())
}

/// Classification of an *aggregate* ACK tally against the configured ACK
/// policy.
///
/// D-6 superseded this on the production path: `replicate_all_ops`
/// previously counted ACKs once over the union of all fan-out addresses,
/// which let a key be reported durable while a quorum of *its own*
/// replicas never ACKed. Production now evaluates quorum per key via
/// [`classify_per_key_replication`]. This aggregate classifier is
/// retained only as a `#[cfg(test)]` reference that pins the
/// [`crate::replication::manager::required_replica_acks`] policy math
/// (the same math the per-key path consumes) — there is intentionally no
/// second production quorum implementation (Rule 6).
#[cfg(test)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum ReplicationClassification {
    /// Every replica target ACKed successfully.
    FullAck,
    /// Some (but not all) replicas ACKed. In best-effort mode with at least
    /// one ACK, the write is still multi-node durable so we respond OK.
    /// In the non-best-effort case this only occurs when the configured
    /// policy explicitly permits it (e.g. `WriteMajority` on RF=3 with
    /// 2/3 ACKs).
    PartialAck,
    /// Best-effort mode AND zero replicas ACKed AND at least one target
    /// existed. This is the "silently single-node" case that requires
    /// STATUS_DEGRADED_DURABILITY.
    ZeroAckBestEffort,
    /// The ACK count is below the configured policy threshold and
    /// best-effort is disabled. The caller must fail the client request
    /// with ERR_REPLICATION_FAILED.
    PolicyViolation {
        /// Number of replica ACKs the configured policy required.
        required: usize,
    },
}

/// Pure, side-effect-free classification of replication ACK outcome.
///
/// Inputs:
/// - `ack_count`: number of replica targets that ACKed successfully.
/// - `total_targets`: number of replica targets the batch was sent to.
/// - `ack_policy`: `Some(policy)` to enforce, `None` for best-effort (no
///   minimum enforced).
/// - `best_effort`: whether `replication_degraded_mode = "best_effort"`
///   is active — determines whether a policy violation is suppressed and
///   whether zero-ACK triggers the degraded-durability escalation.
///
/// See [`ReplicationClassification`] for semantics.
///
/// Superseded on the production path by [`classify_per_key_replication`]
/// (D-6); retained as a `#[cfg(test)]` reference for the policy math.
#[cfg(test)]
pub(crate) fn classify_replication_outcome(
    ack_count: usize,
    total_targets: usize,
    ack_policy: Option<crate::replication::manager::AckPolicy>,
    best_effort: bool,
) -> ReplicationClassification {
    let required = match ack_policy {
        Some(policy) => crate::replication::manager::required_replica_acks(total_targets, policy),
        None => 0, // best-effort: no minimum
    };

    if ack_count < required && !best_effort {
        return ReplicationClassification::PolicyViolation { required };
    }

    if best_effort && ack_count == 0 && total_targets > 0 {
        return ReplicationClassification::ZeroAckBestEffort;
    }

    if ack_count < total_targets {
        return ReplicationClassification::PartialAck;
    }

    ReplicationClassification::FullAck
}

/// D-6: per-key replication verdict.
///
/// A key is *durable* when a quorum of the replicas **it was actually
/// sent to** ACKed; otherwise it failed (or, under best-effort, is
/// degraded). This is the per-key analogue of the aggregate
/// `ReplicationClassification` — see [`classify_per_key_replication`].
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum KeyReplicationVerdict {
    /// A quorum of this key's own replica set ACKed (or the key had no
    /// regular replica targets — single-node / RF=1 — so durability is
    /// trivially satisfied by the local copy).
    Durable,
    /// This key did not reach a quorum of its own replica set, and
    /// best-effort is disabled: the batch must surface
    /// `ERR_REPLICATION_FAILED`.
    Failed {
        /// Replica ACKs this key required from its own set.
        required: usize,
        /// Replica ACKs this key actually received from its own set.
        acked: usize,
        /// Size of this key's regular replica target set.
        targets: usize,
    },
    /// This key did not reach a quorum, but best-effort is enabled: the
    /// write proceeds with degraded durability rather than failing.
    DegradedBestEffort {
        /// ACKs received from this key's own set.
        acked: usize,
        /// Size of this key's regular replica target set.
        targets: usize,
    },
}

impl KeyReplicationVerdict {
    /// True when this key failed its own quorum with best-effort disabled
    /// — the batch must return `ERR_REPLICATION_FAILED`.
    pub(crate) fn is_failure(&self) -> bool {
        matches!(self, KeyReplicationVerdict::Failed { .. })
    }

    /// True when this key did not reach full durability under best-effort
    /// (it proceeded best-effort with a missing copy).
    pub(crate) fn is_degraded(&self) -> bool {
        matches!(self, KeyReplicationVerdict::DegradedBestEffort { .. })
    }
}

/// D-6: evaluate the ACK policy **per key** against the replica set the
/// key was actually sent to, instead of over the union of every fan-out
/// address.
///
/// Inputs:
/// - `targets`: this key's regular replica addresses (from
///   [`ReplicationPlan::key_targets`]). Empty means RF=1 / single-node —
///   the local copy alone satisfies durability.
/// - `acked`: the set of addresses that ACKed in this fan-out (any
///   address in the whole batch; only this key's targets are consulted).
/// - `ack_policy`: `Some(policy)` to enforce, `None` for best-effort with
///   no minimum.
/// - `best_effort`: whether a per-key quorum miss is downgraded to
///   degraded-durability instead of a hard failure.
///
/// The previous implementation counted ACKs once over `by_addr.len()` —
/// the *union* of all addresses, including dual-write extras and the
/// disjoint replica sets of unrelated shards — so a key could be reported
/// `STATUS_OK` while zero of its own replicas held a copy. This function
/// closes that hole.
pub(crate) fn classify_per_key_replication(
    targets: &[SocketAddr],
    acked: &std::collections::HashSet<SocketAddr>,
    ack_policy: Option<crate::replication::manager::AckPolicy>,
    best_effort: bool,
) -> KeyReplicationVerdict {
    // A key with no regular replica targets (RF=1 / single-node, or a key
    // that only ever fanned out to dual-write migration extras) is durable
    // on the local copy alone — there is no replica quorum to meet.
    // Dual-write durability is enforced separately by the per-set
    // invariant in `replicate_all_ops_with_barrier`.
    if targets.is_empty() {
        return KeyReplicationVerdict::Durable;
    }

    let target_count = targets.len();
    let key_acks = targets.iter().filter(|a| acked.contains(*a)).count();

    // best_effort mode (RF=1-only in valid configs) imposes no per-key
    // minimum: the write proceeds regardless. But when this key's own
    // replica set produced ZERO ACKs while it had targets, durability
    // silently collapsed to the local copy — surface that as
    // `DegradedBestEffort` so the caller emits STATUS_DEGRADED_DURABILITY
    // (mirrors the old aggregate `ZeroAckBestEffort`).
    if best_effort {
        if key_acks == 0 {
            return KeyReplicationVerdict::DegradedBestEffort {
                acked: key_acks,
                targets: target_count,
            };
        }
        return KeyReplicationVerdict::Durable;
    }

    let required = match ack_policy {
        Some(policy) => crate::replication::manager::required_replica_acks(target_count, policy),
        None => 0, // no policy configured (RF<=1): no minimum
    };

    if key_acks >= required {
        KeyReplicationVerdict::Durable
    } else {
        KeyReplicationVerdict::Failed {
            required,
            acked: key_acks,
            targets: target_count,
        }
    }
}

/// Gap #8 (TERANODE_PRODUCTION_READINESS_GAPS.md): pre-apply state
/// captured by a dispatch handler so a failed-replication rollback can
/// restore the record exactly.
///
/// Each variant pairs 1:1 with a `ReplicaOp` whose original compensation
/// path used defaults / zeros / unconditional restores:
///
/// * `UnsetMined` — block_height + subtree_idx of the entry being cleared.
/// * `Reassign` — utxo_hash of the slot before the reassign.
/// * `Prune` — status byte of the slot before the prune.
/// * `SetLocked` — locked flag + DAH before SetLocked cleared pruning state.
///
/// `None` indicates "no before-image needed" (the op's compensation is
/// fully determined by the on-device state at rollback time, e.g.
/// spend, freeze, etc.).
#[derive(Debug, Clone, Copy)]
pub(crate) enum BeforeImage {
    /// No before-image needed — compensation reads current device state.
    None,
    /// Captured pre-apply block-entry fields for an unset-mined op.
    UnsetMined { block_height: u32, subtree_idx: u32 },
    /// Captured pre-apply utxo_hash for a reassign op.
    Reassign { prior_utxo_hash: [u8; 32] },
    /// Captured pre-apply locked flag and DAH for a set-locked op.
    SetLocked {
        prior_locked: bool,
        prior_delete_at_height: u32,
    },
    /// Captured pre-apply status byte for a prune op.
    ///
    /// `PruneSlot` `ReplicaOp`s are currently only generated by the
    /// migration delta path, which does not call
    /// `compensate_replication_failure`. The variant exists so a future
    /// dispatch handler that adds a prune client API can capture the
    /// pre-apply status byte without re-plumbing the rollback API.
    /// Tests in `tests/replication_rollback.rs` construct this variant
    /// directly to exercise the compensation + recovery path.
    #[allow(dead_code)]
    Prune { prior_status: u8 },
}

/// Gap #8: build a parallel `before_images` vec of `BeforeImage::None`
/// for handlers that don't capture pre-apply state (spend, freeze,
/// set-conflicting, etc.). The shape mirrors `repl_ops` exactly so
/// `compensate_replication_failure` can index `before_images[i].1[j]`
/// in lockstep with `repl_ops[i].1[j]`.
fn no_before_images(repl_ops: &[(TxKey, Vec<ReplicaOp>)]) -> Vec<(TxKey, Vec<BeforeImage>)> {
    repl_ops
        .iter()
        .map(|(k, ops)| (*k, vec![BeforeImage::None; ops.len()]))
        .collect()
}

fn before_images_match_repl_ops(
    repl_ops: &[(TxKey, Vec<ReplicaOp>)],
    before_images: &[(TxKey, Vec<BeforeImage>)],
) -> bool {
    repl_ops.len() == before_images.len()
        && repl_ops
            .iter()
            .zip(before_images)
            .all(|((op_key, ops), (before_key, images))| {
                op_key == before_key && ops.len() == images.len()
            })
}

fn push_repl_with_before_image(
    repl_ops: &mut Vec<(TxKey, Vec<ReplicaOp>)>,
    before_images: &mut Vec<(TxKey, Vec<BeforeImage>)>,
    key: TxKey,
    op: ReplicaOp,
    before: BeforeImage,
) {
    repl_ops.push((key, vec![op]));
    before_images.push((key, vec![before]));
}

/// Compensate for a replication failure by reversing locally-applied mutations.
///
/// When `replicate_all_ops` fails, the local engine has already applied the
/// ops and the redo log has the forward entries. This function applies the
/// inverse operation for each op in `repl_ops`, then appends compensating
/// redo entries so crash recovery also reverses the mutations.
///
/// This ensures the local node doesn't diverge from replicas: the client
/// receives an error, and the local state is rolled back as if the write
/// never happened.
///
/// Returns `Ok(Some((first, last)))` with the redo-sequence range of the
/// compensating entries when any were written, or `Ok(None)` when there
/// were no ops to reverse. The caller (`compensate_replication_failure_or_error`)
/// uses that range to register a durable compensation intent and replicate
/// the compensating ops to the replicas that may have applied the original
/// mutation (D-4) — the rolled-back state is pushed to divergent replicas
/// rather than left local-only.
///
/// # DC-1: slot-restore write failures are surfaced, not swallowed
///
/// The reassign / prune rollback paths restore a slot via
/// `crate::io::write_utxo_slot`. If that device write fails it is recorded
/// and returned as `Err` *after* the compensating redo entries are made
/// durable. A failed in-memory/device restore therefore leaves the system
/// in a state the next recovery replay fixes (the redo log is the source of
/// truth) while the caller fails the op with `ERR_INTERNAL` instead of
/// reporting a clean rollback.
///
/// # Gap #8: bit-exact rollback via captured before-images
///
/// `before_images[i].1[j]` carries the pre-apply state captured at
/// dispatch entry for `repl_ops[i].1[j]`. When the variant is non-`None`
/// the compensation path uses the captured value to restore the original
/// record state exactly — no zeros, no defaults, no unconditional
/// restores. The compensation also appends a `Compensate*` redo entry
/// with the same before-image so a crash mid-rollback can re-run the
/// restore deterministically (gap #8 part 3).
///
/// `before_images.len()` MUST equal `repl_ops.len()` and each inner Vec
/// MUST align with the corresponding `repl_ops` inner Vec. Callers that
/// have no before-image to capture pass `BeforeImage::None`.
///
/// # Crash safety: the double-fault gap
///
/// If the master crashes between the original redo write (durable) and
/// this compensation function completing, crash recovery will replay the
/// original mutation without compensation. The write becomes durable on
/// the master even though no replica received it and the client got no
/// response.
///
/// This is acceptable because:
/// 1. The client received no response (connection dropped), so it
///    doesn't know whether the write succeeded — it must handle
///    ambiguity regardless.
/// 2. Replica catch-up streaming will propagate the write to replicas
///    once they reconnect, restoring the replication invariant.
/// 3. Actual data loss requires a second fault: the master's disk
///    failing before catch-up completes (double-fault scenario).
///
/// The alternative (writing a "pending replication" marker in the redo
/// entry and checking it on recovery) would add per-write overhead to
/// the hot path for a scenario that requires two independent failures.
fn compensate_replication_failure(
    engine: &Engine,
    repl_ops: &[(TxKey, Vec<ReplicaOp>)],
    before_images: &[(TxKey, Vec<BeforeImage>)],
    redo_log: Option<&Mutex<RedoLog>>,
) -> std::result::Result<Option<(u64, u64)>, String> {
    let mut comp_redo: Vec<RedoOp> = Vec::new();
    // DC-1: a slot-restore `write_utxo_slot` that fails must NOT be
    // swallowed. We record the first such failure and surface it once the
    // compensating redo entries are durable, so the redo log still drives a
    // correct replay on restart while the caller learns the in-memory/device
    // restore did not complete cleanly (the op must not report a clean
    // rollback). Mirrors the R-004/R-035 "propagate the write error rather
    // than log-and-continue" discipline already applied to engine slot
    // writes and receiver metadata writes.
    let mut restore_write_err: Option<String> = None;

    let before_shape_ok = before_images_match_repl_ops(repl_ops, before_images);
    if !before_shape_ok {
        tracing::error!(
            repl_groups = repl_ops.len(),
            before_groups = before_images.len(),
            "replication compensation aborted: before-image shape mismatch"
        );
        return Err("before-image shape mismatch".to_string());
    }

    // Helper: look up the before-image aligned with `repl_ops[i].1[j]`. Shape
    // was validated above, so a missing entry is impossible unless this function
    // is edited incorrectly.
    let lookup_before = |i: usize, j: usize| -> BeforeImage { before_images[i].1[j] };

    for (i, (key, ops)) in repl_ops.iter().enumerate() {
        for (j, op) in ops.iter().enumerate() {
            match op {
                ReplicaOp::Spend {
                    offset,
                    current_block_height,
                    block_height_retention,
                    ..
                } => {
                    if let Ok(slot) = engine.read_slot(key, *offset) {
                        let req = crate::ops::unspend::UnspendRequest {
                            tx_key: *key,
                            offset: *offset,
                            utxo_hash: slot.hash,
                            spending_data: slot.spending_data,
                            current_block_height: *current_block_height,
                            block_height_retention: *block_height_retention,
                        };
                        let _ = engine.unspend(&req);
                        comp_redo.push(RedoOp::Unspend {
                            tx_key: *key,
                            offset: *offset,
                            spending_data: Some(slot.spending_data),
                            new_spent_count: 0,
                        });
                    }
                }
                ReplicaOp::Unspend {
                    offset,
                    spending_data,
                    current_block_height,
                    block_height_retention,
                    ..
                } => {
                    // Reverse unspend → re-spend the slot with its exact
                    // prior spending_data and original DAH evaluation context.
                    if let Ok(slot) = engine.read_slot(key, *offset) {
                        let req = crate::ops::spend::SpendMultiRequest {
                            tx_key: *key,
                            spends: vec![crate::ops::spend::SpendItem {
                                offset: *offset,
                                utxo_hash: slot.hash,
                                spending_data: *spending_data,
                                idx: 0,
                            }],
                            ignore_conflicting: true,
                            ignore_locked: true,
                            current_block_height: *current_block_height,
                            block_height_retention: *block_height_retention,
                        };
                        if let Ok(v) = engine.validate_spend_multi(&req) {
                            let _ = v.apply(engine);
                        }
                        comp_redo.push(RedoOp::Spend {
                            tx_key: *key,
                            offset: *offset,
                            spending_data: *spending_data,
                            new_spent_count: 0,
                        });
                    }
                }
                ReplicaOp::Freeze { offset, .. } => {
                    if let Ok(slot) = engine.read_slot(key, *offset) {
                        let req = crate::ops::remaining::UnfreezeRequest {
                            tx_key: *key,
                            offset: *offset,
                            utxo_hash: slot.hash,
                        };
                        let _ = engine.unfreeze(&req);
                        comp_redo.push(RedoOp::UnfreezeV2 {
                            tx_key: *key,
                            offset: *offset,
                            utxo_hash: slot.hash,
                        });
                    }
                }
                ReplicaOp::Unfreeze { offset, .. } => {
                    if let Ok(slot) = engine.read_slot(key, *offset) {
                        let req = crate::ops::remaining::FreezeRequest {
                            tx_key: *key,
                            offset: *offset,
                            utxo_hash: slot.hash,
                        };
                        let _ = engine.freeze(&req);
                        comp_redo.push(RedoOp::FreezeV2 {
                            tx_key: *key,
                            offset: *offset,
                            utxo_hash: slot.hash,
                        });
                    }
                }
                ReplicaOp::SetMined {
                    block_id,
                    block_height,
                    subtree_idx,
                    current_block_height,
                    block_height_retention,
                    ..
                } => {
                    let req = crate::ops::set_mined::SetMinedRequest {
                        tx_key: *key,
                        block_id: *block_id,
                        block_height: *block_height,
                        subtree_idx: *subtree_idx,
                        on_longest_chain: false,
                        unset_mined: true,
                        current_block_height: *current_block_height,
                        block_height_retention: *block_height_retention,
                    };
                    let _ = engine.set_mined(&req);
                    comp_redo.push(RedoOp::SetMined {
                        tx_key: *key,
                        block_id: *block_id,
                        block_height: *block_height,
                        subtree_idx: *subtree_idx,
                        unset: true,
                    });
                }
                ReplicaOp::UnsetMined {
                    block_id,
                    current_block_height,
                    block_height_retention,
                    ..
                } => {
                    // Gap #8: reverse unset → re-set the block entry using
                    // the captured pre-apply block_height + subtree_idx.
                    // When no before-image is available we fall back to
                    // best-effort zeros AND skip emitting a Compensate*
                    // redo entry — a crash mid-rollback would replay zeros
                    // which is worse than letting startup recovery skip
                    // the missing compensation entry.
                    let (bh, sti) = match lookup_before(i, j) {
                        BeforeImage::UnsetMined {
                            block_height,
                            subtree_idx,
                        } => (block_height, subtree_idx),
                        _ => (0u32, 0u32),
                    };
                    let req = crate::ops::set_mined::SetMinedRequest {
                        tx_key: *key,
                        block_id: *block_id,
                        block_height: bh,
                        subtree_idx: sti,
                        on_longest_chain: true,
                        unset_mined: false,
                        current_block_height: *current_block_height,
                        block_height_retention: *block_height_retention,
                    };
                    let _ = engine.set_mined(&req);
                    // Forward redo entry: re-add the original block entry
                    // (so a recovery replay applies the same restoration).
                    comp_redo.push(RedoOp::SetMined {
                        tx_key: *key,
                        block_id: *block_id,
                        block_height: bh,
                        subtree_idx: sti,
                        unset: false,
                    });
                    // Compensation-intent redo entry — only emitted when a
                    // real before-image was captured. On crash mid-
                    // rollback, recovery's `replay_compensate_unset_mined`
                    // restores the same state from this entry alone.
                    if matches!(lookup_before(i, j), BeforeImage::UnsetMined { .. }) {
                        comp_redo.push(RedoOp::CompensateUnsetMined {
                            tx_key: *key,
                            block_id: *block_id,
                            block_height: bh,
                            subtree_idx: sti,
                        });
                    }
                }
                ReplicaOp::Reassign {
                    offset,
                    new_hash,
                    block_height,
                    spendable_after,
                    ..
                } => {
                    // Gap #8: reverse reassign using the captured prior
                    // utxo_hash. When no before-image is available, fall
                    // back to zeros AND skip the Compensate* entry — a
                    // crash mid-rollback that replayed zeros would silently
                    // diverge.
                    let prior_hash = match lookup_before(i, j) {
                        BeforeImage::Reassign { prior_utxo_hash } => Some(prior_utxo_hash),
                        _ => None,
                    };
                    let restore_hash = prior_hash.unwrap_or([0u8; 32]);
                    // The post-reassign slot is UTXO_UNSPENT with the new
                    // hash. `engine.reassign` requires UTXO_FROZEN as a
                    // precondition, so going back through that API would
                    // silently fail (status mismatch). Restore by writing
                    // the slot directly instead.
                    if let Some(entry) = engine.lookup(key)
                        && let Ok(slot) = crate::io::read_utxo_slot(
                            engine.device_ref_for(entry.device_id),
                            entry.record_offset,
                            *offset,
                        )
                        && slot.hash == *new_hash
                    {
                        let restored = crate::record::UtxoSlot::new_unspent(restore_hash);
                        // DC-1: do not swallow the restore write error. The
                        // CompensateReassign redo entry below is still
                        // emitted so recovery replays the correct restore on
                        // restart; we record the failure so the caller fails
                        // the op instead of reporting a clean rollback.
                        if let Err(e) = crate::io::write_utxo_slot(
                            engine.device_ref_for(entry.device_id),
                            entry.record_offset,
                            *offset,
                            &restored,
                        ) && restore_write_err.is_none()
                        {
                            restore_write_err =
                                Some(format!("reassign rollback slot-restore write failed: {e}"));
                        }
                    }
                    // Forward redo entry mirrors the engine call so a
                    // recovery replay re-applies the same hash restoration.
                    // We retain the Reassign entry for back-compat with
                    // recovery paths that don't yet know about
                    // CompensateReassign.
                    comp_redo.push(RedoOp::Reassign {
                        tx_key: *key,
                        offset: *offset,
                        new_hash: restore_hash,
                        block_height: *block_height,
                        spendable_after: *spendable_after,
                    });
                    // Compensation-intent: only when a real before-image
                    // was captured. Recovery's `replay_compensate_reassign`
                    // restores the slot bit-exactly from this entry.
                    if let Some(prior) = prior_hash {
                        comp_redo.push(RedoOp::CompensateReassign {
                            tx_key: *key,
                            offset: *offset,
                            prior_utxo_hash: prior,
                        });
                    }
                }
                ReplicaOp::PruneSlot { offset, .. }
                | ReplicaOp::PruneSlotIfSpentBy { offset, .. } => {
                    // Gap #8: PruneSlot only changes the status byte to
                    // UTXO_PRUNED. The slot data (hash, spending_data) is
                    // preserved on device. To reverse, restore the captured
                    // pre-apply status byte (UNSPENT / SPENT / FROZEN).
                    // When no before-image is available we fall back to
                    // UNSPENT — preserves prior best-effort behavior — and
                    // skip the Compensate* redo entry.
                    let prior_status = match lookup_before(i, j) {
                        BeforeImage::Prune { prior_status } => Some(prior_status),
                        _ => None,
                    };
                    let restore_status = prior_status.unwrap_or(crate::record::UTXO_UNSPENT);
                    if let Some(entry) = engine.lookup(key)
                        && let Ok(mut slot) = crate::io::read_utxo_slot(
                            engine.device_ref_for(entry.device_id),
                            entry.record_offset,
                            *offset,
                        )
                        && slot.status == crate::record::UTXO_PRUNED
                    {
                        slot.status = restore_status;
                        // DC-1: surface the restore write failure rather than
                        // swallowing it (see the reassign site above). The
                        // CompensatePrune redo entry below still drives a
                        // correct recovery replay.
                        if let Err(e) = crate::io::write_utxo_slot(
                            engine.device_ref_for(entry.device_id),
                            entry.record_offset,
                            *offset,
                            &slot,
                        ) && restore_write_err.is_none()
                        {
                            restore_write_err =
                                Some(format!("prune rollback slot-restore write failed: {e}"));
                        }
                    }
                    // Compensation-intent redo entry — only when a real
                    // before-image was captured. A crash mid-rollback
                    // would otherwise have no way to recover the status
                    // byte; with the entry, recovery's
                    // `replay_compensate_prune` restores the slot
                    // bit-exactly.
                    if let Some(s) = prior_status {
                        comp_redo.push(RedoOp::CompensatePrune {
                            tx_key: *key,
                            offset: *offset,
                            prior_status: s,
                        });
                    }
                }
                ReplicaOp::SetConflicting {
                    value,
                    current_block_height,
                    retention,
                    ..
                } => {
                    let req = crate::ops::remaining::SetConflictingRequest {
                        tx_key: *key,
                        value: !value,
                        current_block_height: *current_block_height,
                        block_height_retention: *retention,
                    };
                    let _ = engine.set_conflicting(&req);
                    comp_redo.push(RedoOp::SetConflicting {
                        tx_key: *key,
                        value: !value,
                        current_block_height: *current_block_height,
                        block_height_retention: *retention,
                    });
                }
                ReplicaOp::SetLocked { value, .. } => {
                    let (target_locked, target_dah) = match lookup_before(i, j) {
                        BeforeImage::SetLocked {
                            prior_locked,
                            prior_delete_at_height,
                        } => (prior_locked, prior_delete_at_height),
                        _ => (!value, 0),
                    };
                    let _ =
                        engine.restore_set_locked_for_compensation(key, target_locked, target_dah);
                    comp_redo.push(RedoOp::SetLocked {
                        tx_key: *key,
                        value: target_locked,
                    });
                    if matches!(lookup_before(i, j), BeforeImage::SetLocked { .. }) {
                        comp_redo.push(RedoOp::CompensateSetLocked {
                            tx_key: *key,
                            prior_locked: target_locked,
                            prior_delete_at_height: target_dah,
                        });
                    }
                }
                ReplicaOp::PreserveUntil { .. } => {
                    let req = crate::ops::remaining::PreserveUntilRequest {
                        tx_key: *key,
                        block_height: 0,
                    };
                    let _ = engine.preserve_until(&req);
                    comp_redo.push(RedoOp::PreserveUntil {
                        tx_key: *key,
                        block_height: 0,
                    });
                }
                ReplicaOp::Create { .. } => {
                    let req = crate::ops::remaining::DeleteRequest {
                        tx_key: *key,
                        due_guard: None,
                    };
                    let _ = engine.delete(&req);
                    comp_redo.push(RedoOp::Delete {
                        tx_key: *key,
                        record_offset: 0,
                        record_size: 0,
                    });
                }
                ReplicaOp::Delete { .. } | ReplicaOp::DeleteV2 { .. } => {
                    // Delete compensation is handled directly in
                    // handle_delete_batch using pre-captured record snapshots.
                    // If this path is reached from another handler, the record
                    // is already destroyed and cannot be restored here.
                    // `DeleteV2` behaves identically to `Delete` for rollback —
                    // the extra tombstone fields don't change that the record
                    // cannot be reconstructed at this point.
                }
                ReplicaOp::MarkLongestChain {
                    on_longest_chain,
                    current_block_height,
                    block_height_retention,
                    ..
                } => {
                    // R-052 best-effort compensation: re-apply with the
                    // inverse `on_longest_chain` flag. Matches the no-
                    // before-image strategy used by SetConflicting /
                    // SetLocked / PreserveUntil — bit-exact pre-image
                    // restoration is deferred until a dedicated
                    // BeforeImage::MarkLongestChain variant is plumbed
                    // through. The forward redo entry mirrors the call
                    // so a recovery replay performs the same flip.
                    let req = crate::ops::mark_longest_chain::MarkOnLongestChainRequest {
                        tx_key: *key,
                        on_longest_chain: !on_longest_chain,
                        current_block_height: *current_block_height,
                        block_height_retention: *block_height_retention,
                    };
                    if let Ok(resp) = engine.mark_on_longest_chain(&req) {
                        comp_redo.push(RedoOp::MarkOnLongestChain {
                            tx_key: *key,
                            on_longest_chain: !on_longest_chain,
                            current_block_height: *current_block_height,
                            block_height_retention: *block_height_retention,
                            generation: resp.generation,
                        });
                    }
                }
                ReplicaOp::RemoveConflictingChild { child_txid, .. } => {
                    // Reverse a remove by re-appending the child to the parent
                    // (`key` is the parent). append/remove are exact inverses
                    // and both idempotent. The forward redo entry mirrors the
                    // compensating engine call for recovery replay.
                    let _ = engine.append_conflicting_child(key, *child_txid);
                    comp_redo.push(RedoOp::AppendConflictingChild {
                        parent_key: *key,
                        child_txid: *child_txid,
                    });
                }
            }
        }
    }

    // Fault-injection point (test-only, inert without the
    // `fault-injection` feature): all engine effects above have been
    // applied to in-memory/device state, but the compensating redo
    // entries have NOT been appended yet. This is the WAL-inverted window
    // the red-team flagged as the single most fragile spot. A crash here
    // (followed by power loss) leaves NO durable compensating intent, so
    // recovery replays the still-durable ORIGINAL redo entry and the slot
    // is reproduced deterministically — never half-applied.
    crate::fault_injection::check(
        crate::fault_injection::SyncPoint::MidCompensationBeforeRedoAppend,
    );

    let comp_range = if comp_redo.is_empty() {
        None
    } else {
        Some(
            write_redo_ops(engine, redo_log, &comp_redo)
                .map_err(|e| format!("replication compensation redo write failed: {e}"))?,
        )
    };

    // DC-1: surface a slot-restore write failure only AFTER the compensating
    // redo entries are durable. The redo log is the source of truth: on
    // restart, recovery replays the Compensate* entries and restores the
    // slot bit-exactly, so leaving the in-memory/device slot momentarily
    // wrong is fixed by the next recovery — not a silent divergence. The
    // caller treats the returned error as a non-clean rollback (ERR_INTERNAL).
    if let Some(cause) = restore_write_err {
        return Err(cause);
    }

    Ok(comp_range)
}

/// D-4: drive replication of a compensation redo range to the replicas that
/// may have applied the now-rolled-back original op, using the same per-key
/// fan-out + durable-intent machinery as a normal mutation.
///
/// The compensating ops are reconstructed from the comp redo range exactly
/// the way startup recovery does (`recover_pending_replication_intents`),
/// then handed to `replicate`. The intent is committed (cleared) only after
/// `replicate` reaches its ACK-policy durability bar. If `replicate` fails
/// the intent is left **pending** so startup / runtime catch-up re-drives the
/// repair — the rolled-back state is never abandoned on a divergent replica.
///
/// `replicate` is injected so this is unit-testable without a `RunningCluster`;
/// production passes a closure that calls [`replicate_all_ops`].
fn replicate_compensation_intent<F>(
    tracker: Option<&crate::replication::durable::ReplicationIntentTracker>,
    redo_log: Option<&Mutex<RedoLog>>,
    engine: &Engine,
    comp_range: (u64, u64),
    mut replicate: F,
) -> std::result::Result<(), String>
where
    F: FnMut(&[(TxKey, Vec<ReplicaOp>)], (u64, u64)) -> std::result::Result<(), String>,
{
    if !valid_redo_range(comp_range) {
        return Ok(());
    }
    let tracker = match tracker {
        Some(t) => t,
        // No durable intent tracker means no replication is configured
        // (single-node / tests without a cluster) — nothing to reconcile.
        None => return Ok(()),
    };

    let redo_log = match redo_log {
        Some(r) => r,
        None => {
            // Without a redo log here we cannot reconstruct the ops inline, and
            // cannot derive the intent's key set. Recovery cannot replay a
            // key-filtered intent it can't reconstruct either, so there is
            // nothing durable to record — the local rollback stands on its own.
            return Ok(());
        }
    };

    // Mirror `write_redo_ops`' routing: when per-store logs are attached the
    // comp range may span multiple store logs, so read the merged, sequence-
    // ordered view via the engine. Otherwise read from the passed handle.
    // (This read is side-effect-free; the durable intent-file write below still
    // precedes the replication network round-trip, preserving WAL-first order.)
    let entries = if engine.has_per_store_redo() {
        engine
            .read_redo_from_sequence_merged(comp_range.0)
            .map_err(|e| format!("read compensation redo for replication failed: {e}"))?
    } else {
        redo_log
            .lock()
            .read_from_sequence(comp_range.0)
            .map_err(|e| format!("read compensation redo for replication failed: {e}"))?
    };
    let mut ops_by_key: Vec<(TxKey, Vec<ReplicaOp>)> = Vec::new();
    for entry in &entries {
        if entry.sequence < comp_range.0 || entry.sequence > comp_range.1 {
            continue;
        }
        let Some(tx_key) = entry.op.tx_key().copied() else {
            continue;
        };
        let shard = ShardTable::shard_for_key(&tx_key);
        if let Some(op) =
            crate::cluster::coordinator::redo_entry_to_replica_op(entry, shard, engine)
        {
            ops_by_key.push((tx_key, vec![op]));
        }
    }

    // Register the compensation intent durably with its EXACT key set so a
    // crash before the fan-out completes leaves a marker that startup recovery
    // re-replicates — filtered to exactly these compensating keys.
    let comp_keys: Vec<TxKey> = ops_by_key.iter().map(|(k, _)| *k).collect();
    begin_replication_intent_with_tracker(comp_range, &comp_keys, Some(tracker))?;

    if ops_by_key.is_empty() {
        // Nothing replicable in this range (e.g. only Compensate* markers
        // that have no replica-op form). The local rollback stands on its
        // own; clear the intent.
        commit_replication_intent_with_tracker(comp_range, Some(tracker))?;
        return Ok(());
    }

    // Replicate the compensating ops. Only on success do we clear the comp
    // intent — until the compensating op reaches the same durability bar the
    // original required, the intent stays outstanding and drives repair.
    replicate(&ops_by_key, comp_range)?;
    commit_replication_intent_with_tracker(comp_range, Some(tracker))?;
    Ok(())
}

fn compensate_replication_failure_or_error(
    request_id: u64,
    cluster: Option<&RunningCluster>,
    engine: &Engine,
    repl_ops: &[(TxKey, Vec<ReplicaOp>)],
    before_images: &[(TxKey, Vec<BeforeImage>)],
    redo_log: Option<&Mutex<RedoLog>>,
    intent_ranges: &[(u64, u64)],
) -> Option<ResponseFrame> {
    let comp_range = match compensate_replication_failure(engine, repl_ops, before_images, redo_log)
    {
        Ok(range) => range,
        Err(cause) => {
            tracing::error!(
                cause = %cause,
                "replication compensation failed; leaving replication intent pending for operator recovery"
            );
            // DC-1: do not clear the original intent on a failed rollback —
            // it must stay pending so recovery re-replays.
            return Some(error_response(request_id, ERR_INTERNAL, &cause));
        }
    };

    // D-4: the local rollback succeeded. If the compensating ops produced a
    // redo range, push them to the replicas that may already hold the
    // now-rolled-back original op, keeping the compensation intent
    // outstanding until that reconciliation reaches its durability bar.
    if let Some(comp_range) = comp_range {
        let tracker = REPLICATION_INTENT_TRACKER.get();
        let replicate_result =
            replicate_compensation_intent(tracker, redo_log, engine, comp_range, |ops, range| {
                replicate_all_ops(cluster, ops, range, &[]).map(|_| ())
            });
        if let Err(cause) = replicate_result {
            // The compensation intent (if registered) is durable and stays
            // pending; startup / catch-up will re-drive the reconciliation.
            // We still clear the original intent: the comp intent now carries
            // the repair obligation (it reverses the same keys). The client
            // already learns the op failed.
            tracing::warn!(
                cause = %cause,
                comp_first = comp_range.0,
                comp_last = comp_range.1,
                "compensation reconciliation to replicas did not complete; intent left pending for catch-up",
            );
        }
    }

    // The original op's replication intent is cleared: any replica that
    // applied it is reconciled by the compensating op above (whose intent
    // remains outstanding until durable), so the original range no longer
    // needs to be re-driven.
    clear_replication_intents_after_compensation(intent_ranges);
    None
}

/// Look up (or create) the per-address replication slot.
fn repl_slot_for(addr: SocketAddr) -> std::sync::Arc<Mutex<PerAddrSlot>> {
    // The outer pool lock is held only for the HashMap lookup/insert,
    // not during I/O.
    let mut pool = REPL_POOL.lock();
    pool.entry(addr)
        .or_insert_with(|| {
            std::sync::Arc::new(Mutex::new(PerAddrSlot {
                connection: None,
                last_acked: 0,
                next_sequence: None,
            }))
        })
        .clone()
}

/// Drop the cached per-address replication state (pooled connection AND
/// dense-sequence cursor) for `addr`.
///
/// The next [`send_replica_ops_to`] re-probes the replica's applied
/// watermark before assigning sequence numbers — exactly what a fresh
/// master process does on first contact. Integration tests use this to
/// emulate a master restart against a live replica; it is also safe to
/// call operationally (the probe/relabel protocol re-converges).
pub fn reset_replica_stream(addr: SocketAddr) {
    let slot = {
        let mut pool = REPL_POOL.lock();
        pool.remove(&addr)
    };
    // Lock (and immediately drop) the slot so an in-flight send on the
    // removed slot finishes before the connection closes underneath it.
    if let Some(slot) = slot {
        let mut guard = slot.lock();
        guard.connection = None;
        guard.next_sequence = None;
    }
}

/// Drop only the pooled connection for `addr`, KEEPING the
/// dense-sequence cursor.
///
/// Used when the replica process restarted (its old connection is dead
/// or would be served by a defunct handler) but the master's stream
/// position remains valid: the next send reconnects and continues at
/// the same cursor, and the receiver's persisted watermark makes the
/// first post-restart batch an exact next-expected match.
pub fn drop_replica_connection(addr: SocketAddr) {
    let slot = {
        let pool = REPL_POOL.lock();
        pool.get(&addr).cloned()
    };
    if let Some(slot) = slot {
        slot.lock().connection = None;
    }
}

/// Send one `ReplicaBatch` frame on the slot's pooled connection and wait
/// for the replica's `ReplicaAck`.
///
/// Reuses the cached connection if healthy, otherwise reconnects (once on
/// a failed send). Returns the decoded ack on success; `Err` covers
/// connect/send/recv transport failures. The caller holds the slot lock,
/// so concurrent sends to the SAME replica are serialized (correct: TCP
/// is ordered) while different replicas proceed in parallel.
fn exchange_replica_batch(
    slot_guard: &mut PerAddrSlot,
    addr: SocketAddr,
    batch: &ReplicaBatch,
    ack_timeout: Duration,
    auth_secret: Option<&[u8]>,
) -> std::result::Result<ReplicaAck, String> {
    let mut transport = match slot_guard.connection.take() {
        Some(t) if t.is_connected() && t.auth_secret_matches(auth_secret) => t,
        _ => TcpReplicaTransport::connect_with_auth(
            &addr.to_string(),
            Duration::from_secs(5),
            auth_secret.map(|s| s.to_vec()),
        )
        .map_err(|e| format!("connect: {e}"))?,
    };

    if let Err(e) = transport.send_batch(batch) {
        // Connection may be stale (broken by partition, killed node, etc.).
        // Drop the broken transport and reconnect once before giving up.
        drop(transport);
        let mut retry_transport = TcpReplicaTransport::connect_with_auth(
            &addr.to_string(),
            Duration::from_secs(5),
            auth_secret.map(|s| s.to_vec()),
        )
        .map_err(|e2| format!("send: {e}; reconnect: {e2}"))?;
        if let Err(e2) = retry_transport.send_batch(batch) {
            return Err(format!("send after reconnect: {e2}"));
        }
        transport = retry_transport;
    }

    match transport.recv_ack(ack_timeout) {
        Ok(ack) => {
            slot_guard.connection = Some(transport);
            Ok(ack)
        }
        Err(e) => Err(format!("recv_ack: {e}")),
    }
}

/// Maximum send attempts per batch inside [`send_replica_ops_to`]: the
/// initial send plus one relabeled retry after a cursor-resync signal
/// (`ReplicaAck::Gap` or a duplicate-skip ACK whose `through_sequence`
/// is ahead of the batch). The receiver's watermark can only move via
/// this slot's own serialized sends, so a single renegotiation round
/// always converges; a second disagreement is a hard error.
const MAX_SEQUENCE_RENEGOTIATIONS: usize = 2;

/// Send replica ops to one replica address on that address's **dense
/// per-replica sequence stream** (R-D1/D-3).
///
/// Behavior, all under the per-address slot mutex:
///
/// 1. If the slot's stream cursor is unsynced (first contact since
///    process start), send an empty-batch **probe**; the receiver ACKs
///    its authoritative per-stream applied watermark and the cursor is
///    adopted as `watermark + 1`. This is what keeps the master's
///    per-replica next-sequence consistent with the receiver's persisted
///    watermark across restarts of either side.
/// 2. Label the batch `first_sequence = cursor` and send.
/// 3. ACK handling:
///    * `Ok { through == last_sequence }` — success: advance the cursor,
///      record `redo_high` (the redo-log position this batch covers) in
///      the durable [`crate::replication::durable::AckTracker`] for
///      catch-up/lag bookkeeping.
///    * `Gap { expected_sequence }` — the replica is missing positions
///      below the label (burned by an earlier failed batch): relabel at
///      `expected_sequence` and retry once.
///    * `Ok { through > last_sequence }` — duplicate-skip against a
///      watermark ahead of the cursor (cursor desync): adopt
///      `through + 1` and retry once. The batch content was NOT applied,
///      so this is never treated as success.
///    * transport / replica error — fail the batch and **burn** the
///      assigned positions (advance the cursor past them). The replica
///      may or may not have applied the frame; burning guarantees a
///      position is never reused for different content, and the benign
///      hole (if any) heals on the next send via the Gap/relabel path.
///
/// `redo_high` is the highest master redo-log sequence whose ops are
/// covered by this batch — pass `0` when not applicable (e.g. catch-up
/// chunks whose redo progress the caller records itself).
///
/// Returns `Ok(())` once the replica has durably applied (or provably
/// already applied) every op in `ops`; `Err(message)` otherwise.
pub fn send_replica_ops_to(
    addr: SocketAddr,
    ops: &[ReplicaOp],
    ack_timeout: Duration,
    auth_secret: Option<&[u8]>,
    cluster_key: u64,
    source_node_id: u64,
    redo_high: u64,
) -> std::result::Result<(), String> {
    if ops.is_empty() {
        return Ok(());
    }
    let slot = repl_slot_for(addr);
    // Lock only this address's slot. Other addresses are uncontended.
    let mut slot_guard = slot.lock();

    // Sync the stream cursor on first contact: adopt the replica's
    // authoritative applied watermark. Initializing from any master-side
    // persisted value instead could label NEW ops at positions the
    // replica already covers, which the receiver would dedup-skip and
    // ACK — silent drop. The probe makes that impossible by
    // construction.
    let mut next = match slot_guard.next_sequence {
        Some(n) => n,
        None => {
            let probe = ReplicaBatch {
                first_sequence: 0,
                ops: Vec::new(),
                trace_ctx: None,
                source_node_id: Some(source_node_id),
                cluster_key,
            };
            match exchange_replica_batch(&mut slot_guard, addr, &probe, ack_timeout, auth_secret)? {
                ReplicaAck::Ok { through_sequence } => {
                    let n = through_sequence + 1;
                    slot_guard.next_sequence = Some(n);
                    n
                }
                other => {
                    return Err(format!("watermark probe rejected: {other:?}"));
                }
            }
        }
    };

    for attempt in 0..MAX_SEQUENCE_RENEGOTIATIONS {
        let batch = ReplicaBatch {
            first_sequence: next,
            ops: ops.to_vec(),
            trace_ctx: crate::observability::WireTraceContext::from_current_span(),
            source_node_id: Some(source_node_id),
            cluster_key,
        };
        let last = batch.last_sequence();

        let ack =
            match exchange_replica_batch(&mut slot_guard, addr, &batch, ack_timeout, auth_secret) {
                Ok(ack) => ack,
                Err(e) => {
                    // Burn the assigned positions: the frame may have been
                    // applied with the ACK lost in flight. Reusing the
                    // positions for different content could be dedup-skipped
                    // by the receiver; a hole heals via Gap/relabel instead.
                    slot_guard.next_sequence = Some(last + 1);
                    return Err(e);
                }
            };

        match ack {
            ReplicaAck::Ok { through_sequence } if through_sequence == last => {
                slot_guard.next_sequence = Some(last + 1);
                slot_guard.last_acked = through_sequence;
                // Persist the redo-log coverage for crash-safe catch-up
                // and lag monitoring (real redo space, not the stream
                // labels — see AckTracker docs).
                if redo_high > 0
                    && let Some(tracker) = ACK_TRACKER.get()
                {
                    tracker.record_ack(addr, redo_high);
                }
                return Ok(());
            }
            ReplicaAck::Ok { through_sequence } => {
                // Duplicate-skip against a watermark ahead of our cursor:
                // nothing from THIS batch was applied. Adopt and retry.
                tracing::warn!(
                    %addr,
                    attempt,
                    sent_first = next,
                    sent_last = last,
                    replica_through = through_sequence,
                    "replication: cursor behind replica watermark; resyncing and relabeling",
                );
                slot_guard.next_sequence = Some(through_sequence + 1);
                next = through_sequence + 1;
            }
            ReplicaAck::Gap {
                expected_sequence, ..
            } => {
                // Benign hole left by burned positions; relabel down to
                // the replica's next-expected sequence and retry.
                tracing::warn!(
                    %addr,
                    attempt,
                    sent_first = next,
                    expected_sequence,
                    "replication: replica NAKed sequence gap; relabeling and re-sending",
                );
                slot_guard.next_sequence = Some(expected_sequence);
                next = expected_sequence;
            }
            ReplicaAck::Error { message, .. } => {
                // Burn the positions — the replica may have applied a
                // prefix before failing.
                slot_guard.next_sequence = Some(last + 1);
                return Err(format!("replica error: {message}"));
            }
        }
    }

    Err(format!(
        "replication to {addr}: sequence renegotiation did not converge after \
         {MAX_SEQUENCE_RENEGOTIATIONS} attempts",
    ))
}

// ---------------------------------------------------------------------------
// Quorum check
// ---------------------------------------------------------------------------

/// Check if the cluster has quorum (majority of nodes are alive).
///
/// Returns `None` if quorum is met or no cluster is configured (single-node mode).
/// Returns `Some(ResponseFrame)` with an error if quorum is not met, meaning
/// this node cannot safely accept mutations.
///
/// In a clustered deployment, a node must see at least 2 alive nodes (including
/// itself) to accept writes. This prevents split-brain scenarios where isolated
/// nodes diverge by independently accepting conflicting writes.
fn check_quorum(cluster: Option<&RunningCluster>, request_id: u64) -> Option<ResponseFrame> {
    let cluster = cluster?;
    let alive = cluster.alive_node_count();
    let peak = cluster.peak_cluster_size();

    // A node that has only ever seen itself (peak=1) is a standalone cluster
    // node — quorum is trivially met. This covers single-node test setups
    // and bootstrap scenarios.
    if peak <= 1 {
        return None;
    }

    // For a node that was previously part of a multi-node cluster, require
    // a majority (more than half of the peak observed cluster size) to prevent
    // split-brain. With 3 nodes, need >= 2. With 5 nodes, need >= 3.
    let quorum_needed = (peak / 2) + 1;
    if alive < quorum_needed {
        return Some(error_response(request_id, ERR_NO_QUORUM, "no quorum"));
    }
    None
}

/// Returns true if the given opcode is a mutation that requires quorum.
fn is_mutation_opcode(op: u16) -> bool {
    matches!(
        op,
        OP_SPEND_BATCH
            | OP_UNSPEND_BATCH
            | OP_SET_MINED_BATCH
            | OP_CREATE_BATCH
            | OP_FREEZE_BATCH
            | OP_UNFREEZE_BATCH
            | OP_REASSIGN_BATCH
            | OP_SET_CONFLICTING_BATCH
            | OP_REMOVE_CONFLICTING_CHILD_BATCH
            | OP_SET_LOCKED_BATCH
            | OP_PRESERVE_UNTIL_BATCH
            | OP_DELETE_BATCH
            | OP_MARK_LONGEST_CHAIN_BATCH
            | OP_PRESERVE_TRANSACTIONS
            | OP_PROCESS_EXPIRED_PRESERVATIONS
    )
}

fn needs_dispatch_visibility_barrier(op: u16) -> bool {
    is_mutation_opcode(op)
        || matches!(
            op,
            OP_GET_BATCH
                | OP_GET_SPEND_BATCH
                | OP_QUERY_OLD_UNMINED
                | OP_QUERY_CONFLICTING
                | OP_REPLICA_BATCH
        )
}

/// True for ops whose state must NOT be observed by concurrent reads:
/// every mutation opcode plus `OP_REPLICA_BATCH` (which APPLIES master-
/// originated mutations locally). These take the exclusive (write) side
/// of the barrier; client reads take the shared (read) side and are
/// blocked while a mutation/replica-batch is in flight.
fn needs_exclusive_visibility_barrier(op: u16) -> bool {
    is_mutation_opcode(op) || matches!(op, OP_REPLICA_BATCH)
}

/// Hot opcodes that take FINE-GRAINED, PER-KEY visibility instead of the coarse
/// global barrier. `handle_request` acquires no guard for these; the handler
/// itself acquires `engine.visibility().mutation(&keys)` (write) or `.read(&keys)`
/// (read) once it has decoded its keys — so disjoint-key mutations/reads run
/// concurrently while a read of key K is still excluded from a mutation of K
/// (batch-atomic per key). All OTHER mutation opcodes keep the coarse global
/// exclusive guard for now (correct, just not yet parallelized).
fn manages_own_visibility(op: u16) -> bool {
    matches!(op, OP_SPEND_BATCH | OP_GET_BATCH | OP_GET_SPEND_BATCH)
}

/// Owns whichever side of the `dispatch_visibility_barrier` rwlock is
/// appropriate for the opcode. Dropping it releases the guard; the
/// underlying enum keeps the borrow checker honest without exposing
/// `RwLockReadGuard`/`RwLockWriteGuard` to every call site.
///
/// The exclusive (mutation) side is held in an `Option` so it can be
/// moved out into a [`MutationBarrier`] and released *early* — see the
/// C-1 fix. The shared (read) side has no early-release path; it is held
/// for the full duration of the read so a reader never observes a
/// partially-applied batch.
#[allow(clippy::large_enum_variant, dead_code)]
enum DispatchVisibilityGuard<'a> {
    Shared(parking_lot::RwLockReadGuard<'a, ()>),
    /// Exclusive write side. `None` once the guard has been moved out
    /// into a [`MutationBarrier`] (the handle then owns and releases it).
    Exclusive(Option<parking_lot::RwLockWriteGuard<'a, ()>>),
}

/// C-1: a borrowed handle to the exclusive visibility barrier that a
/// mutation handler can **release early** — after the local engine apply
/// and redo-log durability are complete, but before the replication
/// network round-trip begins.
///
/// # Visibility / crash-safety contract
///
/// The exclusive barrier exists to make a mutation's *local apply*
/// atomically visible: no concurrent reader (which holds the shared
/// side) may observe a partially-applied — i.e. torn — batch. Once the
/// handler has fully applied every op to the engine and fsynced the redo
/// log, the local commit is complete and durable. From that point the
/// replication fan-out is a *separate phase* that must not hold the
/// engine-wide barrier: holding it across the synchronous network RTT
/// (a) lets bidirectional master↔master write load form a cross-node
/// circular wait broken only by the multi-second ack timeout (the peer's
/// `OP_REPLICA_BATCH` apply needs *its* exclusive barrier), and (b)
/// stalls every concurrent client read for the full replication RTT.
///
/// Releasing the barrier before fan-out keeps the no-torn-read invariant
/// (the batch is fully applied before release) while relaxing the older
/// "no observable rollback window" property: a reader may now observe a
/// locally-committed value that a subsequent replication failure
/// compensates away. That is sound because the local apply *is* a
/// durable commit (the redo log is the source of truth) and replication-
/// failure compensation is a distinct logical mutation recorded in the
/// redo log, recoverable across a crash by the existing
/// compensation/intent machinery.
pub(crate) struct MutationBarrier<'a> {
    guard: Option<parking_lot::RwLockWriteGuard<'a, ()>>,
}

impl MutationBarrier<'_> {
    /// Release the exclusive visibility barrier. Idempotent — a second
    /// call is a no-op. Called by mutation handlers at the
    /// local-apply-complete / pre-replication boundary so the
    /// replication round-trip does not hold the engine-wide barrier.
    pub(crate) fn release(&mut self) {
        self.guard = None;
    }
}

fn acquire_dispatch_visibility_guard(
    engine: &Engine,
    op: u16,
    flags: u16,
) -> Option<DispatchVisibilityGuard<'_>> {
    if !needs_dispatch_visibility_barrier(op) {
        return None;
    }
    // Hot per-key ops self-manage their visibility inside the handler (after key
    // decode), so `handle_request` takes no coarse guard for them.
    if manages_own_visibility(op) {
        return None;
    }
    // W2/P3: a migration-flagged OP_REPLICA_BATCH takes the SHARED side of
    // the barrier instead of the EXCLUSIVE side that normal replica batches
    // (and all mutations) take. Migration applies funnel many concurrent
    // batches at one target; on the exclusive side they serialize end-to-end
    // (≤1000 ops + device fsync + redo flush each), starving foreground
    // master→replica ACKs and client reads → error 20. Moving them to the
    // shared side lets them run concurrently with each other and with client
    // reads, and (parking_lot is write-preferring) a waiting foreground
    // normal-replica batch or client mutation still drains them within one
    // in-flight apply, not behind a deep queue.
    //
    // This is safe WITHOUT the exclusive side because three independent
    // invariants already cover what the barrier would have:
    //   1. Checkpoint coordination is preserved: `perform_checkpoint_with_
    //      reset_guard` (src/checkpoint.rs) holds the EXCLUSIVE `.write()`
    //      across snapshot_index + persist_allocator, which still excludes
    //      every shared holder including these migration applies — so the
    //      snapshot cannot tear across a migrated record. (A full bypass —
    //      "no guard" — would race the checkpoint snapshot and could drop a
    //      migrated record whose redo entry is pre-fence but whose index
    //      update missed the snapshot; the SHARED guard closes that.)
    //   2. Torn-read fence: a shard being migrated has its inbound bit set,
    //      so `is_master` returns Transitioning and GET_BATCH /
    //      GET_SPEND_BATCH / mutations on that shard return
    //      ERR_MIGRATION_IN_PROGRESS before they ever reach the engine. No
    //      client read can observe the migrated shard's intermediate state,
    //      even though the shared side admits concurrent reads.
    //   3. Per-record integrity: every ReplicaOp variant in
    //      `receiver::apply_op` routes through a stripe-locked engine method
    //      (spend/create/delete/prune_slot/prune_slot_if_spent_by_child/
    //      mark_on_longest_chain/set_record_generation all take
    //      `self.locks.lock(key)`). The route is pinned by the load-bearing
    //      tests `apply_prune_slot_routes_through_stripe_lock` and
    //      `generation_sync_routes_through_stripe_lock` in receiver.rs.
    // The migration flag itself is authenticated: the receiver requires the
    // cluster key (F-G7-005) and dispatch rejects a request_id whose high
    // bits are non-zero, so an unauthenticated/forged batch cannot reach the
    // shared branch.
    //
    // Normal (non-migration) replica batches KEEP the exclusive guard: their
    // shards are NOT fenced, so a torn read of a partially-applied batch IS
    // client-observable. Only the migration flag downgrades the side.
    let is_migration_replica_batch = op == OP_REPLICA_BATCH && (flags & FLAG_MIGRATION_BATCH != 0);
    if needs_exclusive_visibility_barrier(op) && !is_migration_replica_batch {
        Some(DispatchVisibilityGuard::Exclusive(Some(
            engine.acquire_mutation_visibility_guard(),
        )))
    } else {
        Some(DispatchVisibilityGuard::Shared(
            engine.acquire_dispatch_visibility_guard(),
        ))
    }
}

/// Move the exclusive write guard out of a [`DispatchVisibilityGuard`]
/// into a [`MutationBarrier`] so a mutation handler can release it early
/// (C-1).
///
/// Returns `None` for read-side (shared) ops, ops that take no barrier,
/// or an exclusive guard whose write guard has already been taken. The
/// lock guard is transferred into the returned handle (the outer
/// `Exclusive` slot is left empty), so dropping or `release()`-ing the
/// handle is what actually releases the lock; the outer guard's
/// scope-end drop then has nothing left to release.
fn mutation_barrier_from<'g, 'a>(
    guard: &'g mut Option<DispatchVisibilityGuard<'a>>,
) -> Option<MutationBarrier<'a>>
where
    'a: 'g,
{
    match guard {
        Some(DispatchVisibilityGuard::Exclusive(slot)) => {
            slot.take().map(|g| MutationBarrier { guard: Some(g) })
        }
        _ => None,
    }
}

/// Phase I — true if `op` is a client-facing read or write that must
/// wait for the node to be `Alive` (its first committed topology
/// observed). Bootstrap traffic — topology proposals/votes/commits,
/// replica batches, ping/health, partition map, admin diagnostics —
/// bypasses the gate so the node has an opportunity to become ready
/// in the first place.
fn needs_cluster_readiness(op: u16) -> bool {
    is_mutation_opcode(op) || matches!(op, OP_GET_BATCH | OP_GET_SPEND_BATCH | OP_QUERY_OLD_UNMINED)
}

/// Gap #5 — return `Some(error_response)` when `op` depends on a secondary
/// index that failed to rebuild at startup.
///
/// The mapping below identifies each opcode's secondary-index dependency:
///
/// - **Unmined index** (`SECONDARY_UNMINED_OK`): drives the pruner's
///   "old unmined" iterator (`OP_QUERY_OLD_UNMINED`) and the
///   mining/longest-chain workflow (`OP_MARK_LONGEST_CHAIN_BATCH`,
///   which writes the secondary unmined entry on every transition).
///   `OP_SET_MINED_BATCH` also touches the secondary by clearing
///   `unmined_since`, so it's gated as well.
///
/// - **DAH index** (`SECONDARY_DAH_OK`): drives the DAH-based deletion
///   sweep (`OP_PROCESS_EXPIRED_PRESERVATIONS`), the preservation override
///   (`OP_PRESERVE_TRANSACTIONS`, `OP_PRESERVE_UNTIL_BATCH`), and the
///   conflict workflow (`OP_SET_CONFLICTING_BATCH` schedules / clears DAH
///   entries depending on `block_height_retention`).
///
/// - **Both indexes** (`OP_DELETE_BATCH`): a delete touches both
///   secondaries to remove any tombstone entries.
///
/// Regular spend/get/create/freeze/unfreeze/unspend/reassign/set-locked
/// paths do NOT depend on the secondary indexes, so they keep working even
/// when a secondary is degraded — that's what the gap doc required.
fn check_secondary_readiness(op: u16, request_id: u64) -> Option<ResponseFrame> {
    secondary_readiness_verdict(op, secondary_status(), request_id)
}

/// Pure policy function: given an opcode and a [`SecondaryStatus`] snapshot,
/// return `Some(error_response)` if the op depends on an unavailable
/// secondary, or `None` otherwise.
///
/// Split out from [`check_secondary_readiness`] so tests can drive every
/// branch deterministically without mutating the global readiness flags
/// (which would race with other parallel tests).
pub(crate) fn secondary_readiness_verdict(
    op: u16,
    status: SecondaryStatus,
    request_id: u64,
) -> Option<ResponseFrame> {
    if status.fully_ok() {
        return None;
    }
    let needs_unmined = matches!(
        op,
        OP_QUERY_OLD_UNMINED | OP_MARK_LONGEST_CHAIN_BATCH | OP_SET_MINED_BATCH
    );
    let needs_dah = matches!(
        op,
        OP_PROCESS_EXPIRED_PRESERVATIONS
            | OP_PRESERVE_TRANSACTIONS
            | OP_PRESERVE_UNTIL_BATCH
            | OP_SET_CONFLICTING_BATCH
    );
    let needs_both = matches!(op, OP_DELETE_BATCH);
    if needs_both && (!status.dah_ok || !status.unmined_ok) {
        return Some(error_response(
            request_id,
            ERR_INDEX_DEGRADED,
            "secondary index unavailable: delete requires both DAH and unmined indexes",
        ));
    }
    if needs_unmined && !status.unmined_ok {
        return Some(error_response(
            request_id,
            ERR_INDEX_DEGRADED,
            "secondary index unavailable: unmined-secondary failed to rebuild at startup",
        ));
    }
    if needs_dah && !status.dah_ok {
        return Some(error_response(
            request_id,
            ERR_INDEX_DEGRADED,
            "secondary index unavailable: DAH-secondary failed to rebuild at startup",
        ));
    }
    None
}

// ---------------------------------------------------------------------------
// Shard ownership check
// ---------------------------------------------------------------------------

/// Check if a txid belongs to a shard owned by this node.
///
/// Returns `None` if the key is local (or no cluster is configured).
/// Returns `Some(BatchItemError)` with a redirect error if the key belongs
/// to a remote node, including the target node's address in `error_data`.
///
/// When `allow_if_migrating` is true (for read operations), the check
/// allows local handling if this node is actively migrating the shard
/// outbound — the data is still present locally until migration completes.
fn check_shard_ownership(
    txid: &[u8; 32],
    item_index: u32,
    cluster: Option<&RunningCluster>,
    allow_if_migrating: bool,
) -> Option<BatchItemError> {
    let cluster = cluster?;
    let key = TxKey { txid: *txid };
    match cluster.is_master(&key) {
        crate::cluster::coordinator::MasterQueryResult::Yes => {
            // If we're the new master but still waiting for inbound migration
            // data, reject mutations so clients retry after migration completes.
            // F-5: reads do NOT wait — there is no wait loop. A read on a shard
            // with pending inbound data returns ERR_MIGRATION_IN_PROGRESS
            // immediately (via the same path below when `allow_if_migrating`
            // is false), or is served locally during *outbound* migration
            // (the `MasterQueryResult::No` arm) where the data is still present.
            if !allow_if_migrating && cluster.has_pending_inbound(&key) {
                let shard = crate::cluster::shards::ShardTable::shard_for_key(&key);
                tracing::debug!(
                    shard,
                    "dispatch: write rejected — pending inbound migration"
                );
                Some(BatchItemError {
                    item_index,
                    error_code: ERR_MIGRATION_IN_PROGRESS,
                    error_data: Vec::new(),
                })
            } else if !allow_if_migrating && cluster.is_shard_write_fenced(&key) {
                let shard = crate::cluster::shards::ShardTable::shard_for_key(&key);
                tracing::debug!(
                    shard,
                    "dispatch: write rejected — write-fenced (delta streaming)"
                );
                Some(BatchItemError {
                    item_index,
                    error_code: ERR_MIGRATION_IN_PROGRESS,
                    error_data: Vec::new(),
                })
            } else {
                None
            }
        }
        crate::cluster::coordinator::MasterQueryResult::Transitioning { last_known_term } => {
            // Topology proposal in flight but not yet quorum-committed.
            // Don't redirect (the redirect target may itself be wrong).
            // Tell the client to retry; once the gap closes the next
            // attempt resolves to Yes or No deterministically.
            tracing::debug!(
                last_known_term,
                "dispatch: deferring request — topology in transition"
            );
            Some(BatchItemError {
                item_index,
                error_code: ERR_MIGRATION_IN_PROGRESS,
                error_data: Vec::new(),
            })
        }
        crate::cluster::coordinator::MasterQueryResult::No => {
            // During outbound migration, reads can still be served locally
            // because the data hasn't been removed yet.
            if allow_if_migrating && cluster.is_migrating_outbound(&key) {
                return None;
            }
            // Determine the target node address for the redirect.
            //
            // R-041: encode the source node's `shard_table_version` from
            // `RouteDecision::RedirectTo` into `error_data` alongside the
            // address so the receiving client can detect a stale-route
            // loop. Wire format: `[addr_len:2][addr][shard_table_version:8]`.
            // Older clients (or external Go adapters) that read
            // `error_data` as raw addr bytes via `from_utf8` will see a
            // malformed UTF-8 buffer (the trailing version bytes are
            // binary), `from_utf8` returns Err, and the legacy
            // redirect-collector returns `None` — falling through to a
            // PartialError surfaced to the caller. That is a graceful
            // failure (no silent corruption); the legacy client just
            // does not benefit from version-based loop detection.
            let route = cluster.route(&key);
            let error_data = match route {
                crate::cluster::shards::RouteDecision::RedirectTo {
                    node,
                    shard_table_version,
                } => match cluster.node_addr(&node) {
                    Some(addr) => crate::protocol::codec::encode_redirect_with_version(
                        &addr.to_string(),
                        shard_table_version,
                    ),
                    // F-4: the routing table names a master node but we have
                    // no address for it (membership not yet learned, or the
                    // node left between routing and address lookup). An
                    // empty-address redirect is useless — the client cannot
                    // connect to "". Return a retryable ERR_NO_QUORUM ("master
                    // unknown, retry") instead so the client backs off and
                    // retries once membership converges, rather than chasing a
                    // blank target.
                    None => {
                        let shard = crate::cluster::shards::ShardTable::shard_for_key(&key);
                        tracing::debug!(
                            shard,
                            node = ?node,
                            "dispatch: master address unknown — returning retryable ERR_NO_QUORUM instead of empty redirect"
                        );
                        return Some(BatchItemError {
                            item_index,
                            error_code: ERR_NO_QUORUM,
                            error_data: Vec::new(),
                        });
                    }
                },
                crate::cluster::shards::RouteDecision::HandleLocally => return None,
            };
            // M10: count every stale-routed request so operators can alert on
            // persistent stale-routing storms (indicates clients are not
            // refreshing the partition map). Best-effort: no-op if metrics
            // haven't been initialized (e.g. unit tests).
            if let Some(m) = DISPATCH_METRICS.get() {
                m.stale_routing_request_total.inc();
            }
            Some(BatchItemError {
                item_index,
                error_code: ERR_REDIRECT,
                error_data,
            })
        }
    }
}

// ---------------------------------------------------------------------------
// Spend
// ---------------------------------------------------------------------------

fn handle_spend_batch(
    req: &RequestFrame,
    engine: &Engine,
    max_batch: u32,
    cluster: Option<&RunningCluster>,
    redo_log: Option<&Mutex<RedoLog>>,
    // C-1: exclusive visibility barrier, released before replication.
    barrier: Option<MutationBarrier<'_>>,
) -> ResponseFrame {
    let (params, items) = match decode_spend_batch_checked(&req.payload, max_batch) {
        Ok(r) => r,
        Err(e) => return codec_error_response(req.request_id, "spend batch", e),
    };

    // Tick entry counters: one batch, N attempted items.
    if let Some(m) = DISPATCH_METRICS.get() {
        m.spend_multi_batches.inc();
        m.spends_attempted.inc_by(items.len() as u64);
        m.spend_multi_items_attempted.inc_by(items.len() as u64);
    }

    // P2 (PR#21 review): `DahOverflow` is the only NON-catastrophic apply-time
    // failure, and it is deterministic from the batch params alone
    // (`current_block_height + block_height_retention`, identical for every
    // group). Validate it ONCE here, BEFORE any redo is written, so
    // `apply_locked` cannot fail with `DahOverflow` mid-batch — which, now that
    // the whole RPC shares one flush, would otherwise leave already-flushed
    // groups durable-in-WAL but unapplied. A residual apply-time *device* error
    // (EIO/ENOSPC) is catastrophic and intentionally still surfaces under the
    // WAL-first contract (its redo is durable; recovery replays it on restart —
    // see the Phase 4 note); the operator must treat a persistent apply-time
    // device error as fatal.
    if params.block_height_retention != 0
        && params
            .current_block_height
            .checked_add(params.block_height_retention)
            .is_none()
    {
        if let Some(m) = DISPATCH_METRICS.get() {
            use crate::metrics::OpCode;
            let failed = tally_storage_abort(m, OpCode::Spend, items.len() as u64, 0, 0, &[]);
            m.spends_failed.inc_by(failed);
            m.spend_multi_items_failed.inc_by(failed);
        }
        // Reuse the exact SpendError::DahOverflow message the apply path
        // produced, so the client-observable error detail (DAH_OVERFLOW…) is
        // unchanged by moving the check earlier.
        let detail = crate::ops::error::SpendError::DahOverflow {
            current_height: params.current_block_height,
            retention: params.block_height_retention,
        }
        .to_string();
        return error_response(req.request_id, ERR_STORAGE_IO, &detail);
    }

    // Group items by txid for efficient locking
    let mut by_txid: HashMap<[u8; 32], Vec<(usize, &WireSpendItem)>> = HashMap::new();
    for (i, item) in items.iter().enumerate() {
        by_txid.entry(item.txid).or_default().push((i, item));
    }

    // Track per-item outcome. `succeeded` is incremented once per item that
    // actually transitioned the slot to SPENT (valid_spends during apply).
    // `idempotent` is items that were silently no-op (already SPENT with the
    // same spending_data). `failed` is items present in the errors vec.
    let mut succeeded: u64 = 0;
    let mut idempotent: u64 = 0;
    let mut errors: Vec<BatchItemError> = Vec::new();
    let mut repl_ops_by_key: Vec<(TxKey, Vec<ReplicaOp>)> = Vec::new();
    let mut spend_redo_range: (u64, u64) = (0, 0);
    let mut spend_intent_ranges: Vec<(u64, u64)> = Vec::new();

    // PERF (target #2): make the WHOLE SpendBatch RPC durable with ONE redo
    // flush — not one per txid-group. Acquire every distinct stripe lock for
    // the RPC up front (deduplicated + sorted → deadlock-free), validate every
    // group under those held locks, write ALL groups' redo ops in one batch
    // (single fsync), then apply every group, then release the locks.
    //
    // This preserves WAL-first ordering (redo durable before any apply) and
    // per-txid validate→apply atomicity (each stripe lock is held across the
    // whole validate→flush→apply window) while collapsing N fsyncs/RPC to one
    // and removing N-1 of the per-call group-commit waits. Because many stripe
    // locks are held at once, validation/apply go through the guard-free
    // `prepare_spend_multi` / `PreparedSpend::apply_locked`; the single-spend
    // path's `ValidatedSpend` would re-acquire the stripe lock and self-deadlock
    // on a stripe collision.
    let txid_keys: Vec<TxKey> = by_txid.keys().map(|t| TxKey { txid: *t }).collect();
    let stripe_guards = engine.lock_unique_stripes(&txid_keys);
    // Per-key visibility: write-lock the stripes of this batch's keys (plus the
    // global SHARED side = checkpoint coordination). Excludes any client read of
    // THESE keys for the apply window (batch-atomic per key) while letting spends
    // on disjoint keys run fully concurrently — the global exclusive barrier this
    // replaces serialized every mutation. Acquired AFTER the stripe Mutexes
    // (consistent table order) and dropped before replication, alongside
    // `stripe_guards`.
    let visibility_guard = engine.visibility().mutation(&txid_keys);

    // Per-group staged mutation carried from validate (Phase 1+2) to apply
    // (Phase 4) so the single redo flush (Phase 3) sits between them.
    struct StagedSpend {
        key: TxKey,
        prepared: PreparedSpend,
        key_repl_ops: Vec<ReplicaOp>,
    }
    let mut staged: Vec<StagedSpend> = Vec::new();
    let mut all_redo_ops: Vec<RedoOp> = Vec::new();

    // Per-group validate result, merged back in a deterministic order below.
    struct GroupOut {
        errors: Vec<BatchItemError>,
        redo_ops: Vec<RedoOp>,
        staged: Option<StagedSpend>,
    }

    // Phase 1+2: validate one owned group (guard-free; the caller holds every
    // stripe lock) and build its redo + replica ops. This is READ-ONLY on the
    // engine — index lookups plus device record reads inside
    // `prepare_spend_multi` (`read_metadata_fast` + per-offset `read_slot_fast`)
    // — so it is safe to run concurrently across groups, exactly like
    // `decorate_get_item` in the GET path. No writes happen here; the single
    // redo flush (Phase 3) and the serial apply (Phase 4) still run afterwards
    // with all stripe locks held, so WAL-first ordering and per-txid atomicity
    // are unchanged.
    let validate_group = |txid: &[u8; 32], group: &[(usize, &WireSpendItem)]| -> GroupOut {
        let mut out = GroupOut {
            errors: Vec::new(),
            redo_ops: Vec::new(),
            staged: None,
        };
        if let Some(redirect_err) = check_shard_ownership(txid, group[0].0 as u32, cluster, false) {
            for &(i, _) in group {
                out.errors.push(BatchItemError {
                    item_index: i as u32,
                    error_code: redirect_err.error_code,
                    error_data: redirect_err.error_data.clone(),
                });
            }
            return out;
        }

        let spend_items: Vec<SpendItem> = group
            .iter()
            .map(|(i, item)| SpendItem {
                offset: item.vout,
                utxo_hash: item.utxo_hash,
                spending_data: item.spending_data,
                idx: *i as u32,
            })
            .collect();

        let multi_req = SpendMultiRequest {
            tx_key: TxKey { txid: *txid },
            spends: spend_items,
            ignore_conflicting: params.ignore_conflicting,
            ignore_locked: params.ignore_locked,
            current_block_height: params.current_block_height,
            block_height_retention: params.block_height_retention,
        };

        // Validate (no disk writes). Guard-free: the stripe lock for this txid
        // is already held by `stripe_guards` above.
        let prepared = match engine.prepare_spend_multi(&multi_req) {
            Ok(v) => v,
            Err(err) => {
                for &(i, _) in group {
                    out.errors.push(spend_error_to_batch_error(i as u32, &err));
                }
                return out;
            }
        };

        // Build redo ops for the real UNSPENT→SPENT transitions. Semantics are
        // identical to the original per-group logic.
        //
        // Gap #2 (TERANODE_PRODUCTION_READINESS_GAPS.md): each Spend redo entry
        // carries the cumulative `new_spent_count` AFTER its own application,
        // computed from THIS group's pre-spent count, so recovery's
        // `replay_spend` overwrite lands on the real post-spend count.
        let error_indices: std::collections::HashSet<u32> =
            prepared.errors.keys().copied().collect();
        let key = TxKey { txid: *txid };
        let post_generation = prepared.pre_generation.wrapping_add(1);
        let pre_spent_count = prepared.pre_spent_count();
        let transition_offsets: std::collections::HashSet<u32> =
            prepared.transitions().iter().map(|(off, _)| *off).collect();

        let mut key_repl_ops: Vec<ReplicaOp> = Vec::new();
        let mut running_count = pre_spent_count;
        for &(i, item) in group {
            if !error_indices.contains(&(i as u32)) && transition_offsets.contains(&item.vout) {
                // Real UNSPENT → SPENT — counter advances by 1. Idempotent
                // re-spends do not emit redo/replication or bump generation;
                // they match the single-spend no-op contract.
                running_count = running_count.wrapping_add(1);
                out.redo_ops.push(RedoOp::SpendV2 {
                    tx_key: key,
                    offset: item.vout,
                    spending_data: item.spending_data,
                    new_spent_count: running_count,
                    current_block_height: params.current_block_height,
                    block_height_retention: params.block_height_retention,
                    target_generation: post_generation,
                    updated_at: engine.now_millis(),
                    // B-5: carry the validated slot hash so recovery can
                    // rebuild a CRC-failing spent slot from this intent.
                    utxo_hash: Some(item.utxo_hash),
                });
                key_repl_ops.push(ReplicaOp::Spend {
                    tx_key: key,
                    offset: item.vout,
                    spending_data: item.spending_data,
                    current_block_height: params.current_block_height,
                    block_height_retention: params.block_height_retention,
                    master_generation: post_generation,
                });
            }
        }

        out.staged = Some(StagedSpend {
            key,
            prepared,
            key_repl_ops,
        });
        out
    };

    // Deterministic group order (by each group's first item index) so the merged
    // redo/replica op order never depends on HashMap iteration or, under the
    // fan-out, on thread scheduling.
    let mut groups: Vec<_> = by_txid.iter().collect();
    groups.sort_unstable_by_key(|(_, g)| g[0].0);

    // Fan the read-only validate across the read pool for batches at or above
    // READ_FANOUT_THRESHOLD (distinct txids); smaller batches stay serial. The
    // collect is order-preserving, so the merge below is deterministic.
    let group_outs: Vec<GroupOut> = match (groups.len() >= READ_FANOUT_THRESHOLD)
        .then(read_pool)
        .flatten()
    {
        Some(pool) => {
            use rayon::iter::{IntoParallelRefIterator, ParallelIterator};
            pool.install(|| {
                groups
                    .par_iter()
                    .map(|&(txid, group)| validate_group(txid, group))
                    .collect()
            })
        }
        None => groups
            .iter()
            .map(|&(txid, group)| validate_group(txid, group))
            .collect(),
    };

    for go in group_outs {
        errors.extend(go.errors);
        all_redo_ops.extend(go.redo_ops);
        if let Some(s) = go.staged {
            staged.push(s);
        }
    }

    // Phase 3: ONE redo write for the whole RPC (single fsync), WAL-first. All
    // stripe locks are still held, so no concurrent mutation can interleave.
    // `engine` is threaded so per-store redo routes each op to its store's log.
    if !all_redo_ops.is_empty() {
        match write_replicated_redo_ops(engine, cluster, redo_log, &all_redo_ops) {
            Ok(range) => {
                if valid_redo_range(range) {
                    spend_intent_ranges.push(range);
                }
                spend_redo_range = range;
            }
            Err(e) => {
                // Redo failed: apply NOTHING (the stripe guards drop on
                // return, releasing the locks). M-01: nothing applied yet, so
                // every non-error item counts as ErrStorage-failed.
                if let Some(m) = DISPATCH_METRICS.get() {
                    use crate::metrics::OpCode;
                    let failed = tally_storage_abort(
                        m,
                        OpCode::Spend,
                        items.len() as u64,
                        succeeded,
                        idempotent,
                        &errors,
                    );
                    m.spends_succeeded.inc_by(succeeded);
                    m.spends_idempotent.inc_by(idempotent);
                    m.spends_failed.inc_by(failed);
                    m.spend_multi_items_succeeded.inc_by(succeeded);
                    m.spend_multi_items_idempotent.inc_by(idempotent);
                    m.spend_multi_items_failed.inc_by(failed);
                }
                return error_response(req.request_id, ERR_STORAGE_IO, &e);
            }
        }
    }

    // Phase 4: apply every staged group (stripe locks still held → WAL-first
    // and per-txid atomicity preserved: redo is already durable, and no other
    // mutation can touch these txids until the guards drop below).
    //
    // PR#21 review (P2): each group's DAH secondary update is DEFERRED
    // (`apply_locked(.., true)`) and folded into one batched secondary fsync
    // after the loop, instead of one `append_and_flush` per last-spend txid.
    //
    // This loop is INTENTIONALLY serial (do not parallelize). Every stripe
    // lock for the RPC is already held, so the apply work is pure in-memory
    // CPU under exclusive ownership — there is no I/O to overlap. Fanning it
    // out would force per-thread `succeeded`/`idempotent`/`errors`/
    // `dah_transitions` accumulators with a deterministic post-join merge AND
    // would fracture the single WAL-first "durable-but-unapplied on apply
    // error → recovery replays the redo" contract that the held-locks +
    // ordered single-flush design depends on. The complexity is not worth it
    // for a lock-bound in-memory loop.
    let mut dah_transitions: Vec<(TxKey, u32, u32)> = Vec::new();
    for st in staged {
        let validation_errors = st.prepared.errors.clone();
        idempotent += st.prepared.idempotent_count() as u64;
        let (resp, dah_transition) = match st.prepared.apply_locked(engine, true) {
            Ok(r) => r,
            Err(e) => {
                // PR#21 review (P2): `DahOverflow` is pre-validated before the
                // flush above, so a failure HERE is a catastrophic device error
                // (EIO/ENOSPC) only. The redo for every group is already durable
                // (WAL-first), so the contract is: the unapplied groups' redo
                // replays on restart — the operator must treat a persistent
                // apply-time device error as fatal and restart (the disk is
                // failing). We return ERR_STORAGE_IO; guards drop on return.
                // (Same WAL-first contract as the pre-existing single-group
                // path; the batched flush only widens which groups are durable-
                // but-unapplied in this catastrophic window.)
                for (idx, err) in &validation_errors {
                    errors.push(spend_error_to_batch_error(*idx, err));
                }
                if let Some(m) = DISPATCH_METRICS.get() {
                    use crate::metrics::OpCode;
                    let failed = tally_storage_abort(
                        m,
                        OpCode::Spend,
                        items.len() as u64,
                        succeeded,
                        idempotent,
                        &errors,
                    );
                    m.spends_succeeded.inc_by(succeeded);
                    m.spends_idempotent.inc_by(idempotent);
                    m.spends_failed.inc_by(failed);
                    m.spend_multi_items_succeeded.inc_by(succeeded);
                    m.spend_multi_items_idempotent.inc_by(idempotent);
                    m.spend_multi_items_failed.inc_by(failed);
                }
                return error_response(req.request_id, ERR_STORAGE_IO, &e.to_string());
            }
        };

        if let Some((old_dah, new_dah)) = dah_transition {
            dah_transitions.push((st.key, old_dah, new_dah));
        }

        if !st.key_repl_ops.is_empty() {
            repl_ops_by_key.push((st.key, st.key_repl_ops));
        }

        // Tally this group's outcomes: real transitions from resp.spent_count,
        // idempotent no-ops already added above, failures from the error map.
        succeeded += resp.spent_count as u64;
        for (idx, err) in validation_errors {
            errors.push(spend_error_to_batch_error(idx, &err));
        }

        // Use signal/block_ids from resp if needed in the future.
        let _ = resp.signal;
    }

    // Fold every group's DAH secondary-index update into ONE redo fsync (still
    // under the stripe locks, matching the inline single-spend ordering). On
    // failure the spends are already applied + durable and recovery reconciles
    // the DAH index from primary metadata, but we surface ERR_STORAGE_IO to
    // match the single-spend `update_dah_index` failure contract.
    if let Err(e) = PreparedSpend::commit_dah_batch(engine, &dah_transitions) {
        if let Some(m) = DISPATCH_METRICS.get() {
            use crate::metrics::OpCode;
            let failed = tally_storage_abort(
                m,
                OpCode::Spend,
                items.len() as u64,
                succeeded,
                idempotent,
                &errors,
            );
            m.spends_succeeded.inc_by(succeeded);
            m.spends_idempotent.inc_by(idempotent);
            m.spends_failed.inc_by(failed);
            m.spend_multi_items_succeeded.inc_by(succeeded);
            m.spend_multi_items_idempotent.inc_by(idempotent);
            m.spend_multi_items_failed.inc_by(failed);
        }
        return error_response(req.request_id, ERR_STORAGE_IO, &e.to_string());
    }

    // Release every stripe lock BEFORE replication (network I/O must not run
    // under the locks). On the error returns above the guards drop at scope end.
    drop(stripe_guards);
    // Release per-key visibility before the replication round-trip (reads of
    // these keys resume immediately, observing the fully-applied local batch),
    // mirroring the old MutationBarrier early-release.
    drop(visibility_guard);

    // Final per-item outcome classification for this batch. `errors` holds
    // validation failures *and* redirect errors (when the txid is not owned
    // by this node), so all three buckets sum to items.len().
    let failed_total = errors.len() as u64;
    let idempotent_total = idempotent;
    debug_assert_eq!(
        succeeded + idempotent_total + failed_total,
        items.len() as u64,
        "spend batch item accounting should be exhaustive"
    );
    if let Some(m) = DISPATCH_METRICS.get() {
        m.spends_succeeded.inc_by(succeeded);
        m.spends_idempotent.inc_by(idempotent_total);
        m.spends_failed.inc_by(failed_total);
        m.spend_multi_items_succeeded.inc_by(succeeded);
        m.spend_multi_items_idempotent.inc_by(idempotent_total);
        m.spend_multi_items_failed.inc_by(failed_total);
        // Dual-write: labeled operations table.
        use crate::metrics::{OpCode, Outcome};
        m.operations.inc_by(OpCode::Spend, Outcome::Ok, succeeded);
        m.operations
            .inc_by(OpCode::Spend, Outcome::Idempotent, idempotent_total);
        for e in &errors {
            m.operations
                .inc(OpCode::Spend, classify_wire_error_code(e.error_code));
        }
    }

    // Phase 5: Replicate (redo already fsynced, engine already applied).
    // C-1: the barrier is released inside `replicate_all_ops_with_barrier`
    // before the network round-trip.
    let repl_outcome = match replicate_all_ops_with_barrier(
        cluster,
        &repl_ops_by_key,
        spend_redo_range,
        &spend_intent_ranges,
        barrier,
    ) {
        Ok(o) => o,
        Err(e) => {
            let before_images = no_before_images(&repl_ops_by_key);
            if let Some(resp) = compensate_replication_failure_or_error(
                req.request_id,
                cluster,
                engine,
                &repl_ops_by_key,
                &before_images,
                redo_log,
                &spend_intent_ranges,
            ) {
                return resp;
            }
            return error_response(req.request_id, ERR_REPLICATION_FAILED, &e);
        }
    };

    if errors.is_empty() {
        let status = if repl_outcome.is_degraded() {
            STATUS_DEGRADED_DURABILITY
        } else {
            STATUS_OK
        };
        ResponseFrame {
            request_id: req.request_id,
            status,
            payload: vec![],
        }
    } else {
        errors.sort_by_key(|e| e.item_index);
        ResponseFrame {
            request_id: req.request_id,
            status: STATUS_PARTIAL_ERROR,
            payload: encode_sparse_errors(&errors),
        }
    }
}

// ---------------------------------------------------------------------------
// Unspend
// ---------------------------------------------------------------------------

// NOTE ON WAL ORDERING: Unlike `handle_spend_batch` which holds the
// per-txid lock across redo write + engine mutation (because spend uses
// validate-then-apply), the handlers below (unspend, set_mined, freeze,
// etc.) write redo ops BEFORE acquiring the engine lock. The redo entry is
// fsynced before the engine validates the request, so a request the engine
// then REJECTS still leaves a durable redo entry. This is only safe when
// the corresponding `replay_*` function re-validates identity exactly as the
// live engine does, so a rejected op replays as a no-op. Concretely, redo
// entries in these paths fall into three classes:
//
//   (a) intentional no-op redo — the op was an idempotent no-op live (e.g.
//       unspend of an already-UNSPENT slot, freeze of an already-FROZEN
//       slot); replay observes the same state and skips.
//   (b) validation-failure redo — the engine rejected the request
//       (ERR_UTXO_HASH_MISMATCH, ERR_UTXO_NOT_FROZEN, …). The matching
//       `replay_*` MUST re-check the same precondition (slot hash / status)
//       and skip, so a rejected op never becomes durable. This is why
//       unspend uses `UnspendV2 { utxo_hash }` and reassign uses
//       `ReassignV2 { prior_utxo_hash }` — the prior identity is carried in
//       the entry precisely so replay can reject what the engine rejected.
//   (c) mutation redo — a confirmed transition; replay applies it.
//
// If a redo op is added here whose `replay_*` cannot re-validate the live
// precondition, this pattern must be restructured to match the spend path's
// validate-then-redo-under-lock discipline instead.
fn handle_unspend_batch(
    req: &RequestFrame,
    engine: &Engine,
    max_batch: u32,
    cluster: Option<&RunningCluster>,
    redo_log: Option<&Mutex<RedoLog>>,
    // C-1: exclusive visibility barrier, released before replication.
    barrier: Option<MutationBarrier<'_>>,
) -> ResponseFrame {
    let (params, items) = match decode_unspend_batch_checked(&req.payload, max_batch) {
        Ok(r) => r,
        Err(e) => return codec_error_response(req.request_id, "unspend batch", e),
    };

    // Tick entry counters: one batch, N attempted items.
    if let Some(m) = DISPATCH_METRICS.get() {
        m.unspend_multi_batches.inc();
        m.unspends_attempted.inc_by(items.len() as u64);
        m.unspend_multi_items_attempted.inc_by(items.len() as u64);
    }

    let mut errors = Vec::new();
    let mut redo_ops: Vec<RedoOp> = Vec::new();

    // Phase 1: Validate ownership and build redo ops from request parameters.
    struct ValidUnspend<'a> {
        idx: usize,
        key: TxKey,
        item: &'a WireUnspendItem,
        pre_generation: u32,
    }
    let mut valid_items: Vec<ValidUnspend> = Vec::new();
    // Gap #2 (TERANODE_PRODUCTION_READINESS_GAPS.md): per-txid running
    // `spent_utxos` counter for redo entries. Recovery's `replay_unspend`
    // overwrites `meta.spent_utxos = new_spent_count`; previously we
    // wrote `0`, which corrupted the counter on crash-replay even when
    // the slot transition was correct. Initialize each running counter
    // from the index entry's cached `spent_utxos` (kept in sync with
    // metadata under the per-record lock) and decrement (saturating at
    // 0) for every entry — replay is idempotent against UTXO_UNSPENT
    // slots so over-decrement on a re-played idempotent redo is
    // harmless because replay skips before touching metadata.
    let mut running_spent: std::collections::HashMap<TxKey, u32> = std::collections::HashMap::new();
    for (i, item) in items.iter().enumerate() {
        if let Some(redirect_err) = check_shard_ownership(&item.txid, i as u32, cluster, false) {
            errors.push(redirect_err);
            continue;
        }
        let key = TxKey { txid: item.txid };
        // Snapshot the generation BEFORE unspend so we can classify the
        // outcome as "real unspend" (gen bumped) vs "idempotent noop"
        // (gen unchanged — slot was already UNSPENT).
        let entry = engine.lookup(&key);
        let pre_generation = entry.as_ref().map(|e| e.generation).unwrap_or(0);
        let pre_spent = entry.as_ref().map(|e| e.spent_utxos).unwrap_or(0);
        // Initialize the running counter with the current spent count
        // (from index cache) the first time we see this txid in this
        // batch. Subsequent items in the same batch decrement from
        // there, modeling the per-item recovery state.
        let counter = running_spent.entry(key).or_insert(pre_spent);
        *counter = counter.saturating_sub(1);
        redo_ops.push(RedoOp::UnspendV2 {
            tx_key: key,
            offset: item.vout,
            spending_data: item.spending_data,
            new_spent_count: *counter,
            current_block_height: params.current_block_height,
            block_height_retention: params.block_height_retention,
            target_generation: pre_generation.wrapping_add(1),
            updated_at: engine.now_millis(),
            // B-5: carry the slot hash so recovery can rebuild a
            // CRC-failing slot to UNSPENT with the correct hash.
            utxo_hash: Some(item.utxo_hash),
        });
        valid_items.push(ValidUnspend {
            idx: i,
            key,
            item,
            pre_generation,
        });
    }

    // Phase 2: WAL-first — write redo before engine mutation.
    let redo_range = match write_replicated_redo_ops(engine, cluster, redo_log, &redo_ops) {
        Ok(range) => range,
        Err(e) => {
            // M-01: `attempted` already ticked; nothing has applied yet, so
            // every non-redirected item counts as ErrStorage-failed.
            if let Some(m) = DISPATCH_METRICS.get() {
                use crate::metrics::OpCode;
                let failed =
                    tally_storage_abort(m, OpCode::Unspend, items.len() as u64, 0, 0, &errors);
                m.unspends_failed.inc_by(failed);
                m.unspend_multi_items_failed.inc_by(failed);
            }
            return error_response(req.request_id, ERR_STORAGE_IO, &e);
        }
    };

    // Phase 3: Apply engine mutations and build repl ops.
    let mut repl_ops_by_key: Vec<(TxKey, Vec<ReplicaOp>)> = Vec::new();
    let mut succeeded: u64 = 0;
    let mut idempotent: u64 = 0;
    for v in &valid_items {
        match engine.unspend(&UnspendRequest {
            tx_key: v.key,
            offset: v.item.vout,
            utxo_hash: v.item.utxo_hash,
            spending_data: v.item.spending_data,
            current_block_height: params.current_block_height,
            block_height_retention: params.block_height_retention,
        }) {
            Ok(resp) => {
                if resp.generation == v.pre_generation {
                    // No-op: slot was already UNSPENT, generation unchanged.
                    idempotent += 1;
                } else {
                    succeeded += 1;
                }
                repl_ops_by_key.push((
                    v.key,
                    vec![ReplicaOp::Unspend {
                        tx_key: v.key,
                        offset: v.item.vout,
                        spending_data: v.item.spending_data,
                        current_block_height: params.current_block_height,
                        block_height_retention: params.block_height_retention,
                        master_generation: resp.generation,
                    }],
                ));
            }
            Err(err) => {
                errors.push(spend_error_to_batch_error(v.idx as u32, &err));
            }
        }
    }

    let failed_total = errors.len() as u64;
    if let Some(m) = DISPATCH_METRICS.get() {
        m.unspends_succeeded.inc_by(succeeded);
        m.unspends_noop.inc_by(idempotent);
        m.unspends_failed.inc_by(failed_total);
        m.unspend_multi_items_succeeded.inc_by(succeeded);
        m.unspend_multi_items_idempotent.inc_by(idempotent);
        m.unspend_multi_items_failed.inc_by(failed_total);
        // Dual-write: labeled operations table.
        use crate::metrics::{OpCode, Outcome};
        m.operations.inc_by(OpCode::Unspend, Outcome::Ok, succeeded);
        m.operations
            .inc_by(OpCode::Unspend, Outcome::Idempotent, idempotent);
        for e in &errors {
            m.operations
                .inc(OpCode::Unspend, classify_wire_error_code(e.error_code));
        }
    }

    // Phase 4: Replicate.
    let repl_outcome = match replicate_all_ops_with_barrier(
        cluster,
        &repl_ops_by_key,
        redo_range,
        &[redo_range],
        barrier,
    ) {
        Ok(o) => o,
        Err(e) => {
            let before_images = no_before_images(&repl_ops_by_key);
            if let Some(resp) = compensate_replication_failure_or_error(
                req.request_id,
                cluster,
                engine,
                &repl_ops_by_key,
                &before_images,
                redo_log,
                &[redo_range],
            ) {
                return resp;
            }
            return error_response(req.request_id, ERR_REPLICATION_FAILED, &e);
        }
    };

    batch_response_with_outcome(req.request_id, &errors, repl_outcome)
}

// ---------------------------------------------------------------------------
// SetMined
// ---------------------------------------------------------------------------

fn handle_set_mined_batch(
    req: &RequestFrame,
    engine: &Engine,
    max_batch: u32,
    cluster: Option<&RunningCluster>,
    redo_log: Option<&Mutex<RedoLog>>,
    // C-1: exclusive visibility barrier, released before replication.
    barrier: Option<MutationBarrier<'_>>,
) -> ResponseFrame {
    let (params, txids) = match decode_set_mined_batch_checked(&req.payload, max_batch) {
        Ok(r) => r,
        Err(e) => return codec_error_response(req.request_id, "set_mined batch", e),
    };

    if let Some(m) = DISPATCH_METRICS.get() {
        m.set_mined_items_attempted.inc_by(txids.len() as u64);
    }

    let mut errors = Vec::new();
    let mut redo_ops: Vec<RedoOp> = Vec::new();

    // Phase 1: Validate ownership and build redo ops from request params.
    struct ValidSetMined {
        idx: usize,
        key: TxKey,
    }
    let mut valid_items: Vec<ValidSetMined> = Vec::new();
    for (i, txid) in txids.iter().enumerate() {
        if let Some(redirect_err) = check_shard_ownership(txid, i as u32, cluster, false) {
            errors.push(redirect_err);
            continue;
        }
        let key = TxKey { txid: *txid };
        redo_ops.push(RedoOp::SetMined {
            tx_key: key,
            block_id: params.block_id,
            block_height: params.block_height,
            subtree_idx: params.subtree_idx,
            unset: params.unset_mined,
        });
        valid_items.push(ValidSetMined { idx: i, key });
    }

    // Phase 2: WAL-first — write redo before engine mutation.
    let redo_range = match write_replicated_redo_ops(engine, cluster, redo_log, &redo_ops) {
        Ok(range) => range,
        Err(e) => {
            // M-01: `attempted` already ticked; nothing has applied yet, so
            // every non-redirected item counts as ErrStorage-failed.
            if let Some(m) = DISPATCH_METRICS.get() {
                use crate::metrics::OpCode;
                let failed =
                    tally_storage_abort(m, OpCode::SetMined, txids.len() as u64, 0, 0, &errors);
                m.set_mined_items_failed.inc_by(failed);
            }
            return error_response(req.request_id, ERR_STORAGE_IO, &e);
        }
    };

    // Gap #8: capture pre-apply (block_height, subtree_idx) for the
    // matching block_id BEFORE the engine clears the entry. Only the
    // unset path needs this — when adding a block entry, rollback is a
    // simple "remove the same block_id" operation that doesn't need
    // historical fields. We read the metadata once per valid_item; if
    // the block_id is not currently present, the unset is a no-op and
    // there is nothing to compensate.
    //
    // F-G5-022 / A-4 (RESOLVED 2026-05-18 — not-applicable):
    // The read here is unlocked, but the engine apply path
    // (`set_mined_batch` → `set_mined_inner`) takes the per-tx stripe
    // mutex at function entry and holds it for the entire validate-
    // and-write sequence (see `Engine` doc comment, "Atomic-apply
    // invariant"). A concurrent same-key set_mined that lands between
    // this read and the engine apply does NOT cause a write-correctness
    // bug — the engine still applies under its own lock and the result
    // returned to the client is consistent. The compensation
    // before-image captured here is a snapshot of state at read time;
    // if it diverges from the now-committed engine state, the rollback
    // restores to a slightly earlier point. That is acceptable under
    // the replication contract: failed-replication compensation runs
    // BEFORE the response is returned to the client, so no committed
    // observer ever saw the to-be-rolled-back state. The reproduction
    // test `tests/g2_atomic_apply.rs` confirms the atomic-apply
    // invariant for the spend path; set_mined inherits the same
    // stripe-lock discipline.
    let pre_unset_image: std::collections::HashMap<TxKey, BeforeImage> = if params.unset_mined {
        valid_items
            .iter()
            .filter_map(|v| {
                let entry = engine.read_block_entry(&v.key, params.block_id).ok()??;
                Some((
                    v.key,
                    BeforeImage::UnsetMined {
                        block_height: { entry.block_height },
                        subtree_idx: { entry.subtree_idx },
                    },
                ))
            })
            .collect()
    } else {
        std::collections::HashMap::new()
    };

    // Phase 3: Apply engine mutations via batch API (params passed once by reference).
    let engine_params = crate::ops::set_mined::SetMinedSharedParams {
        block_id: params.block_id,
        block_height: params.block_height,
        subtree_idx: params.subtree_idx,
        current_block_height: params.current_block_height,
        block_height_retention: params.block_height_retention,
        on_longest_chain: params.on_longest_chain,
        unset_mined: params.unset_mined,
    };
    let keys: Vec<TxKey> = valid_items.iter().map(|v| v.key).collect();
    // The apply is the read-modify-write hot path: each `set_mined_inner` reads
    // the record metadata from the device, mutates, and writes it back. It
    // self-locks on the per-key stripe lock and only touches Mutex-guarded
    // secondary indexes, so independent keys apply concurrently safely — and
    // the slow device I/O then overlaps instead of pinning one core. WAL-first
    // is intact: the batch's `SetMined` redo was already flushed (Phase 2), and
    // `set_mined_inner` writes no redo. Fan out at/above READ_FANOUT_THRESHOLD
    // (order-preserving collect keeps results aligned with `keys`); smaller
    // batches stay serial.
    let results: Vec<
        std::result::Result<crate::ops::set_mined::SetMinedResponse, crate::ops::error::SpendError>,
    > = match (keys.len() >= READ_FANOUT_THRESHOLD)
        .then(read_pool)
        .flatten()
    {
        Some(pool) => {
            use rayon::iter::{IntoParallelRefIterator, ParallelIterator};
            pool.install(|| {
                keys.par_iter()
                    .map(|k| engine.set_mined_inner(k, &engine_params))
                    .collect()
            })
        }
        None => keys
            .iter()
            .map(|k| engine.set_mined_inner(k, &engine_params))
            .collect(),
    };

    let mut repl_ops_by_key: Vec<(TxKey, Vec<ReplicaOp>)> = Vec::new();
    let mut before_images_by_key: Vec<(TxKey, Vec<BeforeImage>)> = Vec::new();
    // LP-2 / spec §3.6: the setMined response must carry the post-op block-ID
    // list per item so the Go client (`txmetacache.SetMinedMulti`) can satisfy
    // its coverage postcondition without an extra GET round-trip. LP-5: the DAH
    // `signal` is surfaced in the same per-item record. `childCount`/#1037 is
    // intentionally NOT emitted: it existed only to let the reference UDF client
    // clear `locked` on pagination child records, which TeraSlab does not have
    // (spec §2.2 — pagination eliminated). The master record's LOCKED flag is
    // cleared server-side inside `set_mined_inner` (engine.rs), so there is
    // nothing left for the client to unlock. `BatchItemSuccess` has no
    // childCount field for the same reason.
    let mut successes: Vec<BatchItemSuccess> = Vec::new();
    let mut succeeded: u64 = 0;
    for (v, result) in valid_items.iter().zip(results) {
        match result {
            Ok(resp) => {
                succeeded += 1;
                let mgen = resp.generation;
                successes.push(BatchItemSuccess {
                    item_index: v.idx as u32,
                    signal: resp.signal.to_wire(),
                    block_ids: resp.block_ids.clone(),
                });
                if params.unset_mined {
                    repl_ops_by_key.push((
                        v.key,
                        vec![ReplicaOp::UnsetMined {
                            tx_key: v.key,
                            block_id: params.block_id,
                            current_block_height: params.current_block_height,
                            block_height_retention: params.block_height_retention,
                            master_generation: mgen,
                        }],
                    ));
                    before_images_by_key.push((
                        v.key,
                        vec![
                            pre_unset_image
                                .get(&v.key)
                                .copied()
                                .unwrap_or(BeforeImage::None),
                        ],
                    ));
                } else {
                    repl_ops_by_key.push((
                        v.key,
                        vec![ReplicaOp::SetMined {
                            tx_key: v.key,
                            block_id: params.block_id,
                            block_height: params.block_height,
                            subtree_idx: params.subtree_idx,
                            on_longest_chain: params.on_longest_chain,
                            current_block_height: params.current_block_height,
                            block_height_retention: params.block_height_retention,
                            master_generation: mgen,
                        }],
                    ));
                    before_images_by_key.push((v.key, vec![BeforeImage::None]));
                }
            }
            Err(err) => {
                errors.push(spend_error_to_batch_error(v.idx as u32, &err));
            }
        }
    }

    let failed_total = errors.len() as u64;
    if let Some(m) = DISPATCH_METRICS.get() {
        m.set_mined_items_succeeded.inc_by(succeeded);
        m.set_mined_items_failed.inc_by(failed_total);
        // Dual-write: labeled operations table.
        use crate::metrics::{OpCode, Outcome};
        m.operations
            .inc_by(OpCode::SetMined, Outcome::Ok, succeeded);
        for e in &errors {
            m.operations
                .inc(OpCode::SetMined, classify_wire_error_code(e.error_code));
        }
    }

    // Phase 4: Replicate.
    let repl_outcome = match replicate_all_ops_with_barrier(
        cluster,
        &repl_ops_by_key,
        redo_range,
        &[redo_range],
        barrier,
    ) {
        Ok(o) => o,
        Err(e) => {
            // Gap #8: rollback uses the captured pre-unset block-entry
            // fields so a crash mid-rollback can be replayed exactly.
            if let Some(resp) = compensate_replication_failure_or_error(
                req.request_id,
                cluster,
                engine,
                &repl_ops_by_key,
                &before_images_by_key,
                redo_log,
                &[redo_range],
            ) {
                return resp;
            }
            return error_response(req.request_id, ERR_REPLICATION_FAILED, &e);
        }
    };

    // Final batch-level ticks: set_mined_succeeded counts a successful batch,
    // set_mined_attempted incremented at dispatch entry. Tick succeeded only
    // if no items failed to preserve a useful "batches that fully succeeded"
    // gauge separate from item-level accounting.
    if let Some(m) = DISPATCH_METRICS.get()
        && failed_total == 0
    {
        m.set_mined_succeeded.inc();
    }

    set_mined_response_with_signals(req.request_id, &successes, &errors, repl_outcome)
}

/// Build the `OP_SET_MINED_BATCH` wire response.
///
/// Unlike [`batch_response_with_outcome`] (errors-only), this carries the
/// per-item `(signal, block_ids)` records required by spec §3.6 and consumed by
/// `txmetacache.SetMinedMulti`. Encoding rules:
///
/// - When all items succeed and replication is fully durable, the status is
///   `STATUS_OK` and the payload is the `encode_partial_with_signals` form
///   (a populated success section, empty error section). The Go client always
///   parses both sections, so the block-ID list is present on the happy path.
/// - When replication is degraded, the status is `STATUS_DEGRADED_DURABILITY`
///   but the payload still carries the block IDs (the mutation applied
///   locally; the client must still learn the block IDs).
/// - When any item failed, the status is `STATUS_PARTIAL_ERROR` and the
///   payload carries both the per-item successes and the sparse error section.
fn set_mined_response_with_signals(
    request_id: u64,
    successes: &[BatchItemSuccess],
    errors: &[BatchItemError],
    outcome: ReplicationOutcome,
) -> ResponseFrame {
    let status = if !errors.is_empty() {
        STATUS_PARTIAL_ERROR
    } else if outcome.is_degraded() {
        STATUS_DEGRADED_DURABILITY
    } else {
        STATUS_OK
    };
    ResponseFrame {
        request_id,
        status,
        payload: encode_partial_with_signals(successes, errors),
    }
}

// ---------------------------------------------------------------------------
// Create
// ---------------------------------------------------------------------------

/// Parse the wire cold_data blob into separate inputs/outputs/inpoints fields.
/// Wire format: [inputs_len:4 LE][inputs][outputs_len:4 LE][outputs][inpoints_len:4 LE][inpoints]
#[allow(clippy::type_complexity)]
fn parse_cold_data_fields(cold_data: &[u8]) -> (Option<&[u8]>, Option<&[u8]>, Option<&[u8]>) {
    if cold_data.len() < 12 {
        return (None, None, None);
    }
    let mut pos = 0usize;

    let Some(inputs) = take_cold_data_section(cold_data, &mut pos) else {
        return (None, None, None);
    };

    let inputs_opt = if inputs.is_empty() {
        None
    } else {
        Some(inputs)
    };

    let Some(outputs) = take_cold_data_section(cold_data, &mut pos) else {
        return (inputs_opt, None, None);
    };

    let outputs_opt = if outputs.is_empty() {
        None
    } else {
        Some(outputs)
    };

    let Some(inpoints) = take_cold_data_section(cold_data, &mut pos) else {
        return (inputs_opt, outputs_opt, None);
    };

    let inpoints_opt = if inpoints.is_empty() {
        None
    } else {
        Some(inpoints)
    };

    (inputs_opt, outputs_opt, inpoints_opt)
}

fn take_cold_data_section<'a>(cold_data: &'a [u8], pos: &mut usize) -> Option<&'a [u8]> {
    let len_end = pos.checked_add(4)?;
    let len_bytes = cold_data.get(*pos..len_end)?;
    let len = u32::from_le_bytes(len_bytes.try_into().ok()?) as usize;
    let start = len_end;
    let end = start.checked_add(len)?;
    let section = cold_data.get(start..end)?;
    *pos = end;
    Some(section)
}

/// Outcome of deciding what `cold_data` a create replica op should carry.
///
/// See [`create_repl_cold_data`] for the rationale behind each variant.
enum CreateReplColdData {
    /// Ship a `ReplicaOp::Create` whose `cold_data` field carries this value.
    /// `None` means "no inline cold data" (non-external create with an empty
    /// wire body); `Some(bytes)` carries the payload the replica must persist.
    Ship(Option<Vec<u8>>),
    /// Do NOT push a replica op for this item. Used only for the
    /// should-never-happen case where an EXTERNAL record's blob cannot be read
    /// back from the master's blob store at replica-op build time. The master's
    /// own create already succeeded (record + blob + ExternalRef are durable
    /// and pinned), so this is degraded under-replication, NOT a client-facing
    /// failure: the caller logs and skips replication for this item only.
    SkipReplicationBlobMissing,
}

/// Decide the `cold_data` a create's `ReplicaOp::Create` must carry.
///
/// # Why external blobs are read back here
///
/// When a client streams a large external blob to the master
/// (`OP_STREAM_CHUNK`/`OP_STREAM_END` write it to the master's blob store
/// only — never replicated) and then sends `OP_CREATE_BATCH` with
/// `FLAG_EXTERNAL_BLOB` and an EMPTY inline `cold_data`, the wire body carries
/// no bytes. Shipping the (empty) wire `cold_data` as `None` would create a
/// live EXTERNAL record with a valid `ExternalRef` but NO blob on the replica,
/// permanently losing the payload on promotion. To close that gap, for an
/// external item we read the blob back from the master's blob store (the same
/// read-back the delete-snapshot path performs) and ship it inline so the
/// receiver's "failing to store cold data must fail the ACK" contract actually
/// engages.
///
/// # Parameters
///
/// * `engine` — the master engine, used to reach `blob_store()` for read-back.
/// * `txid` — the transaction id, also the blob key.
/// * `is_external` — whether this create carries `FLAG_EXTERNAL_BLOB`.
/// * `wire_cold_data` — the inline cold data from the create request.
///
/// # Behavior
///
/// * Non-external: preserves the historical rule — empty wire body → `Ship(None)`,
///   otherwise `Ship(Some(clone))`.
/// * External: reads `engine.blob_store().get(txid)`. Present → `Ship(Some(blob))`.
///   Absent/error/no blob store → [`CreateReplColdData::SkipReplicationBlobMissing`]
///   (a should-never-happen inconsistency: the digest check already verified the
///   blob and it is pinned through registration). The caller must NOT ship a
///   blob-less external Create — doing so re-opens the data-loss bug.
///
/// The blob is read back while the per-item blob pin is still held (it lives in
/// `ValidCreate::_blob_pin` and is dropped only after this loop), so a
/// concurrent periodic GC sweep cannot unlink it between the digest check and
/// this read-back.
fn create_repl_cold_data(
    engine: &Engine,
    txid: &[u8; 32],
    is_external: bool,
    wire_cold_data: &[u8],
) -> CreateReplColdData {
    if !is_external {
        return if wire_cold_data.is_empty() {
            CreateReplColdData::Ship(None)
        } else {
            CreateReplColdData::Ship(Some(wire_cold_data.to_vec()))
        };
    }

    let key = TxKey { txid: *txid };
    match engine.blob_store() {
        Some(bs) => match bs.get(&key.txid) {
            Ok(Some(blob)) => CreateReplColdData::Ship(Some(blob)),
            Ok(None) => CreateReplColdData::SkipReplicationBlobMissing,
            Err(e) => {
                tracing::error!(
                    txid = ?key.txid,
                    err = %e,
                    "external create replica-op build: blob read-back failed",
                );
                CreateReplColdData::SkipReplicationBlobMissing
            }
        },
        None => CreateReplColdData::SkipReplicationBlobMissing,
    }
}

fn handle_create_batch(
    req: &RequestFrame,
    engine: &Engine,
    max_batch: u32,
    cluster: Option<&RunningCluster>,
    redo_log: Option<&Mutex<RedoLog>>,
    blob_store: Option<&dyn BlobStore>,
    // C-1: exclusive visibility barrier, released before replication.
    barrier: Option<MutationBarrier<'_>>,
) -> ResponseFrame {
    let items = match decode_create_batch_checked(&req.payload, max_batch) {
        Ok(r) => r,
        Err(e) => return codec_error_response(req.request_id, "create batch", e),
    };

    if let Some(m) = DISPATCH_METRICS.get() {
        m.creates_attempted.inc_by(items.len() as u64);
    }

    let mut errors = Vec::new();
    let mut redo_ops: Vec<RedoOp> = Vec::new();

    fn release_create_reservation(
        engine: &Engine,
        device_id: u8,
        record_offset: u64,
        reservation_size: u64,
        context: &str,
    ) -> std::result::Result<(), String> {
        engine
            .allocator_for(device_id)
            .lock()
            .free(record_offset, reservation_size)
            .map_err(|e| {
                format!(
                    "create reservation rollback failed after {context}: \
                     device={device_id} offset={record_offset} size={reservation_size}: {e}"
                )
            })
    }

    // Pre-compute mined_block_infos for each item so CreateRequest can borrow them.
    let mined_infos: Vec<Vec<crate::ops::create::MinedBlockInfo>> = items
        .iter()
        .map(|item| {
            if let Some(block_id) = item.mined_block_id {
                vec![crate::ops::create::MinedBlockInfo {
                    block_id,
                    block_height: item.mined_block_height.unwrap_or(0),
                    subtree_idx: item.mined_subtree_idx.unwrap_or(0),
                }]
            } else {
                vec![]
            }
        })
        .collect();

    // Phase 1: Validate ownership, check blobs, and build the record bytes
    // that will be captured in Create after batch allocation assigns
    // record offsets.
    struct PendingCreate<'a, 'p> {
        idx: usize,
        create_req: CreateRequest<'a>,
        utxo_count: u32,
        reservation_size: u64,
        record_bytes: Vec<u8>,
        /// F-IJ-002: keeps the external blob pinned against the periodic
        /// blob-GC sweep from the digest check until index registration.
        /// Released on drop — every failure path (item `continue`, batch
        /// early return) un-pins automatically.
        blob_pin: Option<crate::storage::blobstore::BlobPinGuard<'p>>,
    }

    struct ValidCreate<'a, 'p> {
        idx: usize,
        create_req: CreateRequest<'a>,
        /// Store this record was placed on (round-robin); routes the
        /// `create_at_offset_on` device write and is stamped into the index.
        device_id: u8,
        record_offset: u64,
        reservation_size: u64,
        /// PERF #9: the exact on-device record image (== the CreateV2 redo
        /// bytes). Written to device in one coalesced bulk pwrite per
        /// contiguous run (Phase 2b) after the redo flush; Phase 3 then only
        /// registers the index entry.
        record_bytes: Vec<u8>,
        /// See [`PendingCreate::blob_pin`]; held until after
        /// `create_at_offset` registers the index entry. Never read —
        /// exists purely for its `Drop` (un-pin).
        _blob_pin: Option<crate::storage::blobstore::BlobPinGuard<'p>>,
    }
    let mut pending_items: Vec<PendingCreate> = Vec::new();
    let mut valid_items: Vec<ValidCreate> = Vec::new();

    // P3 (review): a txid repeated WITHIN this batch must reserve/journal/write
    // exactly one copy. Without this guard both copies pass the pre-filter
    // lookup (neither is in the index yet), both reserve+journal+bulk-write a
    // record, and only the 2nd `register_create_at_offset` returns
    // DuplicateTxId — whose region is freed only IN MEMORY, leaving a durable
    // orphan region in the WAL/on device. Drop every occurrence after the first
    // here, before any reservation, so only one copy is ever materialized.
    let mut seen_txids: std::collections::HashSet<[u8; 32]> = std::collections::HashSet::new();

    for (i, item) in items.iter().enumerate() {
        if let Some(redirect_err) = check_shard_ownership(&item.txid, i as u32, cluster, false) {
            errors.push(redirect_err);
            continue;
        }

        if !seen_txids.insert(item.txid) {
            errors.push(BatchItemError {
                item_index: i as u32,
                error_code: ERR_ALREADY_EXISTS,
                error_data: vec![],
            });
            continue;
        }

        // Check whether this item uses an externally-uploaded blob and bind
        // the record metadata to the durable blobstore digest.
        let is_ext = item.flags & FLAG_EXTERNAL_BLOB != 0;
        let (external_ref, blob_pin) = if is_ext {
            let Some(bs) = blob_store else {
                errors.push(BatchItemError {
                    item_index: i as u32,
                    error_code: ERR_BLOB_NOT_FOUND,
                    error_data: vec![],
                });
                continue;
            };
            // F-IJ-002: pin the txid BEFORE the digest check and hold the
            // pin until index registration. The blob may be older than the
            // F-G9-004 grace window (clients legitimately stream the blob
            // long before sending the create), so without the pin a
            // concurrent periodic GC sweep could unlink it between this
            // digest check and `create_at_offset`'s registration —
            // acknowledging an EXTERNAL record whose cold data is gone.
            let pin = engine.blob_pins().pin(&item.txid);
            match bs.digest(&item.txid) {
                Ok(Some(digest)) => (
                    Some(ExternalRef {
                        store_type: 1,
                        content_hash: digest.sha256,
                        total_size: digest.length,
                        input_count: 0,
                        output_count: 0,
                        inputs_offset: 0,
                        outputs_offset: 0,
                    }),
                    Some(pin),
                ),
                Ok(None) => {
                    errors.push(BatchItemError {
                        item_index: i as u32,
                        error_code: ERR_BLOB_NOT_FOUND,
                        error_data: vec![],
                    });
                    continue;
                }
                Err(_) => {
                    errors.push(BatchItemError {
                        item_index: i as u32,
                        error_code: ERR_STORAGE_IO,
                        error_data: vec![],
                    });
                    continue;
                }
            }
        } else {
            (None, None)
        };

        let (inputs, outputs, inpoints) = if is_ext {
            (None, None, None)
        } else {
            parse_cold_data_fields(&item.cold_data)
        };

        let create_req = CreateRequest {
            tx_id: item.txid,
            tx_version: item.tx_version,
            locktime: item.locktime,
            fee: item.fee,
            size_in_bytes: item.size_in_bytes,
            extended_size: item.extended_size,
            is_coinbase: item.is_coinbase,
            spending_height: item.spending_height,
            utxo_hashes: &item.utxo_hashes,
            inputs,
            outputs,
            inpoints,
            is_external: is_ext,
            created_at: item.created_at,
            block_height: item.block_height,
            mined_block_infos: &mined_infos[i],
            frozen: item.flags & 0x04 != 0,
            conflicting: item.flags & 0x02 != 0,
            locked: item.flags & 0x01 != 0,
            external_ref,
            parent_txids: &item.parent_txids,
        };

        let key = TxKey { txid: item.txid };
        // G-4: surface a backend read error rather than collapsing it to
        // "not present" and proceeding with the create. (The engine create
        // re-checks atomically with a checked lookup, but the pre-filter
        // must not report a wrong outcome either.)
        match engine.lookup_checked(&key) {
            Ok(Some(_)) => {
                errors.push(BatchItemError {
                    item_index: i as u32,
                    error_code: ERR_ALREADY_EXISTS,
                    error_data: vec![],
                });
                continue;
            }
            Ok(None) => {}
            Err(e) => {
                errors.push(BatchItemError {
                    item_index: i as u32,
                    error_code: ERR_STORAGE_IO,
                    error_data: format!("index lookup failed: {e}").into_bytes(),
                });
                continue;
            }
        }

        // Gap #2 (TERANODE_PRODUCTION_READINESS_GAPS.md): build the full
        // record bytes before any create WAL flush so the redo entry
        // contains everything recovery needs to reconstruct the on-device
        // record byte-for-byte.
        let (record_bytes, utxo_count) = match engine.build_create_record_bytes(&create_req) {
            Ok(built) => built,
            Err(_) => {
                errors.push(BatchItemError {
                    item_index: i as u32,
                    error_code: ERR_STORAGE_IO,
                    error_data: vec![],
                });
                continue;
            }
        };
        let reservation_size = record_bytes.len() as u64;
        pending_items.push(PendingCreate {
            idx: i,
            create_req,
            utxo_count,
            reservation_size,
            record_bytes,
            blob_pin,
        });
    }

    // Phase 1b: reserve all successful create candidates IN MEMORY (issue #14).
    // The `AllocateRegion` entries are NOT journaled here — they are written
    // ATOMICALLY with the `Create` entries in Phase 2's single batch, so a
    // redo-log-full create can never leave a durable allocation without its
    // record. On a Phase 2 failure the reservations are rolled back in memory
    // (no journal needed, which is essential since the log is full). This
    // window is safe against a concurrent checkpoint persisting the un-journaled
    // reservation because the create holds the exclusive mutation barrier (the
    // same lock the checkpoint task takes) across Phases 1b–3.
    // Round-robin each new record across the configured stores (placement is a
    // free local choice recorded in the index `device_id`; reads route by it).
    // Records destined for the same store must be reserved together on THAT
    // store's allocator — offsets are store-local — so group positions by store
    // and run one `reserve_batch` per store. Each store's allocator tags its
    // own `AllocateRegion` redo ops with its `device_id` (set at boot).
    let device_ids: Vec<u8> = pending_items
        .iter()
        .map(|_| engine.place_new_record())
        .collect();
    let store_count = engine.store_count();
    let mut positions_by_store: Vec<Vec<usize>> = vec![Vec::new(); store_count];
    for (pos, &device_id) in device_ids.iter().enumerate() {
        positions_by_store[device_id as usize].push(pos);
    }

    // `region_by_pos[pos]` is the reserved region for `pending_items[pos]`
    // (`None` if that store was full for this size). `pending_allocs` holds one
    // in-memory reservation handle per store so Phase 2 can commit/rollback all.
    let mut region_by_pos = vec![None; pending_items.len()];
    let mut pending_allocs = Vec::new();
    for (device_id, positions) in positions_by_store.into_iter().enumerate() {
        if positions.is_empty() {
            continue;
        }
        let device_id = device_id as u8;
        let sizes: Vec<u64> = positions
            .iter()
            .map(|&pos| pending_items[pos].reservation_size)
            .collect();
        let mut pending_alloc = match engine.allocator_for(device_id).lock().reserve_batch(&sizes) {
            Ok(p) => p,
            Err(e) => {
                // Roll back stores already reserved in this loop before aborting
                // (nothing is journaled yet, so this is purely in-memory).
                for (rolled_device_id, pa) in pending_allocs {
                    engine
                        .allocator_for(rolled_device_id)
                        .lock()
                        .rollback_pending(pa);
                }
                // M-01: `attempted` already ticked; nothing has applied yet, so
                // every item not already in `errors` counts as ErrStorage-failed.
                if let Some(m) = DISPATCH_METRICS.get() {
                    use crate::metrics::OpCode;
                    let failed =
                        tally_storage_abort(m, OpCode::Create, items.len() as u64, 0, 0, &errors);
                    m.creates_failed.inc_by(failed);
                }
                return error_response(req.request_id, ERR_STORAGE_IO, &format!("{e}"));
            }
        };
        // Seed the redo batch with the not-yet-durable AllocateRegion entries so
        // they fsync together with the Create entries pushed in the loop below.
        // They replay before any Create (lower sequence numbers), so every record
        // has its region allocated first. AllocateRegion has no replica op, so the
        // Phase 4 fan-out (driven by `repl_ops_by_key`) ignores them.
        redo_ops.extend_from_slice(pending_alloc.allocate_region_redo_ops());
        let regions = std::mem::take(&mut pending_alloc.regions);
        for (&pos, region) in positions.iter().zip(regions) {
            region_by_pos[pos] = region;
        }
        pending_allocs.push((device_id, pending_alloc));
    }

    for (pos, pending) in pending_items.into_iter().enumerate() {
        let Some(region) = region_by_pos[pos].take() else {
            errors.push(BatchItemError {
                item_index: pending.idx as u32,
                error_code: ERR_STORAGE_IO,
                error_data: vec![],
            });
            continue;
        };
        let device_id = device_ids[pos];
        let key = TxKey {
            txid: pending.create_req.tx_id,
        };
        let parent_txids: Vec<[u8; 32]> = if pending.create_req.conflicting {
            pending.create_req.parent_txids.to_vec()
        } else {
            Vec::new()
        };
        redo_ops.push(RedoOp::Create {
            tx_key: key,
            device_id,
            record_offset: region.offset,
            utxo_count: pending.utxo_count,
            is_conflicting: pending.create_req.conflicting,
            // PERF #9: clone the record image — the original is retained on
            // ValidCreate for the coalesced bulk device write (Phase 2b). The
            // redo append serializes its own copy regardless, so this is one
            // memcpy, not an extra serialize.
            record_bytes: pending.record_bytes.clone(),
            parent_txids,
        });
        valid_items.push(ValidCreate {
            idx: pending.idx,
            create_req: pending.create_req,
            device_id,
            record_offset: region.offset,
            reservation_size: region.size,
            record_bytes: pending.record_bytes,
            _blob_pin: pending.blob_pin,
        });
    }

    // Phase 2: WAL-first — write [AllocateRegion… + Create…] as ONE atomic
    // batch (a single fsync, all-or-nothing).
    let redo_range = match write_replicated_redo_ops(engine, cluster, redo_log, &redo_ops) {
        Ok(range) => {
            // The AllocateRegion entries are now durable alongside their
            // Create — finalize the in-memory reservations on every store.
            for (device_id, pa) in pending_allocs {
                engine.allocator_for(device_id).lock().commit_pending(pa);
            }
            range
        }
        Err(e) => {
            // Redo failed (e.g. LogFull): roll the reservations back IN MEMORY
            // on every store. Nothing was journaled, so there is no durable
            // allocation to orphan and no compensating redo write is needed
            // (which is the whole point — the log is full). Issue #14.
            for (device_id, pa) in pending_allocs {
                engine.allocator_for(device_id).lock().rollback_pending(pa);
            }
            // M-01: `attempted` already ticked; nothing has applied yet, so
            // every item not already in `errors` counts as ErrStorage-failed.
            if let Some(m) = DISPATCH_METRICS.get() {
                use crate::metrics::OpCode;
                let failed =
                    tally_storage_abort(m, OpCode::Create, items.len() as u64, 0, 0, &errors);
                m.creates_failed.inc_by(failed);
            }
            return error_response(req.request_id, ERR_STORAGE_IO, &e);
        }
    };

    // Phase 2b (PERF #9 + multi-store): write every record's bytes to device in
    // ONE coalesced pwrite per contiguous reservation run, PER STORE. Records are
    // round-robin placed across stores (offsets are store-local), so group by
    // `device_id` and bulk-write each store's records to its own device. WAL-
    // first: this runs AFTER the redo flush above, so every record's `Create`
    // entry is durable first. The bytes are byte-identical to what
    // create_at_offset would have written, so Phase 3 only has to register the
    // index entries (register_create_at_offset).
    // (record_offset, slot_size, record_bytes) for one record's coalesced write.
    type BulkRecord<'a> = (u64, u64, &'a [u8]);
    let mut bulk_by_store: std::collections::HashMap<u8, Vec<BulkRecord>> =
        std::collections::HashMap::new();
    for v in &valid_items {
        bulk_by_store.entry(v.device_id).or_default().push((
            v.record_offset,
            v.reservation_size,
            v.record_bytes.as_slice(),
        ));
    }
    // Fan the per-store coalesced device writes across scoped threads so the N
    // stores' pwrites overlap (each store has its own device) instead of running
    // one-after-another. The calling thread handles the head store; the rest run
    // on scoped threads. Deadlock-safe: `write_records_coalesced` acquires the
    // io_locks stripes in globally-sorted order, so concurrent per-store calls
    // cannot form a lock cycle even though that table is keyed by offset only
    // (cross-store offsets can false-share a stripe).
    let stores: Vec<(u8, &Vec<BulkRecord>)> = bulk_by_store.iter().map(|(&d, r)| (d, r)).collect();
    let bulk_err: Option<CreateError> = match stores.split_first() {
        None => None,
        Some((&(head_id, head_recs), tail)) => std::thread::scope(|scope| {
            let handles: Vec<_> = tail
                .iter()
                .map(|&(device_id, recs)| {
                    scope.spawn(move || engine.write_records_bulk(device_id, recs))
                })
                .collect();
            let mut err = engine.write_records_bulk(head_id, head_recs).err();
            for h in handles {
                let r = h.join().unwrap_or_else(|_| {
                    Err(CreateError::StorageError {
                        detail: "bulk record write thread panicked".to_string(),
                    })
                });
                if let Err(e) = r
                    && err.is_none()
                {
                    err = Some(e);
                }
            }
            err
        }),
    };
    if let Some(e) = bulk_err {
        // Catastrophic device write failure. The `Create` redo entries are
        // already durable, so startup recovery replays them (writing AND
        // registering the records); nothing is registered here. Classify every
        // not-yet-errored item as ErrStorage-failed and fail the request.
        if let Some(m) = DISPATCH_METRICS.get() {
            use crate::metrics::OpCode;
            let failed = tally_storage_abort(m, OpCode::Create, items.len() as u64, 0, 0, &errors);
            m.creates_failed.inc_by(failed);
        }
        return error_response(req.request_id, ERR_STORAGE_IO, &format!("{e}"));
    }
    drop(bulk_by_store);

    // Phase 3: register the index entries (records already on device, Phase 2b).
    //
    // P2 (review): this loop is parallelized across scoped threads. Each item's
    // work is independent and self-serializing — `register_create_at_offset`
    // takes the per-key stripe + per-shard index locks, and after the FIX-2
    // intra-batch dedup above every `valid_items` txid is distinct, so no two
    // items in this batch contend on the same key. The duplicate/error branches
    // free the reservation on the item's OWN store allocator (`allocator_for`
    // is internally `Mutex`-guarded), and `read_metadata` / `create_repl_cold_
    // data` are read-only on the engine. Each thread builds its OWN fragment of
    // `(errors, repl_ops_by_key)` over a CONTIGUOUS slice of `valid_items`; the
    // fragments are merged in slice order after join, so `repl_ops_by_key`
    // ordering and the per-key replica-op contents are byte-identical to the old
    // serial version. `errors` is then stable-sorted by item index so the
    // response encoding is deterministic regardless of thread interleaving.
    //
    // Register one valid item: returns either its replica-op (to push to
    // `repl_ops_by_key`), a per-item error (to push to `errors`), or neither
    // (the degraded under-replication skip). Pure w.r.t. shared mutable state.
    enum RegisterOutcome {
        Replicate(TxKey, ReplicaOp),
        Err(BatchItemError),
        Skip,
    }
    let register_one = |v: &ValidCreate| -> RegisterOutcome {
        let item = &items[v.idx];
        match engine.register_create_at_offset(v.device_id, &v.create_req, v.record_offset) {
            Ok(_) => {
                let key = TxKey { txid: item.txid };
                // Serialize full metadata for the replica so a promoted replica
                // has the authoritative record state.
                let mut meta_buf = Vec::with_capacity(128);
                // Core 46 bytes
                meta_buf.extend_from_slice(&item.tx_version.to_le_bytes());
                meta_buf.extend_from_slice(&item.locktime.to_le_bytes());
                meta_buf.extend_from_slice(&item.fee.to_le_bytes());
                meta_buf.extend_from_slice(&item.size_in_bytes.to_le_bytes());
                meta_buf.extend_from_slice(&item.extended_size.to_le_bytes());
                meta_buf.push(if item.is_coinbase { 1 } else { 0 });
                meta_buf.extend_from_slice(&item.spending_height.to_le_bytes());
                meta_buf.extend_from_slice(&item.created_at.to_le_bytes());
                meta_buf.push(item.flags);
                // Lifecycle 24 bytes
                let (r_gen, r_upd, r_ums, r_dah, r_pu) =
                    if let Ok(meta) = engine.read_metadata(&key) {
                        (
                            { meta.generation },
                            { meta.updated_at },
                            { meta.unmined_since },
                            { meta.delete_at_height },
                            { meta.preserve_until },
                        )
                    } else {
                        (0u32, 0u64, 0u32, 0u32, 0u32)
                    };
                meta_buf.extend_from_slice(&r_gen.to_le_bytes());
                meta_buf.extend_from_slice(&r_upd.to_le_bytes());
                meta_buf.extend_from_slice(&r_ums.to_le_bytes());
                meta_buf.extend_from_slice(&r_dah.to_le_bytes());
                meta_buf.extend_from_slice(&r_pu.to_le_bytes());
                // Extended: block_height + mined_block_infos + parent_txids
                meta_buf.extend_from_slice(&item.block_height.to_le_bytes());
                let block_infos = v.create_req.mined_block_infos;
                meta_buf.push(block_infos.len() as u8);
                for info in block_infos {
                    meta_buf.extend_from_slice(&info.block_id.to_le_bytes());
                    meta_buf.extend_from_slice(&info.block_height.to_le_bytes());
                    meta_buf.extend_from_slice(&info.subtree_idx.to_le_bytes());
                }
                meta_buf.extend_from_slice(&(item.parent_txids.len() as u16).to_le_bytes());
                for ptx in &item.parent_txids {
                    meta_buf.extend_from_slice(ptx);
                }
                if let Some(ext) = v.create_req.external_ref {
                    meta_buf.push(ext.store_type);
                    meta_buf.extend_from_slice(&ext.content_hash);
                    meta_buf.extend_from_slice(&ext.total_size.to_le_bytes());
                    meta_buf.extend_from_slice(&ext.input_count.to_le_bytes());
                    meta_buf.extend_from_slice(&ext.output_count.to_le_bytes());
                    meta_buf.extend_from_slice(&ext.inputs_offset.to_le_bytes());
                    meta_buf.extend_from_slice(&ext.outputs_offset.to_le_bytes());
                }

                let is_external = item.flags & FLAG_EXTERNAL_BLOB != 0;
                // CRITICAL: for a streamed external blob the wire `cold_data`
                // is empty (the bytes arrived via OP_STREAM_*). Shipping that
                // empty body as `cold_data: None` would leave the replica with
                // a live EXTERNAL record + ExternalRef but no blob — the
                // payload is lost on promotion. Read the blob back from the
                // master's (still-pinned) store so it is carried inline and the
                // receiver's fail-the-ACK-on-put-failure contract engages.
                let cold_data =
                    match create_repl_cold_data(engine, &item.txid, is_external, &item.cold_data) {
                        CreateReplColdData::Ship(cold_data) => cold_data,
                        CreateReplColdData::SkipReplicationBlobMissing => {
                            // Should never happen: the digest check verified the
                            // blob and it is pinned through registration. The
                            // master's own create+blob is durable, so this is NOT
                            // a client-facing failure (do not push an error for
                            // `item.idx`). It is degraded under-replication: skip
                            // this item's replica op and log loudly.
                            tracing::error!(
                                txid = ?item.txid,
                                "external create succeeded on master but its blob could not be \
                                 read back for replication; skipping replica op for this item \
                                 (record is under-replicated, not lost on master)",
                            );
                            return RegisterOutcome::Skip;
                        }
                    };
                RegisterOutcome::Replicate(
                    key,
                    ReplicaOp::Create {
                        tx_key: key,
                        metadata_bytes: meta_buf,
                        utxo_hashes: item.utxo_hashes.clone(),
                        cold_data,
                        is_external,
                    },
                )
            }
            Err(CreateError::DuplicateTxId) => {
                // R-014 (A-05): create_at_offset detected the duplicate
                // AFTER pre_allocate_create reserved space — free the
                // reserved region so the allocator does not leak under
                // concurrent create races on the same txid.
                let rollback = release_create_reservation(
                    engine,
                    v.device_id,
                    v.record_offset,
                    v.reservation_size,
                    "create_at_offset duplicate",
                );
                match rollback {
                    Ok(()) => RegisterOutcome::Err(BatchItemError {
                        item_index: v.idx as u32,
                        error_code: ERR_ALREADY_EXISTS,
                        error_data: vec![],
                    }),
                    Err(e) => {
                        tracing::error!(err = %e, "create batch rollback failed");
                        RegisterOutcome::Err(BatchItemError {
                            item_index: v.idx as u32,
                            error_code: ERR_STORAGE_IO,
                            error_data: vec![],
                        })
                    }
                }
            }
            Err(_) => {
                // R-014 (A-05): same fix for the catch-all error path —
                // any failure after pre_allocate_create must release
                // the reserved region.
                if let Err(e) = release_create_reservation(
                    engine,
                    v.device_id,
                    v.record_offset,
                    v.reservation_size,
                    "create_at_offset failure",
                ) {
                    tracing::error!(err = %e, "create batch rollback failed");
                }
                RegisterOutcome::Err(BatchItemError {
                    item_index: v.idx as u32,
                    error_code: ERR_STORAGE_IO,
                    error_data: vec![],
                })
            }
        }
    };

    // Per-chunk fragment: this chunk's errors + its (key, repl-ops) pairs.
    type RegisterFragment = (Vec<BatchItemError>, Vec<(TxKey, Vec<ReplicaOp>)>);

    // Process a contiguous slice of `valid_items`, accumulating its own
    // fragment of (errors, repl_ops). Order within the slice is preserved.
    let register_chunk = |chunk: &[ValidCreate]| -> RegisterFragment {
        let mut frag_errors = Vec::new();
        let mut frag_repl: Vec<(TxKey, Vec<ReplicaOp>)> = Vec::new();
        for v in chunk {
            match register_one(v) {
                RegisterOutcome::Replicate(key, op) => frag_repl.push((key, vec![op])),
                RegisterOutcome::Err(e) => frag_errors.push(e),
                RegisterOutcome::Skip => {}
            }
        }
        (frag_errors, frag_repl)
    };

    // Fan the register work across scoped threads, one contiguous chunk per
    // thread. Bounded by available parallelism and item count; a single chunk
    // runs inline (no thread spawn) to keep small batches cheap. Merge the
    // per-chunk fragments IN CHUNK ORDER so `repl_ops_by_key` matches serial.
    let mut repl_ops_by_key: Vec<(TxKey, Vec<ReplicaOp>)> = Vec::new();
    if !valid_items.is_empty() {
        let max_threads = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1)
            .min(valid_items.len());
        let chunk_count = max_threads.max(1);
        if chunk_count <= 1 {
            let (frag_errors, frag_repl) = register_chunk(&valid_items);
            errors.extend(frag_errors);
            repl_ops_by_key = frag_repl;
        } else {
            let chunk_size = valid_items.len().div_ceil(chunk_count);
            let chunks: Vec<&[ValidCreate]> = valid_items.chunks(chunk_size).collect();
            let fragments: Vec<RegisterFragment> = std::thread::scope(|scope| {
                let (head, tail) = chunks.split_first().expect("chunk_count >= 1");
                let handles: Vec<_> = tail
                    .iter()
                    .map(|&c| scope.spawn(move || register_chunk(c)))
                    .collect();
                let mut out = vec![register_chunk(head)];
                for h in handles {
                    out.push(h.join().unwrap_or_else(|_| {
                        // A register thread panicked. The records are on
                        // device and the Create redo entries are durable, so
                        // recovery will re-register on restart. Surface the
                        // whole batch as a storage failure rather than
                        // silently dropping this chunk's items.
                        (
                            vec![BatchItemError {
                                item_index: 0,
                                error_code: ERR_STORAGE_IO,
                                error_data: b"register thread panicked".to_vec(),
                            }],
                            Vec::new(),
                        )
                    }));
                }
                out
            });
            for (frag_errors, frag_repl) in fragments {
                errors.extend(frag_errors);
                repl_ops_by_key.extend(frag_repl);
            }
        }
    }
    // Deterministic response encoding independent of thread interleaving. The
    // serial version already produced errors in ascending item-index order
    // (Phase 1 then Phase 3, both iterating in item order), so this sort yields
    // the identical ordering for N=1 / single-chunk.
    errors.sort_by_key(|e| e.item_index);

    // Phase 4: Replicate.
    let repl_outcome = match replicate_all_ops_with_barrier(
        cluster,
        &repl_ops_by_key,
        redo_range,
        &[redo_range],
        barrier,
    ) {
        Ok(o) => o,
        Err(e) => {
            let before_images = no_before_images(&repl_ops_by_key);
            if let Some(resp) = compensate_replication_failure_or_error(
                req.request_id,
                cluster,
                engine,
                &repl_ops_by_key,
                &before_images,
                redo_log,
                &[redo_range],
            ) {
                return resp;
            }
            return error_response(req.request_id, ERR_REPLICATION_FAILED, &e);
        }
    };

    // Tick per-item outcome counters. Succeeded = items.len() - errors.len().
    let failed_total = errors.len() as u64;
    let succeeded_total = (items.len() as u64).saturating_sub(failed_total);
    if let Some(m) = DISPATCH_METRICS.get() {
        m.creates_succeeded.inc_by(succeeded_total);
        m.creates_failed.inc_by(failed_total);
        // Dual-write: labeled operations table.
        use crate::metrics::{OpCode, Outcome};
        m.operations
            .inc_by(OpCode::Create, Outcome::Ok, succeeded_total);
        for e in &errors {
            m.operations
                .inc(OpCode::Create, classify_wire_error_code(e.error_code));
        }
    }

    batch_response_with_outcome(req.request_id, &errors, repl_outcome)
}

// ---------------------------------------------------------------------------
// Freeze / Unfreeze / Delete / SetLocked / etc — simple dispatch
// ---------------------------------------------------------------------------

fn handle_freeze_batch(
    req: &RequestFrame,
    engine: &Engine,
    max_batch: u32,
    cluster: Option<&RunningCluster>,
    redo_log: Option<&Mutex<RedoLog>>,
    // C-1: exclusive visibility barrier, released before replication.
    barrier: Option<MutationBarrier<'_>>,
) -> ResponseFrame {
    let items = match decode_slot_item_batch_checked(&req.payload, max_batch) {
        Ok(r) => r,
        Err(e) => return codec_error_response(req.request_id, "freeze batch", e),
    };
    let mut errors = Vec::new();
    let mut redo_ops: Vec<RedoOp> = Vec::new();

    // Phase 1: Validate ownership and build redo ops from request params.
    struct ValidFreeze<'a> {
        idx: usize,
        key: TxKey,
        item: &'a WireSlotItem,
    }
    let mut valid_items: Vec<ValidFreeze> = Vec::new();
    for (i, item) in items.iter().enumerate() {
        if let Some(redirect_err) = check_shard_ownership(&item.txid, i as u32, cluster, false) {
            errors.push(redirect_err);
            continue;
        }
        let key = TxKey { txid: item.txid };
        redo_ops.push(RedoOp::FreezeV2 {
            tx_key: key,
            offset: item.vout,
            utxo_hash: item.utxo_hash,
        });
        valid_items.push(ValidFreeze { idx: i, key, item });
    }
    let total_items = items.len() as u64;

    // Phase 2: WAL-first — write redo before engine mutation.
    let redo_range = match write_replicated_redo_ops(engine, cluster, redo_log, &redo_ops) {
        Ok(range) => range,
        Err(e) => {
            // M-01: nothing has applied yet — classify every non-redirected
            // item as ErrStorage-failed before the early return.
            if let Some(m) = DISPATCH_METRICS.get() {
                use crate::metrics::OpCode;
                let failed = tally_storage_abort(m, OpCode::Freeze, total_items, 0, 0, &errors);
                m.freezes_failed.inc_by(failed);
            }
            return error_response(req.request_id, ERR_STORAGE_IO, &e);
        }
    };

    // Phase 3: Apply engine mutations and build repl ops from engine results.
    let mut repl_ops_by_key: Vec<(TxKey, Vec<ReplicaOp>)> = Vec::new();
    for v in &valid_items {
        match engine.freeze(&FreezeRequest {
            tx_key: v.key,
            offset: v.item.vout,
            utxo_hash: v.item.utxo_hash,
        }) {
            Ok(mgen) => {
                repl_ops_by_key.push((
                    v.key,
                    vec![ReplicaOp::Freeze {
                        tx_key: v.key,
                        offset: v.item.vout,
                        master_generation: mgen,
                    }],
                ));
            }
            Err(err) => {
                errors.push(spend_error_to_batch_error(v.idx as u32, &err));
            }
        }
    }

    // Phase 4: Replicate.
    let repl_outcome = match replicate_all_ops_with_barrier(
        cluster,
        &repl_ops_by_key,
        redo_range,
        &[redo_range],
        barrier,
    ) {
        Ok(o) => o,
        Err(e) => {
            let before_images = no_before_images(&repl_ops_by_key);
            if let Some(resp) = compensate_replication_failure_or_error(
                req.request_id,
                cluster,
                engine,
                &repl_ops_by_key,
                &before_images,
                redo_log,
                &[redo_range],
            ) {
                return resp;
            }
            return error_response(req.request_id, ERR_REPLICATION_FAILED, &e);
        }
    };

    let failed_total = errors.len() as u64;
    let succeeded_total = total_items.saturating_sub(failed_total);
    if let Some(m) = DISPATCH_METRICS.get() {
        m.freezes_succeeded.inc_by(succeeded_total);
        m.freezes_failed.inc_by(failed_total);
        // Dual-write: labeled operations table.
        use crate::metrics::{OpCode, Outcome};
        m.operations
            .inc_by(OpCode::Freeze, Outcome::Ok, succeeded_total);
        for e in &errors {
            m.operations
                .inc(OpCode::Freeze, classify_wire_error_code(e.error_code));
        }
    }

    batch_response_with_outcome(req.request_id, &errors, repl_outcome)
}

