    // 1a. handle_query_old_unmined — matching txids returned
    // -----------------------------------------------------------------------

    #[test]
    fn dispatch_query_old_unmined_returns_matching_txids() {
        let h = DispatchTestHarness::new();
        let txid_a = DispatchTestHarness::make_txid(1);
        let txid_b = DispatchTestHarness::make_txid(2);
        let txid_c = DispatchTestHarness::make_txid(3);

        // Create 3 txs
        assert_eq!(h.create_tx(txid_a, 2).status, STATUS_OK);
        assert_eq!(h.create_tx(txid_b, 2).status, STATUS_OK);
        assert_eq!(h.create_tx(txid_c, 2).status, STATUS_OK);

        // Manually insert into unmined index at different heights
        {
            let mut ui = h.engine.unmined_index();
            ui.insert(100, TxKey { txid: txid_a }, None).unwrap();
            ui.insert(200, TxKey { txid: txid_b }, None).unwrap();
            ui.insert(300, TxKey { txid: txid_c }, None).unwrap();
        }

        // Query with cutoff_height=200 — should return txid_a (100) and txid_b (200)
        let mut payload = Vec::new();
        payload.extend_from_slice(&200u32.to_le_bytes());
        let resp = h.request(OP_QUERY_OLD_UNMINED, payload);
        assert_eq!(resp.status, STATUS_OK);

        // Parse response: [count:4][txids × count]
        let count = u32::from_le_bytes(resp.payload[0..4].try_into().unwrap());
        assert_eq!(count, 2);

        let mut returned_txids: Vec<[u8; 32]> = Vec::new();
        for i in 0..count as usize {
            let start = 4 + i * 32;
            let mut txid = [0u8; 32];
            txid.copy_from_slice(&resp.payload[start..start + 32]);
            returned_txids.push(txid);
        }
        assert!(returned_txids.contains(&txid_a));
        assert!(returned_txids.contains(&txid_b));
        assert!(!returned_txids.contains(&txid_c));
    }

    #[test]
    fn dispatch_query_conflicting_returns_flagged_txids() {
        let h = DispatchTestHarness::new();
        let txid_a = DispatchTestHarness::make_txid(1);
        let txid_b = DispatchTestHarness::make_txid(2);
        let txid_c = DispatchTestHarness::make_txid(3);
        assert_eq!(h.create_tx(txid_a, 2).status, STATUS_OK);
        assert_eq!(h.create_tx(txid_b, 2).status, STATUS_OK);
        assert_eq!(h.create_tx(txid_c, 2).status, STATUS_OK);

        // Flag a and c conflicting (b stays clean).
        for txid in [txid_a, txid_c] {
            h.engine
                .set_conflicting(&crate::ops::remaining::SetConflictingRequest {
                    tx_key: TxKey { txid },
                    value: true,
                    current_block_height: 1000,
                    block_height_retention: 288,
                })
                .unwrap();
        }

        // OP_QUERY_CONFLICTING takes an empty payload.
        let resp = h.request(OP_QUERY_CONFLICTING, Vec::new());
        assert_eq!(resp.status, STATUS_OK);

        let count = u32::from_le_bytes(resp.payload[0..4].try_into().unwrap());
        assert_eq!(count, 2);
        let mut returned: Vec<[u8; 32]> = Vec::new();
        for i in 0..count as usize {
            let start = 4 + i * 32;
            let mut txid = [0u8; 32];
            txid.copy_from_slice(&resp.payload[start..start + 32]);
            returned.push(txid);
        }
        assert!(returned.contains(&txid_a));
        assert!(returned.contains(&txid_c));
        assert!(!returned.contains(&txid_b));

        // After clearing one, the query reflects the change.
        h.engine
            .set_conflicting(&crate::ops::remaining::SetConflictingRequest {
                tx_key: TxKey { txid: txid_a },
                value: false,
                current_block_height: 1000,
                block_height_retention: 288,
            })
            .unwrap();
        let resp2 = h.request(OP_QUERY_CONFLICTING, Vec::new());
        let count2 = u32::from_le_bytes(resp2.payload[0..4].try_into().unwrap());
        assert_eq!(count2, 1);
    }

    #[test]
    fn dispatch_remove_conflicting_child_batch_removes_link() {
        let h = DispatchTestHarness::new();
        let parent = DispatchTestHarness::make_txid(1);
        assert_eq!(h.create_tx(parent, 2).status, STATUS_OK);
        let pk = TxKey { txid: parent };
        let c1 = [0xA1u8; 32];
        let c2 = [0xB2u8; 32];
        h.engine.append_conflicting_child(&pk, c1).unwrap();
        h.engine.append_conflicting_child(&pk, c2).unwrap();

        // [count=1][parent][c1]
        let payload = crate::protocol::codec::encode_conflicting_child_pair_batch(&[(parent, c1)]);
        let resp = h.request(OP_REMOVE_CONFLICTING_CHILD_BATCH, payload);
        assert_eq!(resp.status, STATUS_OK);

        let remaining = h.engine.read_conflicting_children(&pk).unwrap();
        assert_eq!(
            remaining,
            vec![c2],
            "c1 removed via the batch op, c2 remains"
        );

        // Idempotent: removing c1 again still succeeds, list unchanged.
        let payload2 = crate::protocol::codec::encode_conflicting_child_pair_batch(&[(parent, c1)]);
        let resp2 = h.request(OP_REMOVE_CONFLICTING_CHILD_BATCH, payload2);
        assert_eq!(resp2.status, STATUS_OK);
        assert_eq!(h.engine.read_conflicting_children(&pk).unwrap(), vec![c2]);
    }

