    // -----------------------------------------------------------------------
    // 5n. Create then Get — all fields round-trip
    // -----------------------------------------------------------------------

    #[test]
    fn dispatch_create_then_get_all_fields() {
        let h = DispatchTestHarness::new();
        let txid = DispatchTestHarness::make_txid(40);

        // Create 1 tx with 3 UTXOs
        let resp = h.create_tx(txid, 3);
        assert_eq!(resp.status, STATUS_OK);

        // Get it back with ALL_METADATA mask
        let get_payload = encode_get_batch(FieldMask::ALL_METADATA, &[txid]);
        let resp = h.request(OP_GET_BATCH, get_payload);
        assert_eq!(resp.status, STATUS_OK);

        let results = decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].status, 0, "expected found (status=0)");

        // Decode metadata fields in order:
        // tx_version(4) + locktime(4) + fee(8) + size_in_bytes(8) + extended_size(8)
        // + flags(1) + spending_height(4) + created_at(8) + spent_utxos(4) + pruned_utxos(4)
        // + utxo_count(4) + generation(4) + updated_at(8) + unmined_since(4)
        // + delete_at_height(4) + preserve_until(4) + external_ref(65)
        // + reassignment_count(1) + block_entry_count(1)
        let data = &results[0].data;
        let mut pos = 0;

        let tx_version = u32::from_le_bytes(data[pos..pos + 4].try_into().unwrap());
        pos += 4;
        assert_eq!(tx_version, 1);

        let locktime = u32::from_le_bytes(data[pos..pos + 4].try_into().unwrap());
        pos += 4;
        assert_eq!(locktime, 0);

        let fee = u64::from_le_bytes(data[pos..pos + 8].try_into().unwrap());
        pos += 8;
        assert_eq!(fee, 500);

        let size_in_bytes = u64::from_le_bytes(data[pos..pos + 8].try_into().unwrap());
        pos += 8;
        assert_eq!(size_in_bytes, 250);

        let _extended_size = u64::from_le_bytes(data[pos..pos + 8].try_into().unwrap());
        pos += 8;

        let _flags = data[pos];
        pos += 1;

        let _spending_height = u32::from_le_bytes(data[pos..pos + 4].try_into().unwrap());
        pos += 4;

        let _created_at = u64::from_le_bytes(data[pos..pos + 8].try_into().unwrap());
        pos += 8;

        let spent_utxos = u32::from_le_bytes(data[pos..pos + 4].try_into().unwrap());
        pos += 4;
        assert_eq!(spent_utxos, 0, "no UTXOs should be spent");

        let _pruned_utxos = u32::from_le_bytes(data[pos..pos + 4].try_into().unwrap());
        pos += 4;

        let utxo_count = u32::from_le_bytes(data[pos..pos + 4].try_into().unwrap());
        assert_eq!(utxo_count, 3, "utxo_count should be 3");
        let _ = pos; // silence unused warning
    }

    #[test]
    fn dispatch_get_utxo_slots_round_trips_slot_region() {
        let h = DispatchTestHarness::new();
        let txid = DispatchTestHarness::make_txid(42);

        assert_eq!(h.create_tx(txid, 3).status, STATUS_OK);

        let resp = h.request(
            OP_GET_BATCH,
            encode_get_batch(FieldMask::UTXO_SLOTS, &[txid]),
        );
        assert_eq!(resp.status, STATUS_OK);
        let results = decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].status, STATUS_OK);

        let data = &results[0].data;
        let utxo_count = u32::from_le_bytes(data[0..4].try_into().unwrap());
        assert_eq!(utxo_count, 3);
        assert_eq!(data.len(), 4 + 3 * 69);

        let mut pos = 4;
        for i in 0..3u8 {
            let hash = &data[pos..pos + 32];
            pos += 32;
            let status = data[pos];
            pos += 1;
            let spending_data = &data[pos..pos + 36];
            pos += 36;

            assert_eq!(hash[0], i);
            assert_eq!(hash[1], 0);
            assert_eq!(status, crate::record::UTXO_UNSPENT);
            assert_eq!(spending_data, &[0u8; 36]);
        }
    }

    /// R-044 (GH-06 / GH-09) regression: an active streaming-blob
    /// upload session whose cumulative `bytes_received` would exceed
    /// the configured per-stream byte cap MUST be aborted with
    /// `ERR_STREAM_INVARIANT` (wire code 34) — the server must not accept
    /// the chunk and must not let the counter grow unbounded. Pre-fix the
    /// per-stream counter incremented on every chunk with no upper bound,
    /// so a single connection could write multi-terabyte blobs by sending
    /// 4 KiB chunks indefinitely.
    ///
    /// Test installs a 1024-byte cap on the connection state so we can
    /// exercise the rejection path without allocating gigabytes of test data.
    #[test]
    fn stream_chunk_aborts_when_cumulative_bytes_exceed_cap() {
        use crate::protocol::codec::encode_stream_chunk;
        use crate::protocol::opcodes::OP_STREAM_CHUNK;
        use crate::storage::blobstore::{BlobStore, MemoryBlobStore};

        let h = DispatchTestHarness::new();
        let blob_store: std::sync::Arc<dyn BlobStore> = std::sync::Arc::new(MemoryBlobStore::new());
        let txid = DispatchTestHarness::make_txid(0xCA);

        // Hold a single ConnectionState across two chunks, since the
        // active-stream session lives in conn_state and per-chunk
        // routing through handle_request is what production does.
        let mut conn_state =
            crate::server::ConnectionState::new().with_max_stream_total_bytes(1024);

        // Chunk 1: 800 bytes at offset 0 — under the 1024-byte cap.
        let chunk1 = vec![0xAAu8; 800];
        let req1 = RequestFrame {
            request_id: 1,
            op_code: OP_STREAM_CHUNK,
            flags: 0,
            payload: encode_stream_chunk(&txid, 0, &chunk1).into(),
        };
        let resp1 = handle_request(
            &req1,
            &h.engine,
            8192,
            None,
            None,
            &mut conn_state,
            Some(&*blob_store),
        );
        assert_eq!(
            resp1.status,
            STATUS_OK,
            "first chunk under the cap must succeed; payload: {:?}",
            String::from_utf8_lossy(&resp1.payload),
        );

        // Chunk 2: 300 bytes at offset 800 — pushes total to 1100,
        // exceeding the 1024-byte cap. MUST be rejected with wire code
        // ERR_STREAM_INVARIANT(34) (the cap check at handle_stream_chunk
        // returns ERR_STREAM_INVARIANT, not ERR_INTERNAL) and a
        // "exceeds maximum" message in the payload, and the stream session
        // must be removed.
        let chunk2 = vec![0xBBu8; 300];
        let req2 = RequestFrame {
            request_id: 2,
            op_code: OP_STREAM_CHUNK,
            flags: 0,
            payload: encode_stream_chunk(&txid, 800, &chunk2).into(),
        };
        let resp2 = handle_request(
            &req2,
            &h.engine,
            8192,
            None,
            None,
            &mut conn_state,
            Some(&*blob_store),
        );
        assert_eq!(
            resp2.status, STATUS_ERROR,
            "second chunk that pushes total over the cap must be rejected",
        );
        let (code, msg) = crate::protocol::codec::decode_error_payload(&resp2.payload)
            .expect("cap rejection must carry a typed [code:2][msg] error payload");
        assert_eq!(
            code, ERR_STREAM_INVARIANT,
            "byte-cap rejection must use wire code ERR_STREAM_INVARIANT(34); got {code}",
        );
        assert!(
            msg.contains("exceeds maximum"),
            "rejection must include the cap-exceeded reason; got: {msg}",
        );
        assert!(
            !conn_state.streams.contains_key(&txid),
            "stream session must be removed after exceeding the cap",
        );
    }

    /// REL-116: `OP_STREAM_END` whose declared `total_size` does not match the
    /// bytes actually streamed MUST be rejected with wire code
    /// `ERR_STREAM_INVARIANT(34)` (the declared-size-mismatch branch in
    /// `handle_stream_end`), the stream session MUST be removed, and the
    /// partially-written `.tmp` upload artefact MUST be cleaned up (the writer
    /// is `abort`ed). A real `FileBlobStore` is used so the `.tmp` cleanup is
    /// observable on disk, not just inferred from the in-memory map.
    #[test]
    fn stream_end_size_mismatch_aborts_and_cleans_tmp() {
        use crate::protocol::codec::{
            decode_error_payload, encode_stream_chunk, encode_stream_end,
        };
        use crate::protocol::opcodes::{OP_STREAM_CHUNK, OP_STREAM_END};
        use crate::storage::blobstore::{BlobStore, FileBlobStore};
        use std::path::Path;

        // Recursively count files under `dir` whose name ends in ".tmp".
        fn count_tmp_files(dir: &Path) -> usize {
            let mut n = 0;
            let entries = match std::fs::read_dir(dir) {
                Ok(e) => e,
                Err(_) => return 0,
            };
            for entry in entries.flatten() {
                let path = entry.path();
                if path.is_dir() {
                    n += count_tmp_files(&path);
                } else if path
                    .file_name()
                    .and_then(|s| s.to_str())
                    .is_some_and(|s| s.ends_with(".tmp"))
                {
                    n += 1;
                }
            }
            n
        }

        let h = DispatchTestHarness::new();
        let tmp = tempfile::TempDir::new().unwrap();
        let blob_store: std::sync::Arc<dyn BlobStore> =
            std::sync::Arc::new(FileBlobStore::new(tmp.path(), 2));
        let mut conn_state = crate::server::ConnectionState::new();
        let txid = DispatchTestHarness::make_txid(0x7E);

        // Stream 10 bytes across one chunk — opens the stream and writes a
        // `.tmp` artefact to the blob store.
        let chunk = vec![0x42u8; 10];
        let chunk_req = RequestFrame {
            request_id: 1,
            op_code: OP_STREAM_CHUNK,
            flags: 0,
            payload: encode_stream_chunk(&txid, 0, &chunk).into(),
        };
        let chunk_resp = handle_request(
            &chunk_req,
            &h.engine,
            8192,
            None,
            None,
            &mut conn_state,
            Some(&*blob_store),
        );
        assert_eq!(
            chunk_resp.status,
            STATUS_OK,
            "the 10-byte chunk must be accepted; payload: {:?}",
            String::from_utf8_lossy(&chunk_resp.payload),
        );
        assert!(
            conn_state.streams.contains_key(&txid),
            "stream session must be live after the chunk",
        );
        assert_eq!(
            count_tmp_files(tmp.path()),
            1,
            "the in-progress stream must have one .tmp artefact on disk",
        );

        // STREAM_END declares 99 bytes, but only 10 were received — the
        // declared-size-mismatch branch must fire.
        let end_req = RequestFrame {
            request_id: 2,
            op_code: OP_STREAM_END,
            flags: 0,
            payload: encode_stream_end(&txid, 99).into(),
        };
        let end_resp = handle_request(
            &end_req,
            &h.engine,
            8192,
            None,
            None,
            &mut conn_state,
            Some(&*blob_store),
        );
        assert_eq!(end_resp.status, STATUS_ERROR);
        let (code, msg) = decode_error_payload(&end_resp.payload)
            .expect("size-mismatch rejection must carry a typed [code:2][msg] payload");
        assert_eq!(
            code, ERR_STREAM_INVARIANT,
            "declared-size mismatch must use wire code ERR_STREAM_INVARIANT(34); got {code}",
        );
        assert!(
            msg.contains("size mismatch"),
            "rejection must explain the size mismatch; got: {msg}",
        );

        // The session is gone and the partial writer was aborted, so the
        // `.tmp` artefact must be cleaned up — no orphaned upload debris.
        assert!(
            !conn_state.streams.contains_key(&txid),
            "stream session must be removed after the size-mismatch abort",
        );
        assert_eq!(
            count_tmp_files(tmp.path()),
            0,
            "the aborted stream's .tmp artefact must be removed from disk",
        );
        // And no committed blob exists for the txid.
        assert!(
            !blob_store.exists(&txid).unwrap(),
            "a size-mismatched stream must not finalize a blob",
        );
    }

    /// H-1/LM-1: a connection may hold at most
    /// `max_active_streams_per_connection` concurrent in-progress streams.
    /// Opening one more (a fresh txid) is rejected with `ERR_RATE_LIMITED`
    /// while the existing streams stay intact, and the rejected open must
    /// not leak a session into the map.
    #[test]
    fn stream_chunk_rejects_new_stream_past_concurrent_cap() {
        use crate::protocol::codec::{decode_error_payload, encode_stream_chunk};
        use crate::protocol::opcodes::{ERR_RATE_LIMITED, OP_STREAM_CHUNK};
        use crate::storage::blobstore::{BlobStore, MemoryBlobStore};

        let h = DispatchTestHarness::new();
        let blob_store: std::sync::Arc<dyn BlobStore> = std::sync::Arc::new(MemoryBlobStore::new());

        const CAP: usize = 4;
        let mut conn_state = crate::server::ConnectionState::new().with_max_active_streams(CAP);

        // Helper: open a new stream by sending one chunk at offset 0.
        let open_stream =
            |conn_state: &mut crate::server::ConnectionState, n: u8| -> ResponseFrame {
                let txid = DispatchTestHarness::make_txid(n);
                let req = RequestFrame {
                    request_id: n as u64,
                    op_code: OP_STREAM_CHUNK,
                    flags: 0,
                    payload: encode_stream_chunk(&txid, 0, &[0xABu8; 8]).into(),
                };
                handle_request(
                    &req,
                    &h.engine,
                    8192,
                    None,
                    None,
                    conn_state,
                    Some(&*blob_store),
                )
            };

        // Open exactly CAP distinct streams — all must succeed.
        for n in 0..CAP as u8 {
            let resp = open_stream(&mut conn_state, n);
            assert_eq!(
                resp.status,
                STATUS_OK,
                "stream {n} under the cap must be accepted; payload: {:?}",
                String::from_utf8_lossy(&resp.payload),
            );
        }
        assert_eq!(
            conn_state.streams.len(),
            CAP,
            "exactly CAP streams must be open before the rejection",
        );

        // The CAP+1-th distinct stream must be rejected with ERR_RATE_LIMITED.
        let over_txid = DispatchTestHarness::make_txid(CAP as u8);
        let resp = open_stream(&mut conn_state, CAP as u8);
        assert_eq!(
            resp.status, STATUS_ERROR,
            "opening past the concurrent-stream cap must be rejected",
        );
        let (code, msg) = decode_error_payload(&resp.payload).expect("typed error payload");
        assert_eq!(
            code, ERR_RATE_LIMITED,
            "over-cap stream open must surface ERR_RATE_LIMITED, got msg: {msg}",
        );

        // The rejected open must NOT have leaked a session (no fd/tmp would
        // have been allocated — `begin_stream` is never reached).
        assert!(
            !conn_state.streams.contains_key(&over_txid),
            "rejected over-cap stream must not appear in the session map",
        );
        assert_eq!(
            conn_state.streams.len(),
            CAP,
            "existing streams must be unaffected by the rejected open",
        );

        // An existing stream can still receive further chunks (offset 8).
        let txid0 = DispatchTestHarness::make_txid(0);
        let req = RequestFrame {
            request_id: 100,
            op_code: OP_STREAM_CHUNK,
            flags: 0,
            payload: encode_stream_chunk(&txid0, 8, &[0xCDu8; 4]).into(),
        };
        let resp = handle_request(
            &req,
            &h.engine,
            8192,
            None,
            None,
            &mut conn_state,
            Some(&*blob_store),
        );
        assert_eq!(
            resp.status, STATUS_OK,
            "existing stream must keep accepting chunks after an over-cap reject",
        );
    }

    /// H-1/LM-1: a `max_active_streams` of `0` disables the concurrent-stream
    /// cap entirely — many distinct streams open without rejection.
    #[test]
    fn stream_chunk_concurrent_cap_zero_disables_limit() {
        use crate::protocol::codec::encode_stream_chunk;
        use crate::protocol::opcodes::OP_STREAM_CHUNK;
        use crate::storage::blobstore::{BlobStore, MemoryBlobStore};

        let h = DispatchTestHarness::new();
        let blob_store: std::sync::Arc<dyn BlobStore> = std::sync::Arc::new(MemoryBlobStore::new());
        let mut conn_state = crate::server::ConnectionState::new().with_max_active_streams(0);

        for n in 0..32u8 {
            let txid = DispatchTestHarness::make_txid(n);
            let req = RequestFrame {
                request_id: n as u64,
                op_code: OP_STREAM_CHUNK,
                flags: 0,
                payload: encode_stream_chunk(&txid, 0, &[0x11u8; 2]).into(),
            };
            let resp = handle_request(
                &req,
                &h.engine,
                8192,
                None,
                None,
                &mut conn_state,
                Some(&*blob_store),
            );
            assert_eq!(
                resp.status, STATUS_OK,
                "with cap disabled, stream {n} must be accepted",
            );
        }
        assert_eq!(conn_state.streams.len(), 32, "all 32 streams must be open");
    }

    /// H-2: `reap_idle_streams` aborts streams whose `last_activity` is older
    /// than the idle timeout (removing their tmp files via `abort`), leaves a
    /// recently-active stream untouched, and a subsequent op on a reaped
    /// stream id is treated as a fresh/unknown stream — not the old session.
    #[test]
    fn reap_idle_streams_removes_only_stale_sessions() {
        use crate::protocol::codec::{
            decode_error_payload, encode_stream_chunk, encode_stream_end,
        };
        use crate::protocol::opcodes::{ERR_STREAM_NOT_FOUND, OP_STREAM_CHUNK, OP_STREAM_END};
        use crate::storage::blobstore::{BlobStore, MemoryBlobStore};
        use std::time::{Duration, Instant};

        let h = DispatchTestHarness::new();
        let blob_store: std::sync::Arc<dyn BlobStore> = std::sync::Arc::new(MemoryBlobStore::new());
        let mut conn_state = crate::server::ConnectionState::new()
            .with_stream_idle_timeout(Some(Duration::from_secs(30)));

        let stale_txid = DispatchTestHarness::make_txid(1);
        let fresh_txid = DispatchTestHarness::make_txid(2);

        // Open two streams.
        for txid in [stale_txid, fresh_txid] {
            let req = RequestFrame {
                request_id: 1,
                op_code: OP_STREAM_CHUNK,
                flags: 0,
                payload: encode_stream_chunk(&txid, 0, &[0x55u8; 4]).into(),
            };
            let resp = handle_request(
                &req,
                &h.engine,
                8192,
                None,
                None,
                &mut conn_state,
                Some(&*blob_store),
            );
            assert_eq!(resp.status, STATUS_OK, "stream open must succeed");
        }
        assert_eq!(conn_state.streams.len(), 2);

        // Backdate ONLY the stale stream's last_activity well past the
        // timeout; leave the fresh one current.
        if let Some(s) = conn_state.streams.get_mut(&stale_txid) {
            s.last_activity = Instant::now() - Duration::from_secs(120);
        }

        let reaped = conn_state.reap_idle_streams(Instant::now());
        assert_eq!(reaped, 1, "exactly the stale stream must be reaped");
        assert!(
            !conn_state.streams.contains_key(&stale_txid),
            "stale stream's map entry must be gone after reap",
        );
        assert!(
            conn_state.streams.contains_key(&fresh_txid),
            "fresh stream must survive the reap",
        );

        // OP_STREAM_END on the reaped stream id must report it as unknown —
        // the old session is gone, not silently resurrected.
        let end_req = RequestFrame {
            request_id: 9,
            op_code: OP_STREAM_END,
            flags: 0,
            payload: encode_stream_end(&stale_txid, 4).into(),
        };
        let resp = handle_stream_end(&end_req, &mut conn_state, None);
        assert_eq!(resp.status, STATUS_ERROR);
        let (code, _msg) = decode_error_payload(&resp.payload).expect("typed error payload");
        assert_eq!(
            code, ERR_STREAM_NOT_FOUND,
            "ending a reaped stream must surface ERR_STREAM_NOT_FOUND",
        );
    }

    /// H-2: a `None` idle timeout disables the reaper — a stream stamped far
    /// in the past survives `reap_idle_streams`.
    #[test]
    fn reap_idle_streams_disabled_keeps_all_sessions() {
        use crate::protocol::codec::encode_stream_chunk;
        use crate::protocol::opcodes::OP_STREAM_CHUNK;
        use crate::storage::blobstore::{BlobStore, MemoryBlobStore};
        use std::time::{Duration, Instant};

        let h = DispatchTestHarness::new();
        let blob_store: std::sync::Arc<dyn BlobStore> = std::sync::Arc::new(MemoryBlobStore::new());
        let mut conn_state = crate::server::ConnectionState::new().with_stream_idle_timeout(None);

        let txid = DispatchTestHarness::make_txid(7);
        let req = RequestFrame {
            request_id: 1,
            op_code: OP_STREAM_CHUNK,
            flags: 0,
            payload: encode_stream_chunk(&txid, 0, &[0x22u8; 4]).into(),
        };
        let resp = handle_request(
            &req,
            &h.engine,
            8192,
            None,
            None,
            &mut conn_state,
            Some(&*blob_store),
        );
        assert_eq!(resp.status, STATUS_OK);
        if let Some(s) = conn_state.streams.get_mut(&txid) {
            s.last_activity = Instant::now() - Duration::from_secs(86_400);
        }
        let reaped = conn_state.reap_idle_streams(Instant::now());
        assert_eq!(reaped, 0, "disabled reaper must not remove anything");
        assert!(
            conn_state.streams.contains_key(&txid),
            "stream must survive when the reaper is disabled",
        );
    }

    #[test]
    fn dispatch_external_create_binds_record_to_blob_digest() {
        let h = DispatchTestHarness::new();
        let blob_store = crate::storage::blobstore::MemoryBlobStore::new();
        let txid = DispatchTestHarness::make_txid(41);
        let blob_digest = blob_store
            .put(&txid, b"external transaction payload")
            .unwrap();

        let item = WireCreateItem {
            txid,
            tx_version: 1,
            locktime: 0,
            fee: 500,
            size_in_bytes: 123,
            extended_size: 123,
            is_coinbase: false,
            spending_height: 0,
            created_at: 1700000000000,
            flags: FLAG_EXTERNAL_BLOB,
            utxo_hashes: vec![[0xAB; 32]],
            cold_data: vec![],
            block_height: 0,
            mined_block_id: None,
            mined_block_height: None,
            mined_subtree_idx: None,
            parent_txids: vec![],
        };

        let resp =
            h.request_with_blob_store(OP_CREATE_BATCH, encode_create_batch(&[item]), &blob_store);
        assert_eq!(resp.status, STATUS_OK);

        let resp = h.request(
            OP_GET_BATCH,
            encode_get_batch(FieldMask::EXTERNAL_REF, &[txid]),
        );
        assert_eq!(resp.status, STATUS_OK);
        let results = decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].status, STATUS_OK);

        let data = &results[0].data;
        assert_eq!(data.len(), 65);
        assert_eq!(data[0], 1);
        assert_eq!(&data[1..33], &blob_digest.sha256);
        assert_eq!(
            u64::from_le_bytes(data[33..41].try_into().unwrap()),
            blob_digest.length
        );
        assert_ne!(&data[1..33], &txid);
    }

    #[test]
    fn delete_external_blob_missing_rejects_before_wal_and_mutation() {
        let mut h = DispatchTestHarness::new();
        let blob_store: Arc<dyn crate::storage::blobstore::BlobStore> =
            Arc::new(crate::storage::blobstore::MemoryBlobStore::new());
        h.engine.set_blob_store(blob_store.clone());

        let txid = DispatchTestHarness::make_txid(42);
        blob_store
            .put(&txid, b"external transaction payload")
            .unwrap();

        let item = WireCreateItem {
            txid,
            tx_version: 1,
            locktime: 0,
            fee: 500,
            size_in_bytes: 123,
            extended_size: 123,
            is_coinbase: false,
            spending_height: 0,
            created_at: 1700000000000,
            flags: FLAG_EXTERNAL_BLOB,
            utxo_hashes: vec![[0xBC; 32]],
            cold_data: vec![],
            block_height: 0,
            mined_block_id: None,
            mined_block_height: None,
            mined_subtree_idx: None,
            parent_txids: vec![],
        };
        let resp =
            h.request_with_blob_store(OP_CREATE_BATCH, encode_create_batch(&[item]), &*blob_store);
        assert_eq!(resp.status, STATUS_OK);

        blob_store.delete(&txid).unwrap();

        let resp = h.request(OP_DELETE_BATCH, encode_txid_batch(&[txid], &[]));
        assert_eq!(resp.status, STATUS_PARTIAL_ERROR);
        let errors = decode_sparse_errors(&resp.payload).unwrap();
        assert_eq!(errors.len(), 1);
        assert_eq!(errors[0].item_index, 0);
        assert_eq!(errors[0].error_code, ERR_STORAGE_IO);
        assert!(
            String::from_utf8_lossy(&errors[0].error_data)
                .contains("external blob snapshot missing")
        );

        let resp = h.request(
            OP_GET_BATCH,
            encode_get_batch(FieldMask::TX_VERSION, &[txid]),
        );
        assert_eq!(resp.status, STATUS_OK);
        let results = decode_get_response(&resp.payload).unwrap();
        assert_eq!(
            results[0].status, STATUS_OK,
            "delete must not remove the record when its external blob snapshot is missing"
        );
    }

    // -----------------------------------------------------------------------
    // Streamed external blob replication — close create-batch data loss
    // -----------------------------------------------------------------------

    /// Build the `ReplicaOp::Create` metadata_bytes for an EXTERNAL record the
    /// way `handle_create_batch`'s Phase-3 loop does: 46-byte core header,
    /// 24-byte lifecycle block, `block_height(4)` + `block_count(1)=0` +
    /// `parent_count(2)=0`, then the 65-byte `ExternalRef` tail. The receiver
    /// reconstructs the EXTERNAL record (and its `ExternalRef`) from exactly
    /// this layout.
    fn external_create_metadata_bytes(digest_sha256: [u8; 32], total_size: u64) -> Vec<u8> {
        let mut m = Vec::with_capacity(140);
        // Core 46 bytes.
        m.extend_from_slice(&1u32.to_le_bytes()); // tx_version
        m.extend_from_slice(&0u32.to_le_bytes()); // locktime
        m.extend_from_slice(&0u64.to_le_bytes()); // fee
        m.extend_from_slice(&total_size.to_le_bytes()); // size_in_bytes
        m.extend_from_slice(&total_size.to_le_bytes()); // extended_size
        m.push(0); // is_coinbase
        m.extend_from_slice(&0u32.to_le_bytes()); // spending_height
        m.extend_from_slice(&0u64.to_le_bytes()); // created_at
        m.push(0); // wire flags
        // Lifecycle 24 bytes.
        m.extend_from_slice(&0u32.to_le_bytes()); // generation
        m.extend_from_slice(&0u64.to_le_bytes()); // updated_at
        m.extend_from_slice(&0u32.to_le_bytes()); // unmined_since
        m.extend_from_slice(&0u32.to_le_bytes()); // delete_at_height
        m.extend_from_slice(&0u32.to_le_bytes()); // preserve_until
        // Extended: block_height + block_count(0) + parent_count(0).
        m.extend_from_slice(&0u32.to_le_bytes()); // block_height
        m.push(0); // mined_block_infos count
        m.extend_from_slice(&0u16.to_le_bytes()); // parent_txids count
        // ExternalRef (65 bytes): store_type + content_hash + total_size +
        // input_count + output_count + inputs_offset + outputs_offset.
        m.push(1); // store_type
        m.extend_from_slice(&digest_sha256);
        m.extend_from_slice(&total_size.to_le_bytes());
        m.extend_from_slice(&0u32.to_le_bytes()); // input_count
        m.extend_from_slice(&0u32.to_le_bytes()); // output_count
        m.extend_from_slice(&0u64.to_le_bytes()); // inputs_offset
        m.extend_from_slice(&0u64.to_le_bytes()); // outputs_offset
        m
    }

    /// Headline regression: a STREAMED external blob (`OP_STREAM_*` wrote the
    /// bytes to the master's blob store; the create's wire `cold_data` is
    /// empty) must be shipped INLINE to the replica. Before the fix the master
    /// shipped `cold_data: None`, leaving the replica with a live EXTERNAL
    /// record + ExternalRef but no blob — payload lost on promotion.
    #[test]
    fn streamed_external_create_ships_blob_to_replica() {
        use crate::record::ExternalRef;
        use crate::replication::receiver::apply_op;
        use crate::storage::blobstore::{BlobStore, MemoryBlobStore};

        let txid = DispatchTestHarness::make_txid(91);
        let payload = b"streamed external transaction payload bytes".to_vec();

        // Master: blob arrived via OP_STREAM_*, so it is already in the store
        // and the create carries an EMPTY inline cold_data. `DispatchTestHarness`
        // holds the non-reentrant global metrics test-lock for its lifetime, so
        // the master must be dropped before the replica harness is built —
        // scope it and hand the emitted op out of the block.
        let op = {
            let mut m = DispatchTestHarness::new();
            let master_store: Arc<dyn BlobStore> = Arc::new(MemoryBlobStore::new());
            m.engine.set_blob_store(master_store.clone());
            let digest = master_store.put(&txid, &payload).unwrap();

            let item = WireCreateItem {
                txid,
                tx_version: 1,
                locktime: 0,
                fee: 0,
                size_in_bytes: payload.len() as u64,
                extended_size: payload.len() as u64,
                is_coinbase: false,
                spending_height: 0,
                created_at: 1700000000000,
                flags: FLAG_EXTERNAL_BLOB,
                utxo_hashes: vec![[0xAB; 32]],
                cold_data: vec![], // streamed — empty inline body
                block_height: 0,
                mined_block_id: None,
                mined_block_height: None,
                mined_subtree_idx: None,
                parent_txids: vec![],
            };
            let resp = m.request_with_blob_store(
                OP_CREATE_BATCH,
                encode_create_batch(&[item]),
                &*master_store,
            );
            assert_eq!(
                resp.status, STATUS_OK,
                "master external create must succeed"
            );

            // Capture the cold_data the master's replica-op builder produces —
            // this is the exact production decision (`item.cold_data` is empty,
            // so the fix reads the blob back from the master store).
            let cold_data = match create_repl_cold_data(&m.engine, &txid, true, &[]) {
                CreateReplColdData::Ship(cold_data) => cold_data,
                CreateReplColdData::SkipReplicationBlobMissing => {
                    panic!("blob is present + pinned; must ship it, not skip replication")
                }
            };
            assert_eq!(
                cold_data,
                Some(payload.clone()),
                "streamed external create must ship the blob inline (was None before the fix)",
            );

            // Build the full ReplicaOp::Create the master emits.
            ReplicaOp::Create {
                tx_key: TxKey { txid },
                metadata_bytes: external_create_metadata_bytes(digest.sha256, digest.length),
                utxo_hashes: vec![[0xAB; 32]],
                cold_data,
                is_external: true,
            }
        };

        // Apply the captured op to a fresh replica.
        let mut r = DispatchTestHarness::new();
        let replica_store: Arc<dyn BlobStore> = Arc::new(MemoryBlobStore::new());
        r.engine.set_blob_store(replica_store.clone());
        apply_op(&r.engine, &op).expect("replica apply of streamed external create");

        // The replica now resolves the external payload — before the fix this
        // returned BlobNotFound.
        let got = r
            .engine
            .read_cold_data(&TxKey { txid })
            .expect("replica must resolve the external blob after apply");
        assert_eq!(
            got, payload,
            "replica external payload must match the master"
        );

        // Sanity: the replica record really is EXTERNAL with the master's ref
        // (content_hash == SHA256(payload)).
        let meta = r.engine.read_metadata(&TxKey { txid }).unwrap();
        assert!(meta.flags.contains(crate::record::TxFlags::EXTERNAL));
        let ext: ExternalRef = meta.external_ref;
        let ch = ext.content_hash;
        let mut hasher = <sha2::Sha256 as sha2::Digest>::new();
        sha2::Digest::update(&mut hasher, &payload);
        let expected: [u8; 32] = sha2::Digest::finalize(hasher).into();
        assert_eq!(ch, expected);
    }

    /// Regression guard: a NON-external create still follows the historical
    /// inline rule — empty wire body → `None`, non-empty → `Some(bytes)`.
    #[test]
    fn non_external_create_repl_cold_data_follows_inline_rule() {
        let h = DispatchTestHarness::new();
        let txid = DispatchTestHarness::make_txid(92);

        match create_repl_cold_data(&h.engine, &txid, false, &[]) {
            CreateReplColdData::Ship(None) => {}
            CreateReplColdData::Ship(Some(v)) => {
                panic!("empty non-external body must ship None, got {v:?}")
            }
            CreateReplColdData::SkipReplicationBlobMissing => {
                panic!("non-external create must never skip replication")
            }
        }

        let body = vec![0x01, 0x02, 0x03, 0x04];
        match create_repl_cold_data(&h.engine, &txid, false, &body) {
            CreateReplColdData::Ship(Some(v)) => assert_eq!(v, body),
            CreateReplColdData::Ship(None) => panic!("non-empty body must ship Some"),
            CreateReplColdData::SkipReplicationBlobMissing => {
                panic!("non-external create must never skip replication")
            }
        }
    }

    /// Degraded path: an EXTERNAL item whose blob is absent from the master
    /// store must NOT ship a blob-less Create — the builder signals
    /// skip-replication (caller logs + skips the repl op while keeping the
    /// master's own create reported as success). This reproduces the
    /// should-never-happen inconsistency directly at the builder, since the
    /// create-path digest check makes the missing-blob state unreachable
    /// through the full dispatch handler.
    #[test]
    fn external_create_missing_blob_skips_replication_not_client_error() {
        use crate::storage::blobstore::{BlobStore, MemoryBlobStore};

        let txid = DispatchTestHarness::make_txid(93);

        // Blob store present but the blob is absent (intentionally not put).
        // `DispatchTestHarness` holds the global metrics test-lock for its
        // lifetime, so each harness must be dropped before the next is built
        // (the lock is not reentrant) — scope them.
        {
            let mut h = DispatchTestHarness::new();
            let store: Arc<dyn BlobStore> = Arc::new(MemoryBlobStore::new());
            h.engine.set_blob_store(store.clone());
            match create_repl_cold_data(&h.engine, &txid, true, &[]) {
                CreateReplColdData::SkipReplicationBlobMissing => {}
                CreateReplColdData::Ship(v) => {
                    panic!("missing external blob must not ship a Create, got {v:?}")
                }
            }
        }

        // No blob store configured at all: the same external item must also
        // skip (never ship a blob-less external Create).
        {
            let h2 = DispatchTestHarness::new();
            match create_repl_cold_data(&h2.engine, &txid, true, &[]) {
                CreateReplColdData::SkipReplicationBlobMissing => {}
                CreateReplColdData::Ship(v) => {
                    panic!("no blob store must not ship an external Create, got {v:?}")
                }
            }
        }
    }

    // -----------------------------------------------------------------------
    // 5o. Create, Spend, then Get — verify spent_utxos=1
    // -----------------------------------------------------------------------

    #[test]
    fn dispatch_create_spend_then_get() {
        let h = DispatchTestHarness::new();
        let txid = DispatchTestHarness::make_txid(50);

        // Create with 3 UTXOs
        let resp = h.create_tx(txid, 3);
        assert_eq!(resp.status, STATUS_OK);

        // Spend UTXO at vout=0
        let mut utxo_hash = [0u8; 32];
        utxo_hash[0] = 0; // matches the hash generated in create_tx for vout=0
        let spend_params = SpendBatchParams {
            ignore_conflicting: false,
            ignore_locked: false,
            current_block_height: 1000,
            block_height_retention: 288,
        };
        let spend_item = WireSpendItem {
            txid,
            vout: 0,
            utxo_hash,
            spending_data: {
                let mut sd = [0u8; 36];
                sd[0] = 0xAB;
                sd[32..36].copy_from_slice(&1u32.to_le_bytes());
                sd
            },
        };
        let spend_payload = encode_spend_batch(&spend_params, &[spend_item]);
        let resp = h.request(OP_SPEND_BATCH, spend_payload);
        assert_eq!(resp.status, STATUS_OK);

        // Get and verify spent_utxos=1
        let get_payload = encode_get_batch(FieldMask::SPENT_UTXOS, &[txid]);
        let resp = h.request(OP_GET_BATCH, get_payload);
        assert_eq!(resp.status, STATUS_OK);

        let results = decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].status, 0);
        let spent = u32::from_le_bytes(results[0].data[0..4].try_into().unwrap());
        assert_eq!(spent, 1, "spent_utxos should be 1 after spending 1 UTXO");
    }

