    // -----------------------------------------------------------------------
    // 6t. Batch too large rejected
    // -----------------------------------------------------------------------

    #[test]
    fn dispatch_batch_too_large_rejected() {
        let h = DispatchTestHarness::new();

        // Build a create batch with 20 items, but set max_batch_size=10
        let items: Vec<WireCreateItem> = (0..20u8)
            .map(|i| {
                let txid = DispatchTestHarness::make_txid(100 + i);
                let mut hash = [0u8; 32];
                hash[0] = i;
                WireCreateItem {
                    txid,
                    tx_version: 1,
                    locktime: 0,
                    fee: 100,
                    size_in_bytes: 100,
                    extended_size: 100,
                    is_coinbase: false,
                    spending_height: 0,
                    created_at: 1700000000000,
                    flags: 0,
                    utxo_hashes: vec![hash],
                    cold_data: vec![],
                    block_height: 0,
                    mined_block_id: None,
                    mined_block_height: None,
                    mined_subtree_idx: None,
                    parent_txids: vec![],
                }
            })
            .collect();
        let payload = encode_create_batch(&items);
        let resp = h.request_with_max_batch(OP_CREATE_BATCH, payload, 10);
        assert_eq!(resp.status, STATUS_ERROR);
        let (code, msg) = decode_error_payload(&resp.payload).unwrap();
        assert_eq!(code, ERR_PAYLOAD_MALFORMED);
        // The decoder rejects the over-size batch BEFORE allocation, so the
        // error message now identifies the configured limit explicitly. We
        // verify both the count (20) and the configured cap (10) appear so
        // a regression that loses either value would fail this assertion.
        assert!(
            msg.contains("exceeds max_batch_size 10") && msg.contains("20"),
            "expected 'count 20 exceeds max_batch_size 10' in: {msg}"
        );
    }

    // -----------------------------------------------------------------------
    // WAL-first regression tests — redo fsynced before engine mutation
    // -----------------------------------------------------------------------

    /// Test harness with redo log support for crash-recovery testing.
    ///
    /// Like [`DispatchTestHarness`], holds `metrics_test_lock` for its
    /// lifetime: dispatch requests issued through this harness mutate the
    /// process-wide `DISPATCH_METRICS` singleton, and without the guard
    /// they race the metrics-delta tests (e.g.
    /// `prometheus_emits_operations_total_with_labels`, which compares a
    /// rendered snapshot against live counters). Tests using this harness
    /// must NOT take `metrics_test_lock()` themselves (stdlib `Mutex` is
    /// not re-entrant; doing so deadlocks on the same thread).
    struct RedoDispatchHarness {
        engine: Engine,
        redo_log: Arc<Mutex<crate::redo::RedoLog>>,
        data_dev: Arc<MemoryDevice>,
        redo_dev: Arc<MemoryDevice>,
        _metrics_guard: std::sync::MutexGuard<'static, ()>,
    }

    struct CountingSyncDevice {
        inner: Arc<MemoryDevice>,
        sync_count: std::sync::atomic::AtomicUsize,
    }

    impl CountingSyncDevice {
        fn new(size: u64, alignment: usize) -> Self {
            Self {
                inner: Arc::new(MemoryDevice::new(size, alignment).unwrap()),
                sync_count: std::sync::atomic::AtomicUsize::new(0),
            }
        }

        fn sync_count(&self) -> usize {
            self.sync_count.load(std::sync::atomic::Ordering::SeqCst)
        }
    }

    impl BlockDevice for CountingSyncDevice {
        fn pread(&self, buf: &mut [u8], offset: u64) -> crate::device::Result<usize> {
            self.inner.pread(buf, offset)
        }

        fn pwrite(&self, buf: &[u8], offset: u64) -> crate::device::Result<usize> {
            self.inner.pwrite(buf, offset)
        }

        fn alignment(&self) -> usize {
            self.inner.alignment()
        }

        fn size(&self) -> u64 {
            self.inner.size()
        }

        fn sync(&self) -> crate::device::Result<()> {
            self.sync_count
                .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
            self.inner.sync()
        }
    }

    #[test]
    fn redo_group_commit_coalesces_concurrent_dispatch_writers() {
        let redo_dev = Arc::new(CountingSyncDevice::new(4 * 1024 * 1024, 4096));
        let redo_log = Arc::new(Mutex::new(
            RedoLog::open(redo_dev.clone() as Arc<dyn BlockDevice>, 0, 4 * 1024 * 1024)
                .expect("redo log opens"),
        ));
        // Capture sync count after open — F-G4-001's initial header
        // write at open also syncs, and is not part of the group-commit
        // accounting under test.
        let baseline_syncs = redo_dev.sync_count();
        let barrier = Arc::new(std::sync::Barrier::new(3));
        // Bare engine with no per-store redo so the writers take the
        // single-handle group-commit path under test.
        let engine = Arc::new(bare_engine_for_redo_tests());

        let spawn_writer = |byte: u8| {
            let redo_log = Arc::clone(&redo_log);
            let barrier = Arc::clone(&barrier);
            let engine = Arc::clone(&engine);
            std::thread::spawn(move || {
                let tx_key = TxKey { txid: [byte; 32] };
                barrier.wait();
                write_redo_ops_with_group_window(
                    &engine,
                    Some(redo_log.as_ref()),
                    &[RedoOp::Delete {
                        tx_key,
                        record_offset: u64::from(byte) * 4096,
                        record_size: 4096,
                    }],
                    Duration::from_millis(50),
                )
                .expect("grouped redo write succeeds")
            })
        };

        let first = spawn_writer(1);
        let second = spawn_writer(2);
        barrier.wait();

        let mut ranges = vec![
            first.join().expect("first writer joins"),
            second.join().expect("second writer joins"),
        ];
        ranges.sort_by_key(|range| range.0);

        assert_eq!(ranges, vec![(1, 1), (2, 2)]);
        // PERF #5: flush() now folds the F-G4-001 header pwrite into the SAME
        // fsync as the entries (one device.sync() flushes both blocks), so an
        // effective flush is ONE sync. Group commit collapses the two
        // concurrent writers into one effective flush, so the post-open delta
        // is exactly 1 sync.
        assert_eq!(
            redo_dev.sync_count() - baseline_syncs,
            1,
            "concurrent dispatch writers should share one effective flush \
             (one fsync covering entries + folded header under PERF #5)"
        );

        let entries = redo_log.lock().recover().expect("recover grouped entries");
        assert_eq!(entries.len(), 2);
        assert_eq!(entries[0].sequence, 1);
        assert_eq!(entries[1].sequence, 2);
    }

    /// PERF: the 200 µs group-commit window (`REDO_GROUP_COMMIT_WINDOW`) is a
    /// `thread::sleep` before every redo flush. It only buys cross-connection
    /// fsync coalescing for TINY concurrent writes; for a write that already
    /// carries multiple ops the fsync is amortized over them, so the fixed
    /// wait is pure added latency — the per-call 200 µs floor that caps
    /// per-connection throughput (~5000 calls/s). `group_commit_window` skips
    /// the wait for batched writes and keeps it only for single-op writes.
    #[test]
    fn group_commit_window_skips_sleep_for_batched_writes() {
        // Batched writes (the real Teranode traffic: a 742-item CreateBatch
        // RPC, or a whole SpendBatch after target #2) skip the floor entirely.
        assert_eq!(group_commit_window(2), Duration::ZERO);
        assert_eq!(group_commit_window(742), Duration::ZERO);
        // A single-op write keeps the window — the only case where waiting for
        // a concurrent writer to coalesce into the same fsync can pay off.
        assert_eq!(group_commit_window(1), REDO_GROUP_COMMIT_WINDOW);
        // Empty writes never flush, so the window is irrelevant; ZERO is fine.
        assert_eq!(group_commit_window(0), Duration::ZERO);
    }

    /// PERF (target #2): a SpendBatch RPC spanning many distinct txid-groups
    /// must be made durable with ONE redo flush for the whole RPC, not one
    /// flush per txid-group. Pre-fix `handle_spend_batch` calls
    /// `write_replicated_redo_ops` inside the `for (txid, group)` loop, so N
    /// groups => N flushes (each = a 200 µs group-commit sleep + redo-lock
    /// cycle + 2 device syncs). This counts device syncs on the redo device:
    /// one effective flush == 2 syncs (entries + persisted header under
    /// F-G4-001), independent of group count.
    #[test]
    fn spend_batch_flushes_redo_once_per_rpc_not_per_txid_group() {
        let _g = metrics_test_lock();
        let data_dev = Arc::new(MemoryDevice::new(64 * 1024 * 1024, 4096).unwrap());
        let redo_dev = Arc::new(CountingSyncDevice::new(16 * 1024 * 1024, 4096));
        let alloc = SlotAllocator::new(data_dev.clone()).unwrap();
        let index = Index::new(10_000).unwrap();
        // Deliberately TINY stripe count so the N txids below are guaranteed to
        // collide on stripes (pigeonhole: N > stripe_count). The batched spend
        // path must dedup stripe locks before holding them across the single
        // flush — without dedup it self-deadlocks on the non-reentrant
        // per-stripe Mutex, so a hang here is also a regression signal.
        let engine = Engine::new(
            data_dev.clone() as Arc<dyn BlockDevice>,
            index,
            alloc,
            StripedLocks::new(16),
            DahIndex::new(),
            UnminedIndex::new(),
        );
        let redo_log = Arc::new(Mutex::new(
            RedoLog::open(
                redo_dev.clone() as Arc<dyn BlockDevice>,
                0,
                16 * 1024 * 1024,
            )
            .unwrap(),
        ));

        let request = |op: u16, payload: Vec<u8>| -> ResponseFrame {
            let req = RequestFrame {
                request_id: 1,
                op_code: op,
                flags: 0,
                payload: payload.into(),
            };
            let mut cs = crate::server::ConnectionState::new();
            handle_request(&req, &engine, 8192, None, Some(&redo_log), &mut cs, None)
        };

        // N distinct txids, each with 2 utxos. Spending only vout 0 of each
        // leaves the tx not-last-spent => no DAH secondary flush, isolating
        // the main spend redo flush count. N > stripe_count (16) forces
        // stripe collisions so the dedup-lock path is exercised.
        const N: usize = 24;
        let mk_txid = |k: usize| {
            let mut t = [0u8; 32];
            t[0] = 0xC0;
            t[1] = k as u8;
            t
        };
        let mk_hash = |k: usize, vout: u8| {
            let mut h = [0u8; 32];
            h[0] = 0xC0;
            h[1] = k as u8;
            h[2] = vout;
            h
        };

        let create_items: Vec<WireCreateItem> = (0..N)
            .map(|k| WireCreateItem {
                txid: mk_txid(k),
                tx_version: 1,
                locktime: 0,
                fee: 500,
                size_in_bytes: 250,
                extended_size: 0,
                is_coinbase: false,
                spending_height: 0,
                created_at: 1_700_000_000_000,
                flags: 0,
                utxo_hashes: vec![mk_hash(k, 0), mk_hash(k, 1)],
                cold_data: vec![],
                block_height: 0,
                mined_block_id: None,
                mined_block_height: None,
                mined_subtree_idx: None,
                parent_txids: vec![],
            })
            .collect();
        assert_eq!(
            request(OP_CREATE_BATCH, encode_create_batch(&create_items)).status,
            STATUS_OK,
            "seed creates must succeed"
        );

        let params = SpendBatchParams {
            ignore_conflicting: false,
            ignore_locked: false,
            current_block_height: 1000,
            block_height_retention: 0,
        };
        let spend_items: Vec<WireSpendItem> = (0..N)
            .map(|k| WireSpendItem {
                txid: mk_txid(k),
                vout: 0,
                utxo_hash: mk_hash(k, 0),
                spending_data: [0xD2; 36],
            })
            .collect();

        let syncs_before = redo_dev.sync_count();
        let resp = request(OP_SPEND_BATCH, encode_spend_batch(&params, &spend_items));
        let flush_syncs = redo_dev.sync_count() - syncs_before;

        assert_eq!(resp.status, STATUS_OK, "all spends should succeed");
        assert_eq!(
            flush_syncs, 1,
            "the whole {N}-txid-group SpendBatch RPC must be ONE effective redo \
             flush — one fsync (entries + folded header, PERF #5) — not one per \
             txid-group; got {flush_syncs} syncs",
        );
    }

    /// Parallel read fan-out for the spend validate phase must preserve exact
    /// per-item outcomes. Drives a batch above `READ_FANOUT_THRESHOLD` with a
    /// mix of valid spends, a UTXO-hash mismatch, and a not-found txid, then
    /// asserts the resulting on-device state and the single-flush contract —
    /// so the fanned `prepare_spend_multi` reads can't reorder, drop, or
    /// misclassify any item versus the old serial loop.
    #[test]
    fn spend_batch_parallel_validate_preserves_per_item_outcomes() {
        let _g = metrics_test_lock();
        let data_dev = Arc::new(MemoryDevice::new(64 * 1024 * 1024, 4096).unwrap());
        let redo_dev = Arc::new(CountingSyncDevice::new(16 * 1024 * 1024, 4096));
        let alloc = SlotAllocator::new(data_dev.clone()).unwrap();
        let index = Index::new(10_000).unwrap();
        let engine = Engine::new(
            data_dev.clone() as Arc<dyn BlockDevice>,
            index,
            alloc,
            StripedLocks::new(64),
            DahIndex::new(),
            UnminedIndex::new(),
        );
        let redo_log = Arc::new(Mutex::new(
            RedoLog::open(
                redo_dev.clone() as Arc<dyn BlockDevice>,
                0,
                16 * 1024 * 1024,
            )
            .unwrap(),
        ));

        let request = |op: u16, payload: Vec<u8>| -> ResponseFrame {
            let req = RequestFrame {
                request_id: 1,
                op_code: op,
                flags: 0,
                payload: payload.into(),
            };
            let mut cs = crate::server::ConnectionState::new();
            handle_request(&req, &engine, 8192, None, Some(&redo_log), &mut cs, None)
        };

        // N valid txids, each with 2 utxos. N is comfortably above
        // READ_FANOUT_THRESHOLD (8) so the parallel validate path is taken.
        const N: usize = 10;
        let mk_txid = |k: usize| {
            let mut t = [0u8; 32];
            t[0] = 0xA7;
            t[1] = k as u8;
            t
        };
        let mk_hash = |k: usize, vout: u8| {
            let mut h = [0u8; 32];
            h[0] = 0xA7;
            h[1] = k as u8;
            h[2] = vout;
            h
        };

        let create_items: Vec<WireCreateItem> = (0..N)
            .map(|k| WireCreateItem {
                txid: mk_txid(k),
                tx_version: 1,
                locktime: 0,
                fee: 500,
                size_in_bytes: 250,
                extended_size: 0,
                is_coinbase: false,
                spending_height: 0,
                created_at: 1_700_000_000_000,
                flags: 0,
                utxo_hashes: vec![mk_hash(k, 0), mk_hash(k, 1)],
                cold_data: vec![],
                block_height: 0,
                mined_block_id: None,
                mined_block_height: None,
                mined_subtree_idx: None,
                parent_txids: vec![],
            })
            .collect();
        assert_eq!(
            request(OP_CREATE_BATCH, encode_create_batch(&create_items)).status,
            STATUS_OK,
            "seed creates must succeed"
        );

        let params = SpendBatchParams {
            ignore_conflicting: false,
            ignore_locked: false,
            current_block_height: 1000,
            block_height_retention: 0,
        };
        // Build a spend batch: vout 0 valid on all N txids, plus two doomed
        // items — a wrong-hash spend on txid 0's vout 1, and a spend of a txid
        // that was never created. Distinct txids = N + 1 (>= threshold).
        let mut spend_items: Vec<WireSpendItem> = (0..N)
            .map(|k| WireSpendItem {
                txid: mk_txid(k),
                vout: 0,
                utxo_hash: mk_hash(k, 0),
                spending_data: [0xD3; 36],
            })
            .collect();
        spend_items.push(WireSpendItem {
            txid: mk_txid(0),
            vout: 1,
            utxo_hash: [0xEE; 32], // wrong hash -> must be rejected, slot stays unspent
            spending_data: [0xD3; 36],
        });
        let missing_txid = {
            let mut t = [0u8; 32];
            t[0] = 0xBB;
            t
        };
        spend_items.push(WireSpendItem {
            txid: missing_txid,
            vout: 0,
            utxo_hash: [0x00; 32],
            spending_data: [0xD3; 36],
        });

        let syncs_before = redo_dev.sync_count();
        let resp = request(OP_SPEND_BATCH, encode_spend_batch(&params, &spend_items));
        let flush_syncs = redo_dev.sync_count() - syncs_before;

        // Two of the items fail (wrong hash + not-found), so the batch reports
        // a partial error; the valid items still applied.
        assert_eq!(
            resp.status, STATUS_PARTIAL_ERROR,
            "batch with 2 doomed items should report partial error"
        );

        // Every valid txid's vout 0 must be SPENT; vout 1 must be UNSPENT.
        for k in 0..N {
            let slots = engine
                .read_slots(&TxKey { txid: mk_txid(k) })
                .expect("created txid must exist");
            assert_eq!(
                slots[0].status,
                crate::record::UTXO_SPENT,
                "txid {k} vout 0 must be spent by the fanned batch"
            );
            assert_eq!(
                slots[1].status,
                crate::record::UTXO_UNSPENT,
                "txid {k} vout 1 must remain unspent"
            );
        }
        // The wrong-hash item targeted txid 0 vout 1 — already asserted UNSPENT
        // above, confirming the mismatch was rejected, not silently applied.
        // The not-found txid must not have been created as a side effect.
        assert!(
            engine.read_slots(&TxKey { txid: missing_txid }).is_err(),
            "spend of a missing txid must not materialize a record"
        );

        // WAL-first single-flush contract is unchanged by the fan-out: the N
        // valid spends commit in exactly one redo fsync.
        assert_eq!(
            flush_syncs, 1,
            "fanned spend validate must still collapse to one redo flush; got {flush_syncs}"
        );
    }

    /// Parallel apply fan-out for set_mined must preserve exact per-item
    /// outcomes. Drives a batch above `READ_FANOUT_THRESHOLD` (valid txids plus
    /// a not-found txid), then asserts each valid record gained the block entry
    /// with the right fields and the missing one was not materialized — so the
    /// fanned `set_mined_inner` apply can't drop, misroute, or corrupt any item
    /// versus the old serial loop.
    #[test]
    fn set_mined_batch_parallel_apply_preserves_per_item_outcomes() {
        let _g = metrics_test_lock();
        let data_dev = Arc::new(MemoryDevice::new(64 * 1024 * 1024, 4096).unwrap());
        let redo_dev = Arc::new(CountingSyncDevice::new(16 * 1024 * 1024, 4096));
        let alloc = SlotAllocator::new(data_dev.clone()).unwrap();
        let index = Index::new(10_000).unwrap();
        let engine = Engine::new(
            data_dev.clone() as Arc<dyn BlockDevice>,
            index,
            alloc,
            StripedLocks::new(64),
            DahIndex::new(),
            UnminedIndex::new(),
        );
        let redo_log = Arc::new(Mutex::new(
            RedoLog::open(
                redo_dev.clone() as Arc<dyn BlockDevice>,
                0,
                16 * 1024 * 1024,
            )
            .unwrap(),
        ));

        let request = |op: u16, payload: Vec<u8>| -> ResponseFrame {
            let req = RequestFrame {
                request_id: 1,
                op_code: op,
                flags: 0,
                payload: payload.into(),
            };
            let mut cs = crate::server::ConnectionState::new();
            handle_request(&req, &engine, 8192, None, Some(&redo_log), &mut cs, None)
        };

        const N: usize = 10; // > READ_FANOUT_THRESHOLD (8) -> parallel apply path
        let mk_txid = |k: usize| {
            let mut t = [0u8; 32];
            t[0] = 0x5E;
            t[1] = k as u8;
            t
        };
        let create_items: Vec<WireCreateItem> = (0..N)
            .map(|k| WireCreateItem {
                txid: mk_txid(k),
                tx_version: 1,
                locktime: 0,
                fee: 500,
                size_in_bytes: 250,
                extended_size: 0,
                is_coinbase: false,
                spending_height: 0,
                created_at: 1_700_000_000_000,
                flags: 0,
                utxo_hashes: vec![[k as u8; 32]],
                cold_data: vec![],
                block_height: 0,
                mined_block_id: None,
                mined_block_height: None,
                mined_subtree_idx: None,
                parent_txids: vec![],
            })
            .collect();
        assert_eq!(
            request(OP_CREATE_BATCH, encode_create_batch(&create_items)).status,
            STATUS_OK,
            "seed creates must succeed"
        );

        const BLOCK_ID: u32 = 7;
        const BLOCK_HEIGHT: u32 = 900_000;
        const SUBTREE: u32 = 3;
        let params = SetMinedBatchParams {
            block_id: BLOCK_ID,
            block_height: BLOCK_HEIGHT,
            subtree_idx: SUBTREE,
            on_longest_chain: true,
            unset_mined: false,
            current_block_height: BLOCK_HEIGHT,
            block_height_retention: 288,
        };
        // All N valid txids plus one that was never created.
        let missing_txid = {
            let mut t = [0u8; 32];
            t[0] = 0xCC;
            t
        };
        let mut txids: Vec<[u8; 32]> = (0..N).map(mk_txid).collect();
        txids.push(missing_txid);

        let resp = request(OP_SET_MINED_BATCH, encode_set_mined_batch(&params, &txids));
        assert_eq!(
            resp.status, STATUS_PARTIAL_ERROR,
            "batch with one not-found txid should report partial error"
        );

        // Every valid txid must carry the new block entry with the exact fields.
        for k in 0..N {
            let entry = engine
                .read_block_entry(&TxKey { txid: mk_txid(k) }, BLOCK_ID)
                .expect("created txid must exist")
                .unwrap_or_else(|| panic!("txid {k} must have block entry after fanned set_mined"));
            // Copy out of the packed struct before comparing (no unaligned refs).
            let (bh, st) = (entry.block_height, entry.subtree_idx);
            assert_eq!(bh, BLOCK_HEIGHT, "txid {k} block_height");
            assert_eq!(st, SUBTREE, "txid {k} subtree_idx");
        }
        // The not-found txid must not have been materialized.
        assert!(
            engine
                .read_block_entry(&TxKey { txid: missing_txid }, BLOCK_ID)
                .is_err(),
            "set_mined of a missing txid must not materialize a record"
        );
    }

    /// PR#21 review (P2): the per-txid DAH secondary updates must be folded into
    /// ONE batched redo flush for the whole RPC, not one `append_and_flush` per
    /// last-spend txid. `commit_dah_batch` is the fold primitive: N transitions
    /// → one effective flush (one device sync), independent of N.
    #[test]
    fn commit_dah_batch_folds_n_transitions_into_one_flush() {
        let _g = metrics_test_lock();
        let data_dev = Arc::new(MemoryDevice::new(16 * 1024 * 1024, 4096).unwrap());
        let redo_dev = Arc::new(CountingSyncDevice::new(16 * 1024 * 1024, 4096));
        let alloc = SlotAllocator::new(data_dev.clone()).unwrap();
        let engine = Engine::new(
            data_dev.clone() as Arc<dyn BlockDevice>,
            Index::new(10_000).unwrap(),
            alloc,
            StripedLocks::new(1024),
            DahIndex::new(),
            UnminedIndex::new(),
        );
        let redo_log = Arc::new(Mutex::new(
            RedoLog::open(
                redo_dev.clone() as Arc<dyn BlockDevice>,
                0,
                16 * 1024 * 1024,
            )
            .unwrap(),
        ));
        engine.set_redo_log(redo_log);

        // N DAH transitions (old=0 → new=100). commit_dah_batch inserts into the
        // DAH index by key, so no on-device record is required.
        const N: usize = 16;
        let transitions: Vec<(TxKey, u32, u32)> = (0..N)
            .map(|k| {
                let mut t = [0u8; 32];
                t[0] = 0xDA;
                t[1] = k as u8;
                (TxKey { txid: t }, 0u32, 100u32)
            })
            .collect();

        let before = redo_dev.sync_count();
        PreparedSpend::commit_dah_batch(&engine, &transitions).unwrap();
        let syncs = redo_dev.sync_count() - before;
        assert_eq!(
            syncs, 1,
            "{N} DAH transitions must fold into ONE batched secondary fsync, not {N}; got {syncs}",
        );
    }

    impl RedoDispatchHarness {
        fn new() -> Self {
            Self::new_with_redo_size(4 * 1024 * 1024)
        }

        fn new_with_redo_size(redo_size: u64) -> Self {
            let data_dev = Arc::new(MemoryDevice::new(64 * 1024 * 1024, 4096).unwrap());
            let redo_dev = Arc::new(MemoryDevice::new(redo_size.max(4096), 4096).unwrap());
            let alloc = SlotAllocator::new(data_dev.clone()).unwrap();
            let index = Index::new(10000).unwrap();
            let locks = StripedLocks::new(1024);
            let dah = DahIndex::new();
            let unmined = UnminedIndex::new();
            let engine = Engine::new(
                data_dev.clone() as Arc<dyn BlockDevice>,
                index,
                alloc,
                locks,
                dah,
                unmined,
            );
            let redo_log = crate::redo::RedoLog::open(
                redo_dev.clone() as Arc<dyn BlockDevice>,
                0,
                redo_size.max(4096),
            )
            .unwrap();
            Self {
                engine,
                redo_log: Arc::new(Mutex::new(redo_log)),
                data_dev,
                redo_dev,
                _metrics_guard: metrics_test_lock(),
            }
        }

        /// Engine + allocator over a [`crate::cache::CachingDevice`] wrapping the
        /// data device, in write-through (`writeback = false`) or write-back
        /// (`true`) mode. With write-back this proves the WAL recovers records
        /// whose data write only ever landed in the (crash-lost) cache;
        /// `crash_and_recover` rebuilds over the inner `data_dev`, simulating the
        /// lost cache.
        fn new_with_cache(writeback: bool) -> Self {
            let data_dev = Arc::new(MemoryDevice::new(64 * 1024 * 1024, 4096).unwrap());
            let redo_dev = Arc::new(MemoryDevice::new(4 * 1024 * 1024, 4096).unwrap());
            let cache: Arc<dyn BlockDevice> = Arc::new(crate::cache::CachingDevice::new(
                data_dev.clone() as Arc<dyn BlockDevice>,
                8 * 1024 * 1024,
                writeback,
            ));
            let alloc = SlotAllocator::new(cache.clone()).unwrap();
            let index = Index::new(10000).unwrap();
            let engine = Engine::new(
                cache.clone(),
                index,
                alloc,
                StripedLocks::new(1024),
                DahIndex::new(),
                UnminedIndex::new(),
            );
            let redo_log = crate::redo::RedoLog::open(
                redo_dev.clone() as Arc<dyn BlockDevice>,
                0,
                4 * 1024 * 1024,
            )
            .unwrap();
            Self {
                engine,
                redo_log: Arc::new(Mutex::new(redo_log)),
                data_dev,
                redo_dev,
                _metrics_guard: metrics_test_lock(),
            }
        }

        fn new_with_exact_redo_log_size(log_size: u64) -> Self {
            let data_dev = Arc::new(MemoryDevice::new(64 * 1024 * 1024, 4096).unwrap());
            let redo_dev = Arc::new(MemoryDevice::new(log_size.max(4096), 4096).unwrap());
            let alloc = SlotAllocator::new(data_dev.clone()).unwrap();
            let index = Index::new(10000).unwrap();
            let locks = StripedLocks::new(1024);
            let dah = DahIndex::new();
            let unmined = UnminedIndex::new();
            let engine = Engine::new(
                data_dev.clone() as Arc<dyn BlockDevice>,
                index,
                alloc,
                locks,
                dah,
                unmined,
            );
            let redo_log =
                crate::redo::RedoLog::open(redo_dev.clone() as Arc<dyn BlockDevice>, 0, log_size)
                    .unwrap();
            let redo_log = Arc::new(Mutex::new(redo_log));
            engine.allocator().lock().set_redo_log(redo_log.clone());
            Self {
                engine,
                redo_log,
                data_dev,
                redo_dev,
                _metrics_guard: metrics_test_lock(),
            }
        }

        /// Dispatch a request through the full handler with redo log attached.
        fn request(&self, op_code: u16, payload: Vec<u8>) -> ResponseFrame {
            let req = RequestFrame {
                request_id: 1,
                op_code,
                flags: 0,
                payload: payload.into(),
            };
            let mut conn_state = crate::server::ConnectionState::new();
            handle_request(
                &req,
                &self.engine,
                8192,
                None,
                Some(&self.redo_log),
                &mut conn_state,
                None,
            )
        }

        /// Create a transaction and return the response.
        fn create_tx(&self, txid: [u8; 32], utxo_count: u32) -> ResponseFrame {
            let hashes: Vec<[u8; 32]> = (0..utxo_count)
                .map(|i| {
                    let mut h = [0u8; 32];
                    h[0] = (i & 0xFF) as u8;
                    h[1] = ((i >> 8) & 0xFF) as u8;
                    h
                })
                .collect();
            let item = WireCreateItem {
                txid,
                tx_version: 1,
                locktime: 0,
                fee: 500,
                size_in_bytes: 250,
                extended_size: 250,
                is_coinbase: false,
                spending_height: 0,
                created_at: 1700000000000,
                flags: 0,
                utxo_hashes: hashes,
                cold_data: vec![],
                block_height: 0,
                mined_block_id: None,
                mined_block_height: None,
                mined_subtree_idx: None,
                parent_txids: vec![],
            };
            let payload = encode_create_batch(&[item]);
            self.request(OP_CREATE_BATCH, payload)
        }

        /// Simulate crash: drop engine and redo log, rebuild from devices.
        /// Returns a new harness with recovered state.
        fn crash_and_recover(self) -> Self {
            // Drop the engine and redo log — simulates SIGKILL.
            // The MemoryDevice data survives (it's Arc'd).
            let data_dev = self.data_dev.clone();
            let redo_dev = self.redo_dev.clone();
            drop(self);

            // Reopen redo log from device
            let redo_log = crate::redo::RedoLog::open(
                redo_dev.clone() as Arc<dyn BlockDevice>,
                0,
                4 * 1024 * 1024,
            )
            .unwrap();

            // Create fresh index + allocator
            let alloc = SlotAllocator::new(data_dev.clone()).unwrap();
            let primary: crate::index::PrimaryBackend = Index::new(10000).unwrap().into();
            let index = crate::index::ShardedIndex::from_single(primary);

            // Run recovery to rebuild index from redo log
            let stats = crate::recovery::recover(&*data_dev as &dyn BlockDevice, &redo_log, &index)
                .unwrap();
            eprintln!(
                "recovery: {} replayed, {} skipped, {} failed",
                stats.entries_replayed, stats.entries_skipped, stats.entries_failed
            );

            let engine = Engine::new_with_sharded_index(
                data_dev.clone() as Arc<dyn BlockDevice>,
                index,
                alloc,
                StripedLocks::new(1024),
                DahIndex::new(),
                UnminedIndex::new(),
            );

            Self {
                engine,
                redo_log: Arc::new(Mutex::new(redo_log)),
                data_dev,
                redo_dev,
                // Safe to reacquire: `drop(self)` above released the
                // original harness's guard.
                _metrics_guard: metrics_test_lock(),
            }
        }
    }

    #[test]
    fn acked_creates_survive_crash() {
        let h = RedoDispatchHarness::new();

        // Create 50 records, collecting ACK'd txids
        let mut acked_keys = Vec::new();
        for i in 0..50u8 {
            let mut txid = [0u8; 32];
            txid[0] = i;
            txid[31] = i.wrapping_mul(7);
            let resp = h.create_tx(txid, 3);
            if resp.status == STATUS_OK {
                acked_keys.push(TxKey { txid });
            }
        }
        assert!(
            !acked_keys.is_empty(),
            "should have ACK'd at least one create"
        );

        // CRASH and recover
        let h2 = h.crash_and_recover();

        // Every ACK'd key must be in the recovered index
        let mut missing = Vec::new();
        for key in &acked_keys {
            if h2.engine.lookup(key).is_none() {
                missing.push(key);
            }
        }
        assert!(
            missing.is_empty(),
            "ACKed creates lost after crash: {}/{} missing",
            missing.len(),
            acked_keys.len()
        );
    }

    #[test]
    fn writethrough_cache_is_transparent_to_engine_lifecycle() {
        // A full create -> spend -> set_mined -> read lifecycle through a
        // write-through cache must behave exactly as the raw device: the cache is
        // a transparent BlockDevice wrapper.
        let h = RedoDispatchHarness::new_with_cache(false);
        let mut txid = [0u8; 32];
        txid[0] = 0x42;
        let key = TxKey { txid };

        assert_eq!(h.create_tx(txid, 3).status, STATUS_OK, "create");
        // Read back through the cache.
        let hash = h.engine.read_slot(&key, 0).unwrap().hash;

        let params = SpendBatchParams {
            ignore_conflicting: false,
            ignore_locked: false,
            current_block_height: 1000,
            block_height_retention: 288,
        };
        let item = WireSpendItem {
            txid,
            vout: 0,
            utxo_hash: hash,
            spending_data: [0xCD; 36],
        };
        assert_eq!(
            h.request(OP_SPEND_BATCH, encode_spend_batch(&params, &[item]))
                .status,
            STATUS_OK,
            "spend"
        );
        let sm = SetMinedBatchParams {
            block_id: 9,
            block_height: 500_000,
            subtree_idx: 2,
            on_longest_chain: true,
            unset_mined: false,
            current_block_height: 500_000,
            block_height_retention: 288,
        };
        assert_eq!(
            h.request(OP_SET_MINED_BATCH, encode_set_mined_batch(&sm, &[txid]))
                .status,
            STATUS_OK,
            "set_mined"
        );

        // Final state is correct and coherent through the cache.
        assert!(
            h.engine.read_slot(&key, 0).unwrap().is_spent(),
            "slot spent"
        );
        let entry = h
            .engine
            .read_block_entry(&key, 9)
            .unwrap()
            .expect("block entry present");
        let bh = entry.block_height;
        assert_eq!(bh, 500_000, "block height recorded");
    }

    #[test]
    fn writeback_cache_lost_on_crash_is_recovered_from_wal() {
        // The engine writes records through a WRITE-BACK cache, so the data-device
        // write is deferred in RAM and never synced here. On crash that RAM is
        // lost — exactly the volatile-write case the durability contract already
        // tolerates (recovery.rs step 3: the data write "is NOT necessarily
        // durable on return"). The fsynced WAL must still recover everything.
        let h = RedoDispatchHarness::new_with_cache(true);

        let mut acked = Vec::new();
        for i in 0..20u8 {
            let mut txid = [0u8; 32];
            txid[0] = i;
            txid[31] = i.wrapping_mul(11);
            let resp = h.create_tx(txid, 3);
            assert_eq!(resp.status, STATUS_OK, "create {i} failed");
            acked.push(TxKey { txid });
        }
        // Spend slot 0 of the first 10 (the read is served coherently from the
        // dirty cache).
        let mut spent = Vec::new();
        for key in acked.iter().take(10) {
            let hash = h.engine.read_slot(key, 0).unwrap().hash;
            let item = WireSpendItem {
                txid: key.txid,
                vout: 0,
                utxo_hash: hash,
                spending_data: [0xAB; 36],
            };
            let params = SpendBatchParams {
                ignore_conflicting: false,
                ignore_locked: false,
                current_block_height: 1000,
                block_height_retention: 288,
            };
            let resp = h.request(OP_SPEND_BATCH, encode_spend_batch(&params, &[item]));
            assert_eq!(resp.status, STATUS_OK, "spend failed");
            spent.push(*key);
        }

        // CRASH: drop the engine + write-back cache WITHOUT sync; recover over the
        // inner data device, whose blocks never received the deferred writes.
        let h2 = h.crash_and_recover();

        for key in &acked {
            assert!(
                h2.engine.lookup(key).is_some(),
                "created record lost after crash despite the WAL covering the write-back cache"
            );
        }
        for key in &spent {
            let slot = h2
                .engine
                .read_slot(key, 0)
                .expect("spent record must be readable after recovery");
            assert!(slot.is_spent(), "spend lost after crash despite the WAL");
        }
    }

    #[test]
    fn acked_spends_survive_crash() {
        let h = RedoDispatchHarness::new();

        // Create 20 records
        let mut txids = Vec::new();
        for i in 0..20u8 {
            let mut txid = [0u8; 32];
            txid[0] = i;
            txid[31] = i.wrapping_mul(7);
            let resp = h.create_tx(txid, 3);
            assert_eq!(resp.status, STATUS_OK, "create {i} failed");
            txids.push(txid);
        }

        // Spend slot 0 on the first 10 records
        let mut acked_spends = Vec::new();
        for txid in txids.iter().take(10) {
            let key = TxKey { txid: *txid };
            let hash = h.engine.read_slot(&key, 0).unwrap().hash;
            let spend_item = WireSpendItem {
                txid: *txid,
                vout: 0,
                utxo_hash: hash,
                spending_data: [0xAB; 36],
            };
            let params = SpendBatchParams {
                ignore_conflicting: false,
                ignore_locked: false,
                current_block_height: 1000,
                block_height_retention: 288,
            };
            let payload = encode_spend_batch(&params, &[spend_item]);
            let resp = h.request(OP_SPEND_BATCH, payload);
            if resp.status == STATUS_OK {
                acked_spends.push(key);
            }
        }
        assert!(
            !acked_spends.is_empty(),
            "should have ACK'd at least one spend"
        );

        // CRASH and recover
        let h2 = h.crash_and_recover();

        // Verify spent slots are still spent after recovery
        let mut lost = 0;
        for key in &acked_spends {
            match h2.engine.read_slot(key, 0) {
                Ok(slot) => {
                    if !slot.is_spent() {
                        lost += 1;
                    }
                }
                Err(_) => lost += 1,
            }
        }
        assert_eq!(
            lost,
            0,
            "ACKed spends lost after crash: {}/{} not spent",
            lost,
            acked_spends.len()
        );
    }

    /// Gap #2 (TERANODE_PRODUCTION_READINESS_GAPS.md): the spend redo entry
    /// must carry the real `new_spent_count`, not `0`. Simulates the
    /// crash-between-WAL-fsync-and-engine-apply window by spending three
    /// slots, then *forcing* recovery to reapply the spend redo entries
    /// against fresh on-device record bytes (reset by the test). After
    /// recovery, `meta.spent_utxos` must equal 3 — the count the redo
    /// entries actually carried — not 0.
    #[test]
    fn spend_redo_carries_real_new_spent_count_for_replay() {
        let h = RedoDispatchHarness::new();
        let txid = {
            let mut t = [0u8; 32];
            t[0] = 0xAA;
            t
        };
        assert_eq!(h.create_tx(txid, 3).status, STATUS_OK);
        let key = TxKey { txid };

        // Capture the original record offset and hashes BEFORE spending.
        let entry = h.engine.lookup(&key).expect("create registered tx");
        let record_offset = entry.record_offset;
        let pre_meta = crate::io::read_metadata(
            &*h.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
        )
        .expect("read pre-spend metadata");
        let pre_spent: u32 = { pre_meta.spent_utxos };
        assert_eq!(pre_spent, 0, "pre-state spent_utxos must be 0");
        let original_slots: Vec<crate::record::UtxoSlot> = (0..3u32)
            .map(|i| {
                crate::io::read_utxo_slot(
                    &*h.data_dev as &dyn crate::device::BlockDevice,
                    record_offset,
                    i,
                )
                .expect("read original slot")
            })
            .collect();

        // Spend all three slots in a single batch.
        let params = SpendBatchParams {
            ignore_conflicting: false,
            ignore_locked: false,
            current_block_height: 1000,
            block_height_retention: 288,
        };
        let items: Vec<WireSpendItem> = (0..3u32)
            .map(|i| WireSpendItem {
                txid,
                vout: i,
                utxo_hash: original_slots[i as usize].hash,
                spending_data: [(0xC0 + i as u8); 36],
            })
            .collect();
        assert_eq!(
            h.request(OP_SPEND_BATCH, encode_spend_batch(&params, &items))
                .status,
            STATUS_OK,
            "spend batch must succeed",
        );

        // Verify the engine applied the count.
        let post_meta = crate::io::read_metadata(
            &*h.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
        )
        .expect("read post-spend metadata");
        assert_eq!(
            { post_meta.spent_utxos },
            3,
            "engine must have applied real spent_utxos = 3",
        );

        // Roll the on-device slots + counter back to the pre-spend state to
        // simulate "redo fsynced but engine apply lost". The redo entries
        // are still in the redo log device.
        for (i, slot) in original_slots.iter().enumerate() {
            crate::io::write_utxo_slot(
                &*h.data_dev as &dyn crate::device::BlockDevice,
                record_offset,
                i as u32,
                slot,
            )
            .expect("restore pre-spend slot");
        }
        let mut reset_meta = post_meta;
        reset_meta.spent_utxos = pre_spent;
        crate::io::write_metadata(
            &*h.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
            &reset_meta,
        )
        .expect("restore pre-spend metadata");

        // CRASH and recover — replay must reconstruct counter to 3.
        let h2 = h.crash_and_recover();
        let recovered_meta = crate::io::read_metadata(
            &*h2.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
        )
        .expect("read recovered metadata");
        assert_eq!(
            { recovered_meta.spent_utxos },
            3,
            "redo replay must restore spent_utxos = 3 (gap #2 — \
             previously written as 0 in dispatch and applied verbatim)",
        );
        // And every slot must be SPENT after replay.
        for i in 0..3u32 {
            let slot = crate::io::read_utxo_slot(
                &*h2.data_dev as &dyn crate::device::BlockDevice,
                record_offset,
                i,
            )
            .expect("recovered slot reads");
            assert!(slot.is_spent(), "slot {i} must be SPENT after replay");
        }
    }

    /// Companion test for unspend: the same `new_spent_count: 0`
    /// placeholder bug existed in the unspend dispatch path. After
    /// unspending one slot, simulate "redo fsynced but engine lost" by
    /// rolling the slot + counter back, and verify replay restores the
    /// post-unspend counter (decremented from the original).
    #[test]
    fn unspend_redo_carries_real_new_spent_count_for_replay() {
        let h = RedoDispatchHarness::new();
        let txid = {
            let mut t = [0u8; 32];
            t[0] = 0xBB;
            t
        };
        assert_eq!(h.create_tx(txid, 2).status, STATUS_OK);
        let key = TxKey { txid };

        // Spend both slots so the counter is 2 before the unspend.
        let entry = h.engine.lookup(&key).expect("create registered tx");
        let record_offset = entry.record_offset;
        let original_slots: Vec<crate::record::UtxoSlot> = (0..2u32)
            .map(|i| {
                crate::io::read_utxo_slot(
                    &*h.data_dev as &dyn crate::device::BlockDevice,
                    record_offset,
                    i,
                )
                .expect("read original slot")
            })
            .collect();
        let params = SpendBatchParams {
            ignore_conflicting: false,
            ignore_locked: false,
            current_block_height: 1000,
            block_height_retention: 288,
        };
        let spend_items: Vec<WireSpendItem> = (0..2u32)
            .map(|i| WireSpendItem {
                txid,
                vout: i,
                utxo_hash: original_slots[i as usize].hash,
                spending_data: [(0xC0 + i as u8); 36],
            })
            .collect();
        assert_eq!(
            h.request(OP_SPEND_BATCH, encode_spend_batch(&params, &spend_items))
                .status,
            STATUS_OK,
        );
        let pre_unspend_meta = crate::io::read_metadata(
            &*h.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
        )
        .expect("read pre-unspend metadata");
        assert_eq!({ pre_unspend_meta.spent_utxos }, 2);

        // Now unspend slot 0 only.
        let unspend_items = vec![WireUnspendItem {
            txid,
            vout: 0,
            utxo_hash: original_slots[0].hash,
            spending_data: [0xC0; 36],
        }];
        let unspend_params = UnspendBatchParams {
            current_block_height: 1000,
            block_height_retention: 288,
        };
        assert_eq!(
            h.request(
                OP_UNSPEND_BATCH,
                encode_unspend_batch(&unspend_params, &unspend_items),
            )
            .status,
            STATUS_OK,
        );

        // Verify engine count went 2 → 1.
        let post_unspend_meta = crate::io::read_metadata(
            &*h.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
        )
        .expect("read post-unspend metadata");
        assert_eq!(
            { post_unspend_meta.spent_utxos },
            1,
            "engine must apply real spent_utxos = 1 after unspending one slot",
        );

        // Simulate "redo fsynced but engine lost": roll slot 0 back to
        // SPENT and counter back to 2.
        let spent_zero = crate::record::UtxoSlot::new_spent(original_slots[0].hash, [0xC0; 36]);
        crate::io::write_utxo_slot(
            &*h.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
            0,
            &spent_zero,
        )
        .expect("restore SPENT slot 0");
        let mut reset_meta = post_unspend_meta;
        reset_meta.spent_utxos = 2;
        crate::io::write_metadata(
            &*h.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
            &reset_meta,
        )
        .expect("restore pre-unspend metadata");

        // CRASH and recover — replay_unspend must take counter 2 → 1
        // by writing the redo's `new_spent_count`.
        let h2 = h.crash_and_recover();
        let recovered_meta = crate::io::read_metadata(
            &*h2.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
        )
        .expect("read recovered metadata");
        assert_eq!(
            { recovered_meta.spent_utxos },
            1,
            "redo replay must decrement spent_utxos to 1 (gap #2 — \
             previously written as 0 in dispatch)",
        );
        let recovered_slot0 = crate::io::read_utxo_slot(
            &*h2.data_dev as &dyn crate::device::BlockDevice,
            record_offset,
            0,
        )
        .expect("recovered slot 0 reads");
        assert!(
            recovered_slot0.is_unspent(),
            "slot 0 must be UNSPENT after replay",
        );
    }

    #[test]
    fn acked_mark_longest_chain_survives_crash() {
        let h = RedoDispatchHarness::new();

        // Create 10 records and set_mined on them
        let mut txids = Vec::new();
        for i in 0..10u8 {
            let mut txid = [0u8; 32];
            txid[0] = i;
            txid[31] = i.wrapping_mul(7);
            let resp = h.create_tx(txid, 2);
            assert_eq!(resp.status, STATUS_OK);
            txids.push(txid);
        }

        // set_mined on all
        let set_mined_params = SetMinedBatchParams {
            block_id: 42,
            block_height: 1000,
            subtree_idx: 5,
            on_longest_chain: true,
            unset_mined: false,
            current_block_height: 1000,
            block_height_retention: 288,
        };
        let payload = encode_set_mined_batch(&set_mined_params, &txids);
        let resp = h.request(OP_SET_MINED_BATCH, payload);
        assert_eq!(resp.status, STATUS_OK);

        // mark_on_longest_chain = false (unmined) on first 5
        let shared = {
            let mut s = Vec::with_capacity(9);
            s.push(0u8); // on_longest_chain = false
            s.extend_from_slice(&2000u32.to_le_bytes()); // current_block_height
            s.extend_from_slice(&288u32.to_le_bytes()); // block_height_retention
            s
        };
        let payload_bytes = encode_txid_batch(&txids[..5], &shared);
        let resp = h.request(OP_MARK_LONGEST_CHAIN_BATCH, payload_bytes);
        assert_eq!(resp.status, STATUS_OK);

        // CRASH and recover
        let h2 = h.crash_and_recover();

        // The first 5 should have unmined_since = 2000 after recovery
        for txid in txids.iter().take(5) {
            let key = TxKey { txid: *txid };
            let meta = h2.engine.read_metadata(&key).unwrap();
            assert_eq!(
                { meta.unmined_since },
                2000,
                "mark_longest_chain not recovered for txid[0]={:02x}",
                txid[0]
            );
        }
    }

    #[test]
    fn dispatch_get_redirects_non_master_even_if_local_copy_exists() {
        let h = DispatchTestHarness::new();
        let txid = DispatchTestHarness::make_txid(90);
        assert_eq!(h.create_tx(txid, 1).status, STATUS_OK);

        let shard = crate::cluster::shards::ShardTable::shard_for_key(&TxKey { txid });
        let members = vec![
            crate::cluster::shards::NodeId(1),
            crate::cluster::shards::NodeId(2),
        ];
        let table = crate::cluster::shards::ShardTable::compute_with_epoch(&members, 2, 11, 1);
        let master = table.target_assignment(shard).master;
        let self_id = if master == crate::cluster::shards::NodeId(1) {
            crate::cluster::shards::NodeId(2)
        } else {
            crate::cluster::shards::NodeId(1)
        };
        let cluster = crate::cluster::coordinator::new_test_running_cluster(
            self_id,
            table,
            &[
                (
                    crate::cluster::shards::NodeId(1),
                    "127.0.0.1:4401".parse().unwrap(),
                ),
                (
                    crate::cluster::shards::NodeId(2),
                    "127.0.0.1:4402".parse().unwrap(),
                ),
            ],
            &members,
            &[],
            &[],
            &[],
            2,
        );

        let resp = h.request_with_cluster(
            OP_GET_BATCH,
            crate::protocol::codec::encode_get_batch(FieldMask::ALL_METADATA, &[txid]),
            &cluster,
        );
        assert_eq!(resp.status, STATUS_OK);
        let results = crate::protocol::codec::decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].status, ERR_REDIRECT as u8);
    }

    // R-041: REDIRECT now carries shard_table_version so clients can detect
    // a stale-route loop instead of chasing redirects forever. This test
    // exercises the per-item REDIRECT path on both write (BatchItemError)
    // and read (WireGetResult) flows and asserts the version round-trips.
    #[test]
    fn redirect_includes_shard_table_version_for_loop_detection() {
        use crate::cluster::shards::NodeId;
        use crate::cluster::shards::ShardTable;

        // DispatchTestHarness::new() holds metrics_test_lock for the
        // harness lifetime, so the global `operations` /
        // `stale_routing_request_total` increments this test causes do
        // not race with `prometheus_emits_operations_total_with_labels`
        // (which compares a rendered snapshot against live counters).

        let h = DispatchTestHarness::new();
        let txid = DispatchTestHarness::make_txid(91);
        let shard = ShardTable::shard_for_key(&TxKey { txid });
        let members = vec![NodeId(1), NodeId(2)];
        // Pick a non-trivial shard table version so an "0" placeholder
        // would be obvious. compute_with_epoch(epoch=42) sets table.version=42.
        const STALE_VERSION: u64 = 42;
        let table = ShardTable::compute_with_epoch(&members, 2, STALE_VERSION, 1);
        let master = table.target_assignment(shard).master;
        // self_id != master so this node redirects.
        let self_id = if master == NodeId(1) {
            NodeId(2)
        } else {
            NodeId(1)
        };
        let target_addr_for_master = if master == NodeId(1) {
            "127.0.0.1:4501".parse::<std::net::SocketAddr>().unwrap()
        } else {
            "127.0.0.1:4502".parse::<std::net::SocketAddr>().unwrap()
        };
        let cluster = crate::cluster::coordinator::new_test_running_cluster(
            self_id,
            table,
            &[
                (NodeId(1), "127.0.0.1:4501".parse().unwrap()),
                (NodeId(2), "127.0.0.1:4502".parse().unwrap()),
            ],
            &members,
            &[],
            &[],
            &[],
            2,
        );

        // -------- Write path: BatchItemError redirect data --------
        // SetMined writes are routed via check_shard_ownership, which
        // emits BatchItemError { error_code: ERR_REDIRECT, error_data }.
        let set_mined_params = SetMinedBatchParams {
            block_id: 1,
            block_height: 100,
            subtree_idx: 0,
            on_longest_chain: true,
            unset_mined: false,
            current_block_height: 100,
            block_height_retention: 288,
        };
        let payload = encode_set_mined_batch(&set_mined_params, &[txid]);
        let resp = h.request_with_cluster(OP_SET_MINED_BATCH, payload, &cluster);
        // Per-item redirect comes back as a partial-error with one entry.
        // LP-2 / spec §3.6: set_mined now encodes its response as
        // partial-with-signals (success section + error section), so the
        // redirect error is read from the error section of that envelope
        // rather than the bare sparse-error form.
        assert_eq!(resp.status, STATUS_PARTIAL_ERROR);
        let (_successes, errs) = crate::protocol::codec::decode_partial_with_signals(&resp.payload)
            .expect("set_mined redirect response must decode as partial-with-signals");
        assert_eq!(errs.len(), 1, "exactly one redirected item");
        assert_eq!(errs[0].error_code, ERR_REDIRECT);

        // R-041 assertion: error_data must decode to (addr, Some(version))
        // via decode_redirect_with_version. Pre-fix the data was raw addr
        // bytes with no version → decode_redirect_with_version would have
        // returned (addr, None) and the client could not perform a
        // server-vs-client version comparison.
        let (addr, version) =
            crate::protocol::codec::decode_redirect_with_version(&errs[0].error_data)
                .expect("R-041: BatchItemError REDIRECT data must decode with version");
        assert_eq!(addr, target_addr_for_master.to_string());
        assert_eq!(
            version,
            Some(STALE_VERSION),
            "R-041: server's shard_table_version must round-trip through error_data \
             so a client at the same/newer version can detect a stale-route loop",
        );

        // The classify helper must say "Stale" when the client knows a
        // version equal to the server's — chasing this redirect would
        // either loop or land on an even-older view.
        assert_eq!(
            crate::protocol::codec::classify_redirect(version, STALE_VERSION),
            crate::protocol::codec::RedirectFollowDecision::Stale,
            "R-041: server.version == client.version must be classified Stale \
             so the client refreshes/fails instead of looping",
        );
        // And "Follow" only when the server is strictly ahead.
        assert_eq!(
            crate::protocol::codec::classify_redirect(version, STALE_VERSION - 1),
            crate::protocol::codec::RedirectFollowDecision::Follow,
        );

        // -------- Read path: WireGetResult REDIRECT data --------
        // GET_BATCH per-item REDIRECT carries `[ERR_REDIRECT_byte:1][addr_len:2][addr][version:8]`
        // in WireGetResult.data — strip the leading status byte and run
        // the same decode/classify checks.
        let resp = h.request_with_cluster(
            OP_GET_BATCH,
            crate::protocol::codec::encode_get_batch(FieldMask::ALL_METADATA, &[txid]),
            &cluster,
        );
        assert_eq!(resp.status, STATUS_OK);
        let results = crate::protocol::codec::decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].status, ERR_REDIRECT as u8);
        assert!(
            results[0].data.len() > 1,
            "R-041: GetBatch REDIRECT payload must include addr+version, not just the status byte",
        );
        assert_eq!(
            results[0].data[0], ERR_REDIRECT as u8,
            "first byte is still the legacy ERR_REDIRECT status repeat"
        );
        let (get_addr, get_version) =
            crate::protocol::codec::decode_redirect_with_version(&results[0].data[1..])
                .expect("R-041: GetBatch REDIRECT payload must decode with version");
        assert_eq!(get_addr, target_addr_for_master.to_string());
        assert_eq!(
            get_version,
            Some(STALE_VERSION),
            "R-041: GetBatch redirect must also carry the server's shard_table_version",
        );
    }

    /// F-4 regression: when a shard routes to a remote master whose address is
    /// unknown to this node (membership not yet learned, or the node left
    /// between routing and address lookup), the dispatcher must return a
    /// retryable `ERR_NO_QUORUM` rather than an empty-address `ERR_REDIRECT`.
    /// An empty-address redirect is useless — the client cannot connect to ""
    /// — and worse, it looks like a valid routing answer, so the client would
    /// fail outright instead of backing off and retrying once membership
    /// converges.
    #[test]
    fn redirect_to_master_with_unknown_address_returns_retryable_no_quorum() {
        use crate::cluster::shards::NodeId;
        use crate::cluster::shards::ShardTable;

        let h = DispatchTestHarness::new();
        let txid = DispatchTestHarness::make_txid(73);
        let shard = ShardTable::shard_for_key(&TxKey { txid });
        let members = vec![NodeId(1), NodeId(2)];
        let table = ShardTable::compute_with_epoch(&members, 2, 9, 1);
        let master = table.target_assignment(shard).master;
        // This node is NOT the master, so it must redirect.
        let self_id = if master == NodeId(1) {
            NodeId(2)
        } else {
            NodeId(1)
        };
        // Crucially: provide an address ONLY for self_id, not for the master.
        // `node_addr(master)` therefore returns `None`, driving the F-4 path.
        let self_addr: std::net::SocketAddr = if self_id == NodeId(1) {
            "127.0.0.1:4801".parse().unwrap()
        } else {
            "127.0.0.1:4802".parse().unwrap()
        };
        let cluster = crate::cluster::coordinator::new_test_running_cluster(
            self_id,
            table,
            &[(self_id, self_addr)], // master address intentionally absent
            &members,
            &[],
            &[],
            &[],
            2,
        );

        // Sanity: the master's address really is unknown to this node.
        assert!(
            cluster.node_addr(&master).is_none(),
            "test precondition: master address must be unknown for the F-4 path",
        );

        // Read path (GET_BATCH): must surface ERR_NO_QUORUM, not ERR_REDIRECT.
        let resp = h.request_with_cluster(
            OP_GET_BATCH,
            crate::protocol::codec::encode_get_batch(FieldMask::ALL_METADATA, &[txid]),
            &cluster,
        );
        assert_eq!(resp.status, STATUS_OK);
        let results = crate::protocol::codec::decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(
            results[0].status, ERR_NO_QUORUM as u8,
            "master address unknown must yield retryable ERR_NO_QUORUM, not an \
             empty-address ERR_REDIRECT",
        );
        assert_ne!(
            results[0].status, ERR_REDIRECT as u8,
            "must NOT emit an ERR_REDIRECT when the redirect target address is unknown",
        );

        // Write path: `check_shard_ownership` is the per-item routing gate for
        // every mutating batch op. Assert it directly — when the master
        // address is unknown it must yield a retryable ERR_NO_QUORUM with no
        // redirect payload, not an ERR_REDIRECT carrying an empty address.
        let item_err = check_shard_ownership(&txid, 0, Some(&cluster), false)
            .expect("non-owned key must produce a routing error");
        assert_eq!(
            item_err.error_code, ERR_NO_QUORUM,
            "write path must return retryable ERR_NO_QUORUM for an unknown master address, \
             not ERR_REDIRECT",
        );
        assert_ne!(
            item_err.error_code, ERR_REDIRECT,
            "write path must NOT emit ERR_REDIRECT when the redirect target address is unknown",
        );
        assert!(
            item_err.error_data.is_empty(),
            "ERR_NO_QUORUM carries no redirect target (no empty-address payload)",
        );
    }

    #[test]
    fn dispatch_returns_migration_in_progress_for_transitioning_state() {
        // Phase B4: when the local topology_epoch is ahead of the
        // committed term (membership change proposed but not quorum-
        // committed), GET_BATCH must return ERR_MIGRATION_IN_PROGRESS
        // (retryable) rather than ERR_REDIRECT (non-retryable to a
        // possibly-wrong target).
        let h = DispatchTestHarness::new();
        let shard = 33u16;
        let mut txid = [0u8; 32];
        txid[..2].copy_from_slice(&shard.to_le_bytes());

        let members = vec![crate::cluster::shards::NodeId(1)];
        let table = crate::cluster::shards::ShardTable::compute_with_epoch(&members, 1, 7, 1);
        let cluster = crate::cluster::coordinator::new_test_running_cluster(
            crate::cluster::shards::NodeId(1),
            table,
            &[(
                crate::cluster::shards::NodeId(1),
                "127.0.0.1:4901".parse().unwrap(),
            )],
            &members,
            &[],
            &[],
            &[],
            1,
        );
        // Drive the cluster into the "Transitioning" gap: local
        // topology_epoch = 8, committed_term still = 7. We bump
        // `topology_epoch` directly because `cluster_key_handle()` now
        // exposes the quorum-committed term (see `RunningCluster::
        // local_cluster_key`), which is precisely the value that must
        // *not* advance to trigger the Transitioning gap here.
        cluster
            .topology_epoch_handle()
            .store(8, std::sync::atomic::Ordering::Release);

        let resp = h.request_with_cluster(
            OP_GET_BATCH,
            crate::protocol::codec::encode_get_batch(FieldMask::ALL_METADATA, &[txid]),
            &cluster,
        );
        assert_eq!(resp.status, STATUS_OK);
        let results = crate::protocol::codec::decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(
            results[0].status, ERR_MIGRATION_IN_PROGRESS as u8,
            "Transitioning state must yield ERR_MIGRATION_IN_PROGRESS, not ERR_REDIRECT \
             (so the client retries instead of chasing a possibly-wrong redirect target)",
        );
    }

    #[test]
    fn client_handles_migration_in_progress_polling() {
        let h = DispatchTestHarness::new();
        let shard = 77u16;
        let mut txid = [0u8; 32];
        txid[..2].copy_from_slice(&shard.to_le_bytes());
        let members = vec![crate::cluster::shards::NodeId(1)];
        let table = crate::cluster::shards::ShardTable::compute_with_epoch(&members, 1, 12, 1);
        let cluster = crate::cluster::coordinator::new_test_running_cluster(
            crate::cluster::shards::NodeId(1),
            table,
            &[(
                crate::cluster::shards::NodeId(1),
                "127.0.0.1:4501".parse().unwrap(),
            )],
            &members,
            &[shard],
            &[],
            &[],
            1,
        );

        let started = std::time::Instant::now();
        let resp = h.request_with_cluster(
            OP_GET_BATCH,
            crate::protocol::codec::encode_get_batch(FieldMask::ALL_METADATA, &[txid]),
            &cluster,
        );
        let elapsed = started.elapsed();

        assert_eq!(resp.status, STATUS_OK);
        let results = crate::protocol::codec::decode_get_response(&resp.payload).unwrap();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].status, ERR_MIGRATION_IN_PROGRESS as u8);
        assert!(
            elapsed < std::time::Duration::from_millis(200),
            "pending inbound read should fail fast, took {:?}",
            elapsed
        );
    }

    /// R-043 (GH-04) regression: a malicious or buggy peer that sends
    /// an `OP_MIGRATION_COMPLETE` frame whose `entry_count` is so
    /// large that `entry_count * 36` overflows `usize` MUST be rejected
    /// with `ERR_MIGRATION_IN_PROGRESS` instead of allocating a
    /// `Vec::with_capacity(entry_count)` (which would OOM the process,
    /// and on 32-bit could even pass the size sanity check because
    /// `60 + entry_count * 36` would wrap to a small value).
    ///
    /// We exercise the overflow path by sending `entry_count =
    /// usize::MAX as u32` (which fits in the wire `u32` field) but a
    /// payload that is only the 60-byte header. The server must
    /// reject without panicking or allocating.
    #[test]
    fn migration_complete_unchecked_multiply_rejects_max_count() {
        let h = DispatchTestHarness::new();
        let shard = 17u16;

        let members = vec![crate::cluster::shards::NodeId(1)];
        let table = crate::cluster::shards::ShardTable::compute_with_epoch(&members, 1, 12, 1);
        let cluster = crate::cluster::coordinator::new_test_running_cluster(
            crate::cluster::shards::NodeId(1),
            table,
            &[(
                crate::cluster::shards::NodeId(1),
                "127.0.0.1:4717".parse().unwrap(),
            )],
            &members,
            &[shard],
            &[],
            &[],
            1,
        );

        // Build a 60-byte header: shard:u64 | utxo_records_received:u64 |
        // migration_epoch:u64 | source_manifest:32 | entry_count:u32 = u32::MAX.
        let mut payload = Vec::with_capacity(60);
        payload.extend_from_slice(&(shard as u64).to_le_bytes()); // shard:u64
        payload.extend_from_slice(&0u64.to_le_bytes()); // utxo_records_received
        payload.extend_from_slice(&0u64.to_le_bytes()); // migration_epoch
        payload.extend_from_slice(&[0u8; 32]); // source_manifest (all zeros)
        payload.extend_from_slice(&u32::MAX.to_le_bytes()); // entry_count = ATTACK
        assert_eq!(payload.len(), 60);

        let req = RequestFrame {
            request_id: shard as u64,
            op_code: OP_MIGRATION_COMPLETE,
            flags: 0,
            payload: payload.into(),
        };
        let mut conn_state = crate::server::ConnectionState::new();
        let resp = handle_request(
            &req,
            &h.engine,
            8192,
            Some(&cluster),
            None,
            &mut conn_state,
            None,
        );

        // Either the overflow check fires (preferred) or the size
        // mismatch fires (also acceptable — both end in a rejection
        // before any large allocation). Both surface as
        // `ERR_MIGRATION_IN_PROGRESS` per the existing rejection path.
        assert_ne!(
            resp.status, STATUS_OK,
            "u32::MAX entry_count must be rejected, not accepted",
        );
        assert!(
            !resp.payload.is_empty(),
            "rejection must include an error message in the payload",
        );
    }

